-- Poems batch 113
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('49a47eb4-2172-4893-96f3-af82a6e881c5','葉叔佐妻輓詩','姜特立','宋','宋诗','song-poetry','','[]','元是毗耶女，來嬪居士家。',48,'全唐诗/poet.song.126000.json','["元是毗耶女，來嬪居士家。", "一門函佛界，三子摘天葩。", "積累千金富，追迎百兩車。", "合書賢婦傳，遺像儼笄珈。"]'),
('6330ad7c-095f-48b6-9202-3338d48e3dc7','閒興','姜特立','宋','宋诗','song-poetry','','[]','天氣正清和，人情物意嘉。',48,'全唐诗/poet.song.126000.json','["天氣正清和，人情物意嘉。", "綠樹蔭屋角，微風起簷牙。", "挾書仲舒園，種菊淵明家。", "逍遥無一事，遠志凌青霞。"]'),
('afbfae82-5927-4e09-a554-2f0175a0348b','再贈湯仲輝','姜特立','宋','宋诗','song-poetry','','[]','肥遯元無悶，躬耕亦自娛。',24,'全唐诗/poet.song.126000.json','["肥遯元無悶，躬耕亦自娛。", "曲肱安陋巷，愛爾亦顔徒。"]'),
('3ae0f561-e4bf-4ce4-be12-066a1904573b','詠蠶','姜特立','宋','宋诗','song-poetry','','[]','㒩㒩屢神化，宛宛始成室。',132,'全唐诗/poet.song.126000.json','["㒩㒩屢神化，宛宛始成室。", "生從五泰初，事至三起畢。", "利物先遭烹，謀身自無術。", "衣被遍四方，丘山計端疋。", "豈知驕奢主，結綺縱游逸。", "剪綵滿園林，光輝豔風日。", "理宜得敗亡，此道天所疾。", "禮經重親蠶，一縷知自出。", "大禹惡衣服，仁儉由聖質。", "我本生田家，蠶織嘗究悉。", "初不恥縕袍，一煖志願訖。"]'),
('5ae26a03-2453-4272-892b-9953c92e393e','葺圃','姜特立','宋','宋诗','song-poetry','','[]','種樹書頻讀，齊民術屢窺。',48,'全唐诗/poet.song.127000.json','["種樹書頻讀，齊民術屢窺。", "曾求竹醉日，更問柳眠時。", "盧橘初非橘，蒲葵不是葵。", "因而辨名物，甘作老樊遲。"]'),
('4693e5b8-b83d-400e-82b7-bfdce9ec600b','韓子師朝路爲小人無禮去國再來婺女  其一','姜特立','宋','宋诗','song-poetry','','[]','推敲乍可恕詩客，攘臂豈容遭怒螗。',64,'全唐诗/poet.song.127000.json','["推敲乍可恕詩客，攘臂豈容遭怒螗。", "三尺何時尸鼠輩，九霄一日失鵷行。", "君王擬聽尚書履，使者行催相國裝。", "共喜日邊歸去近，雙溪椎皷下舟航。"]'),
('d062c061-802a-488c-bb32-a1b373d9988b','韓子師朝路爲小人無禮去國再來婺女  其二','姜特立','宋','宋诗','song-poetry','','[]','庭下棠陰七換秋，去思遺愛滿東州。',64,'全唐诗/poet.song.127000.json','["庭下棠陰七換秋，去思遺愛滿東州。", "當年父老留大尹，今日兒童迎細侯。", "久別雙溪勞夢想，重來八詠識風流。", "故人再此相逢地，曉出衡門失舊愁。"]'),
('f13fbd70-0cb7-43dd-a63f-a42a1cf96daf','翫月','姜特立','宋','宋诗','song-poetry','','[]','天風忽披拂，覺我襟袂清。',48,'全唐诗/poet.song.127000.json','["天風忽披拂，覺我襟袂清。", "雲片玉鱗薄，月華金暈生。", "曾於滄海看，浩蕩此時情。", "髣髴見三山，洶湧波浪驚。"]'),
('058b9a6f-e934-4432-b6ce-d672c176f1a5','晨起','姜特立','宋','宋诗','song-poetry','','[]','東旭曉曈矓，照我牆角紅。',48,'全唐诗/poet.song.127000.json','["東旭曉曈矓，照我牆角紅。", "衰意忽開豁，衰顔亦丰茸。", "便欲理晨策，去遶菊花叢。", "惜無會心友，一尊清興同。"]'),
('dc396dc2-5a7c-4ac0-90c6-2c02989804c6','古意','姜特立','宋','宋诗','song-poetry','','[]','共綰同心結，那知有別離。',24,'全唐诗/poet.song.127000.json','["共綰同心結，那知有別離。", "對人爭忍說，不敢畫蛾眉。"]'),
('e280ebf8-f3d6-4657-be1e-9a005dcdda2b','霜後菊','姜特立','宋','宋诗','song-poetry','','[]','嫩黄釅白媚秋暉，正坐清霜一夜飛。',32,'全唐诗/poet.song.127000.json','["嫩黄釅白媚秋暉，正坐清霜一夜飛。", "似怯曉來天氣冷，一時都換紫羅衣。"]'),
('0292fa04-dad4-4d20-8a79-46f1c0c3ec6a','送邦佐弟歸鄉','姜特立','宋','宋诗','song-poetry','','[]','昔時俱是一兒童，今日相看兩禿翁。',64,'全唐诗/poet.song.127000.json','["昔時俱是一兒童，今日相看兩禿翁。", "舊約對牀心自喜，新詩入夢句仍工。", "吾衰已覺身如幻，汝老猶疑氣吐虹。", "南北相望才數舍，何時更卜一尊同。"]'),
('9f97cf71-bf86-4d10-a49d-aca0cf4bfa5b','子陵','姜特立','宋','宋诗','song-poetry','','[]','足加帝腹狂奴態，自是君王禮數寬。',32,'全唐诗/poet.song.127000.json','["足加帝腹狂奴態，自是君王禮數寬。", "四海但知天子貴，先生只作故人看。"]'),
('179bc70e-1537-4652-8bb4-bef2035b6306','喜雪','姜特立','宋','宋诗','song-poetry','','[]','陰宰弄精神，空中舞玉塵。',48,'全唐诗/poet.song.127000.json','["陰宰弄精神，空中舞玉塵。", "入簷燈影亂，折竹曉聲頻。", "照幌光侵曙，欺梅氣壓春。", "老夫貪快賞，呵凍拂烏巾。"]'),
('4d97b084-ad2b-41f9-bd34-b2e1d3c9c68b','柳','姜特立','宋','宋诗','song-poetry','','[]','長條攀折歎離披，底事人間管別離。',32,'全唐诗/poet.song.127000.json','["長條攀折歎離披，底事人間管別離。", "何似龍津通御氣，建章宮裏鬭腰支。"]'),
('53ef6394-8a2d-431d-b908-a84127b4b776','懷方叔','姜特立','宋','宋诗','song-poetry','','[]','憶昔尊前共賦詩，如今仙去見無期。',32,'全唐诗/poet.song.127000.json','["憶昔尊前共賦詩，如今仙去見無期。", "吟魂想只空山裏，嘲弄風光人不知。"]'),
('8d201548-4db7-43f8-8a4b-fcbb997e746f','有感','姜特立','宋','宋诗','song-poetry','','[]','滴水添壺箭，跳丸疊崦嵫。',24,'全唐诗/poet.song.127000.json','["滴水添壺箭，跳丸疊崦嵫。", "只誇顔似玉，不覺鬢成絲。"]'),
('469686c6-f8d7-4721-a8a1-393595cd31b6','初夏','姜特立','宋','宋诗','song-poetry','','[]','時節催農圃，園林花事空。',24,'全唐诗/poet.song.127000.json','["時節催農圃，園林花事空。", "柳蒼無故態，苗長有新功。"]'),
('212a1576-7e6c-4134-a2e3-d984a82c9a27','因觀贊皇平泉草木記有感','姜特立','宋','宋诗','song-poetry','','[]','平泉草木頻移主，西雒園池幾換人。',32,'全唐诗/poet.song.127000.json','["平泉草木頻移主，西雒園池幾換人。", "但把風花觀世界，莫將金石認吾身。"]'),
('af03083e-3caf-457e-a6c3-56b37d6c06b4','悼邦節弟','姜特立','宋','宋诗','song-poetry','','[]','皇考憐同出，青山憶並廬。',48,'全唐诗/poet.song.127000.json','["皇考憐同出，青山憶並廬。", "前春曾訪我，無月不來書。", "易感中年後，難忘少長初。", "倏然成夢幻，歲晚重欷歔。"]'),
('7c435618-7021-4fb2-b4e5-3156529f5c13','張致政輓章','姜特立','宋','宋诗','song-poetry','','[]','上壽身仍健，榮封歲屢終。',48,'全唐诗/poet.song.127000.json','["上壽身仍健，榮封歲屢終。", "無因拜龐德，空幸識王戎。", "含玉亡遺恨，懸車近古風。", "燎黄應不遠，光寵賁幽宮。"]'),
('4d1fbb7b-29b2-45a7-8233-c23db387be8a','次韻黄司理','姜特立','宋','宋诗','song-poetry','','[]','龍墀射策筆如神，馬首哦詩句益新。',64,'全唐诗/poet.song.127000.json','["龍墀射策筆如神，馬首哦詩句益新。", "忽捧名篇端有意，欲求强對恐無人。", "浸淫漢魏知追古，摸索曹劉已識真。", "荀氏八龍誰最著，慈明頭角在雲津。"]'),
('e9734894-2ff8-4620-a56a-d5139ca5b162','悼何求卿內子王氏川人王丞相夫人母之妯娌','姜特立','宋','宋诗','song-poetry','','[]','名父飛鳬席慶長，良人傅粉舊傳芳。',64,'全唐诗/poet.song.127000.json','["名父飛鳬席慶長，良人傅粉舊傳芳。", "籃輿曾带陽臺雨，花院俄沉婺宿光。", "表表門眉看列倩，詵詵蘭玉有諸郎。", "不唯綵誥生前寵，更有豐碑自玉堂。"]'),
('8f21ea35-2735-4b34-9d43-5c26c0c2bc50','漁舍感秋','姜特立','宋','宋诗','song-poetry','','[]','小築瞰清流，人閒境更幽。',24,'全唐诗/poet.song.127000.json','["小築瞰清流，人閒境更幽。", "蒹葭寒带水，蟋蟀靜吟秋。"]'),
('da01010b-3fcc-40d7-9752-083fc9fcbb2f','繭菴回','姜特立','宋','宋诗','song-poetry','','[]','歸路俯清川，呼奴自刺船。',24,'全唐诗/poet.song.127000.json','["歸路俯清川，呼奴自刺船。", "戲魚翻晚照，宿鳥入寒煙。"]'),
('6ca8e478-175d-45a9-8431-248d0352c3fc','暑退秋夜賞月','姜特立','宋','宋诗','song-poetry','','[]','冠巾暑退纔如律，詩酒交情不作踈。',32,'全唐诗/poet.song.127000.json','["冠巾暑退纔如律，詩酒交情不作踈。", "今夕孤光清到骨，鏤冰裁玉滿林廬。"]'),
('ccaeb312-a82d-4dc2-8d9e-918df3f489cd','拒霜','姜特立','宋','宋诗','song-poetry','','[]','楚天寂歷暮雲平，何處江村落鴈聲。',32,'全唐诗/poet.song.127000.json','["楚天寂歷暮雲平，何處江村落鴈聲。", "正是西風掃黄葉，不知春色在朱榮。"]'),
('3d30246c-0fa7-43fb-a9cd-76b41f8d7081','罷劉巖酒庫','姜特立','宋','宋诗','song-poetry','','[]','世事升沈侔蝶化，吾生來往更蠅營。',64,'全唐诗/poet.song.127000.json','["世事升沈侔蝶化，吾生來往更蠅營。", "歸心有愧陶元亮，家事當如尚子平。", "豈是木雞猶有變，故令鷗鳥尚相驚。", "老夫本自無城府，抱甕何妨過此生。"]'),
('bc5539cd-6042-4c92-a209-ffc6fdb46197','閩中得家書','姜特立','宋','宋诗','song-poetry','','[]','家書隔歲至，生死半一新。',72,'全唐诗/poet.song.127000.json','["家書隔歲至，生死半一新。", "新故無已時，悲喜俱傷神。", "人生茲世間，誰是出世者。", "有如獨繭蠶，終日自纏裹。", "迢迢碧海路，青鳥長來去。", "安得挾雙成，吹笙入煙霧。"]'),
('3de18249-ac7a-405b-8263-d0ef6f461144','海上獲捷禱於廟神王公方交鬬間賊桅忽倒赴水死者太半後請于朝賜額靈惠','姜特立','宋','宋诗','song-poetry','','[]','直駕樓船擣賊桅，金槃一擲萬人開。',32,'全唐诗/poet.song.127000.json','["直駕樓船擣賊桅，金槃一擲萬人開。", "何當爲奏褒封典，釃酒刲羊亦快哉。"]'),
('1c531597-22e0-47aa-bd25-63ad18ac5f11','出閩中四首  其一','姜特立','宋','宋诗','song-poetry','','[]','山行十日到吾家，臘盡歸人惜歲華。',32,'全唐诗/poet.song.127000.json','["山行十日到吾家，臘盡歸人惜歲華。", "斗酒隻雞誰勞我，更須踏雪看梅花。"]'),
('5b35a7ed-161b-45d1-be7b-b8326024d381','出閩中四首  其二','姜特立','宋','宋诗','song-poetry','','[]','千里携家一禿翁，一尊倒盡百愁空。',32,'全唐诗/poet.song.127000.json','["千里携家一禿翁，一尊倒盡百愁空。", "野梅可是工迎客，排日開花到浙中。"]'),
('b88b9694-e2b8-4d1f-a2c0-feda531f4efb','出閩中四首  其三','姜特立','宋','宋诗','song-poetry','','[]','飄蓬不歸根，而我還故里。',84,'全唐诗/poet.song.127000.json','["飄蓬不歸根，而我還故里。", "有食即可安，何必土風美。", "豈非俗緣故，墮此膠漆底。", "艱關一月程，况復携老稚。", "囊空畏途遠，蓐食常夜起。", "人生貴適意，奔走殊未已。", "俟有三逕資，吾生恐無幾。"]'),
('17a46577-7d15-41b0-b20b-aa1e22a672c0','出閩中四首  其四','姜特立','宋','宋诗','song-poetry','','[]','晚出仙霞嶺，平原豁故關。',48,'全唐诗/poet.song.127000.json','["晚出仙霞嶺，平原豁故關。", "石窮千里逕，雲失萬重山。", "漸喜鄉音似，遥知兒輩歡。", "不緣懷里社，倦翼未須還。"]'),
('24a9ec4c-2c7f-441b-a574-38bfae60ff46','湖光爲劉慶遠作也','姜特立','宋','宋诗','song-poetry','','[]','湖水浸坤軸，湖光混太清。',144,'全唐诗/poet.song.127000.json','["湖水浸坤軸，湖光混太清。", "風來縠紋起，夜靜鏡奩平。", "初訝琉璃軟，還疑組練橫。", "微茫連澤國，瀲灩蹙寒汀。", "破碎翻千月，泓澄印萬星。", "雨來添點綴，日射鬭晶熒。", "橋影虹垂澗，杉陰幕覆亭。", "魚跳全薦玉，山卧半沈青。", "小泛依吳榜，長謠任楚萍。", "擠排李白醉，勾引屈原醒。", "暇日宜呼客，平時好濯纓。", "吟哦萬景集，未足稱詩情。"]'),
('7a140221-e2ba-4805-ba97-d392903d63bf','編猥作','姜特立','宋','宋诗','song-poetry','','[]','老來事業無多子，收拾新詩又滿編。',32,'全唐诗/poet.song.127000.json','["老來事業無多子，收拾新詩又滿編。", "金玉那能潤身後，等閒猶作百年傳。"]'),
('20beaf73-45e6-43fe-a9dd-b5045439516c','秋園','姜特立','宋','宋诗','song-poetry','','[]','商氣入山園，園花取次妍。',24,'全唐诗/poet.song.127000.json','["商氣入山園，園花取次妍。", "蓼叢迎露重，菊本望秋圓。"]'),
('9fc95ac9-df00-42a0-9496-0b7b80cf2dfa','再悼邦節弟','姜特立','宋','宋诗','song-poetry','','[]','滿腹書何用，謀身事竟非。',48,'全唐诗/poet.song.127000.json','["滿腹書何用，謀身事竟非。", "中堂親尚在，私室子疇依。", "人去驚漚沒，秋來愁鴈飛。", "它時風雨夕，相憶淚霑衣。"]'),
('dcff4c77-bc0f-4600-9c7c-9362cacd470e','月下','姜特立','宋','宋诗','song-poetry','','[]','晚來暑退坐前墀，嫋嫋南薰動翠微。',32,'全唐诗/poet.song.127000.json','["晚來暑退坐前墀，嫋嫋南薰動翠微。", "便欲乘風遊汗漫，白雲頂上翫清輝。"]'),
('25d058de-5e7c-484b-99c6-57c8d3d7a2cc','送謝叔光','姜特立','宋','宋诗','song-poetry','','[]','青陽迫殘臘，寒色滿江干。',48,'全唐诗/poet.song.127000.json','["青陽迫殘臘，寒色滿江干。", "我有採薪疾，君方行路難。", "來無十日款，去作一程寬。", "翌晚解鞍罷，親庭足笑歡。"]'),
('4cd1ca08-a508-440e-9d8d-9ba8338425e0','歸括蒼和楊嗣之吏部煙雨樓韻四首  其一','姜特立','宋','宋诗','song-poetry','','[]','誰發天慳得勝遊，佳名收拾更無留。',32,'全唐诗/poet.song.127000.json','["誰發天慳得勝遊，佳名收拾更無留。", "鄭虔祁岳今誰是，爲掃陰沈萬壑秋。"]'),
('a686466e-75b9-41e9-90f7-b2fdf7983198','歸括蒼和楊嗣之吏部煙雨樓韻四首  其二','姜特立','宋','宋诗','song-poetry','','[]','幾重綠樹暗羅紈，多少空濛遠近山。',32,'全唐诗/poet.song.127000.json','["幾重綠樹暗羅紈，多少空濛遠近山。", "物色聯翩吟不斷，使君佳句玉連環。"]'),
('81baef65-4f71-4ea3-acde-fca319785286','歸括蒼和楊嗣之吏部煙雨樓韻四首  其三','姜特立','宋','宋诗','song-poetry','','[]','絕唱從前恨未多，騷人墨客浪經過。',32,'全唐诗/poet.song.127000.json','["絕唱從前恨未多，騷人墨客浪經過。", "直須吏部楊夫子，始奈樓中煙雨何。"]'),
('979bc3b0-95de-47a7-910a-c79e56984167','歸括蒼和楊嗣之吏部煙雨樓韻四首  其四','姜特立','宋','宋诗','song-poetry','','[]','宴坐簾旌捲翠微，朝昏萬變發新姿。',32,'全唐诗/poet.song.127000.json','["宴坐簾旌捲翠微，朝昏萬變發新姿。", "錦囊莫怕嵐霏濕，带取風光入鳳池。"]'),
('2ed003e3-c1cb-4a4b-8f19-716d0f3127c8','噉筍','姜特立','宋','宋诗','song-poetry','','[]','自從孤竹夷齊死，清節何人萃一門。',32,'全唐诗/poet.song.127000.json','["自從孤竹夷齊死，清節何人萃一門。", "惟有此君無俗韵，至今風味屬諸孫。"]'),
('4e4aaab4-c6d5-49d3-bfdf-ddd0b8f73b61','赴飲席家人供新衣','姜特立','宋','宋诗','song-poetry','','[]','勸我著新衣，深辭老不宜。',24,'全唐诗/poet.song.127000.json','["勸我著新衣，深辭老不宜。", "如今百事懶，不比舞雩時。"]'),
('9c1635a4-6b0f-4e85-8c64-1e6e3502777e','柳','姜特立','宋','宋诗','song-poetry','','[]','森森萬木勢崢嶸，千尺孤標更上征。',32,'全唐诗/poet.song.127000.json','["森森萬木勢崢嶸，千尺孤標更上征。", "惟有柳絲低拂路，腰支憔悴爲多情。"]'),
('9fc4e396-bebf-4dfb-8418-d6fec188dd8f','曩備員宮屬令旨畫箑覓詩字以金書','姜特立','宋','宋诗','song-poetry','','[]','時頒便面覓新詩，巧畫花枝作好題。',32,'全唐诗/poet.song.127000.json','["時頒便面覓新詩，巧畫花枝作好題。", "多謝東皇不嫌棄，親將仙手寫金泥。"]'),
('edf1097a-7c2f-478a-b2b5-1be4bc490708','林欽之主簿輓章','姜特立','宋','宋诗','song-poetry','','[]','敬讀銘鎸語，遥知磊落胸。',48,'全唐诗/poet.song.127000.json','["敬讀銘鎸語，遥知磊落胸。", "義襟如郭震，豪氣似元龍。", "萬里摧車軸，三春折澗松。", "天雖不可問，餘慶後人鍾。"]'),
('255ddfac-e6ad-45eb-a99a-64daa90261ba','寄韓判院南澗常伯之子','姜特立','宋','宋诗','song-poetry','','[]','每思南澗一凄然，不見風騷二十年。',64,'全唐诗/poet.song.127000.json','["每思南澗一凄然，不見風騷二十年。", "子厚猶能記先友，審言且喜有家傳。", "蜩螗聲亂無遺響，山水人亡有絕絃。", "海內可能無法眼，直須參取祖師禪。"]'),
('90ab7c63-f87f-4bfd-adf6-3eee3d1b7c58','庚申度夏自適','姜特立','宋','宋诗','song-poetry','','[]','透脫逍遥遊外，遠離煩惱濁中。',28,'全唐诗/poet.song.127000.json','["透脫逍遥遊外，遠離煩惱濁中。", "夜夜滿懷明月，時時入夢清風。"]'),
('49b34e83-618b-4b54-b7e0-e25fa1ac5180','戲題','姜特立','宋','宋诗','song-poetry','','[]','樂天妙語過雞林，平處猶爲治世音。',32,'全唐诗/poet.song.127000.json','["樂天妙語過雞林，平處猶爲治世音。", "豁達如今唯李老，不妨風月自閒吟。"]'),
('83a54aa5-8247-49ab-ace4-0a47d8054a89','閨怨','姜特立','宋','宋诗','song-poetry','','[]','別恨迢迢千里餘，天涯何處覓音書。',32,'全唐诗/poet.song.127000.json','["別恨迢迢千里餘，天涯何處覓音書。", "花間羞見雙雙蝶，水上愁尋六六魚。"]'),
('a7298c47-ec5b-4f36-b6a8-7366084eb1c4','暑退喜秋','姜特立','宋','宋诗','song-poetry','','[]','頹齡厭濁暑，瘦骨便清秋。',72,'全唐诗/poet.song.127000.json','["頹齡厭濁暑，瘦骨便清秋。", "蓐收方回鑣，灝氣橫九州。", "老鶴生精神，孤松鬰颼飀。", "如飲寒露漿，貯以青瑶甌。", "既蠲膏肓疾，復洗熱惱憂。", "斟酌楚人賦，併作商聲謳。"]'),
('fc37febd-53bb-4da1-a243-d0de416f079a','暑退','姜特立','宋','宋诗','song-poetry','','[]','歸卧林間十二春，心安日日是良辰。',64,'全唐诗/poet.song.127000.json','["歸卧林間十二春，心安日日是良辰。", "家居佛界清凉國，人住仙宮自在身。", "無事入山尋阮客，有時擊壤助堯民。", "雖無高行追先隠，畢究田園樂亦真。"]'),
('0f071564-d42a-4413-9eb3-e3feae67d1de','歌豐年','姜特立','宋','宋诗','song-poetry','','[]','稔歲非常歲，時時霧雨并。',120,'全唐诗/poet.song.127000.json','["稔歲非常歲，時時霧雨并。", "陂塘留夜月，澗谷瀉秋聲。", "卧裌驚宵冷，披紗怯曉清。", "水泉俱自足，阡陌更無爭。", "荷鍤疏餘浸，腰鐮候小晴。", "秫材寒眼富，酒興老涎生。", "便覺糟床注，還欣庾粟盈。", "新君鍾瑞慶，舊俗迓昇平。", "賽社雞豚具，迎神笳皷鳴。", "支離徒受粟，一飽愧斯氓。"]'),
('00eaaeea-a4da-4057-9dac-2f5bf76cc9d5','人送巖桂二首  其一','姜特立','宋','宋诗','song-poetry','','[]','七月濁暑氣氤氳，天香忽墮明月輪。',32,'全唐诗/poet.song.127000.json','["七月濁暑氣氤氳，天香忽墮明月輪。", "一枝先入西風手，洗我三伏胸中塵。"]'),
('f718ac48-f43d-4339-ba5e-9b794586517a','人送巖桂二首  其二','姜特立','宋','宋诗','song-poetry','','[]','香馥清晨可療饑，飽人勝食齋房芝。',32,'全唐诗/poet.song.127000.json','["香馥清晨可療饑，飽人勝食齋房芝。", "便好架巢枝上宿，不愁無酒只愁詩。"]'),
('a16f8d13-8517-4ee5-9b87-dc7cdc0c14c0','漁舍','姜特立','宋','宋诗','song-poetry','','[]','漁舍時時須一到，水光山色浄相親。',32,'全唐诗/poet.song.127000.json','["漁舍時時須一到，水光山色浄相親。", "玉肌花貌不須替，自有陽臺行雨人。"]'),
('991be03f-821f-488b-b54d-a9791e598484','詠菊','姜特立','宋','宋诗','song-poetry','','[]','菊稟金天精，勁氣凌風霜。',48,'全唐诗/poet.song.127000.json','["菊稟金天精，勁氣凌風霜。", "水流山下潭，飲者壽命長。", "泛我盃中物，染我詩句香。", "所以陶徵君，愛之不忍忘。"]'),
('7fe54d18-6051-4c97-82ca-c294a59106d1','秋來得雨','姜特立','宋','宋诗','song-poetry','','[]','夜來一番雨，青我一席蔬。',48,'全唐诗/poet.song.127000.json','["夜來一番雨，青我一席蔬。", "洗甑炊香秔，何必食有魚。", "便可釀新秫，唧唧鳴齋厨。", "且以樂殘年，此外不願餘。"]'),
('4ac7ce34-40b1-4253-8260-98853c969df3','憶仲子','姜特立','宋','宋诗','song-poetry','','[]','吟哦五字有規模，妙處時時亦起予。',32,'全唐诗/poet.song.127000.json','["吟哦五字有規模，妙處時時亦起予。", "送老百年將付汝，豈知顔路請吾車。"]'),
('e3c892f0-248d-4ee0-8061-5bfa989c05f1','報國如乖願歸耕寧買田此歐陽公酬杜正獻告老後詩也前輩名公亦有買田詩句蓋寓歸耕意爾豈真若今士夫爲多田翁耶','姜特立','宋','宋诗','song-poetry','','[]','出仕雖無補，歸耕寧買田。',24,'全唐诗/poet.song.127000.json','["出仕雖無補，歸耕寧買田。", "聊將報明主，庶不媿前賢。"]'),
('b4933901-7c22-4611-8b54-38a4b4363a40','哭仲子','姜特立','宋','宋诗','song-poetry','','[]','一日死生隔，平生父子休。',72,'全唐诗/poet.song.127000.json','["一日死生隔，平生父子休。", "暮齡逢逆境，老淚濕清秋。", "浪急珠沉海，天昏壑失舟。", "煙霄落鵰鶚，天廐喪驊騮。", "萬里車軸折，百年江漢流。", "吾生今已矣，世事付悠悠。"]'),
('cbeb9ffa-3868-40c7-bb9d-6f79cc1fea0f','邸報京丞相薨背','姜特立','宋','宋诗','song-poetry','','[]','丞相今朝薨相位，衣冠贈典一番新。',32,'全唐诗/poet.song.127000.json','["丞相今朝薨相位，衣冠贈典一番新。", "作場好夢歸鄉去，仰羨無非夢裏人。"]'),
('cd70fc9f-2863-4d4c-a058-df9b7e9b9b50','暇日歎日月之逾邁念吾生之幾何感而成章','姜特立','宋','宋诗','song-poetry','','[]','密移不自覺，猛省却堪驚。',48,'全唐诗/poet.song.127000.json','["密移不自覺，猛省却堪驚。", "紅顔去不返，白髮來無情。", "劫秦氣何用，袒漢力莫爭。", "求勝竟無術，陶然任此生。"]'),
('75d29d83-6ce5-476d-8e37-a8438ae980da','致政張教授晚而買妾有女戲贈','姜特立','宋','宋诗','song-poetry','','[]','隠君無婦幾經時，暮景鰥居却未宜。',64,'全唐诗/poet.song.127000.json','["隠君無婦幾經時，暮景鰥居却未宜。", "且喜中郎新有女，豈容白傅老無兒。", "閨中不著玉川婢，天下應傳京兆眉。", "無計去陪湯餠客，花卿有子待歌詩。"]'),
('11eccdcc-1bec-4fb2-a1e9-d89894aa18d6','賞海棠','姜特立','宋','宋诗','song-poetry','','[]','海棠初破萼，紅豔欲無春。',24,'全唐诗/poet.song.127000.json','["海棠初破萼，紅豔欲無春。", "小插依霜鬢，花應恕老人。"]'),
('1330012f-2e98-4157-9e53-9bb47debe884','諭亡子','姜特立','宋','宋诗','song-poetry','','[]','死固汝可憐，生亦我所愛。',24,'全唐诗/poet.song.127000.json','["死固汝可憐，生亦我所愛。", "生死兩相繆，吾將解其會。"]'),
('cdd0c32c-82ac-4747-9a69-90b0ea45a7ce','余有仲子之戚九日親故携酒訪我於梅山之上因詠昔人詩人情皆向菊天意欲摧蘭之句不覺凄然有感遂易一字足成篇','姜特立','宋','宋诗','song-poetry','','[]','九日上梅山，愁心卒未安。',48,'全唐诗/poet.song.127000.json','["九日上梅山，愁心卒未安。", "人情皆向菊，天意獨摧蘭。", "管女不及嫁，萊衣空自寒。", "牛山多感慨，把酒淚闌干。"]'),
('97a90991-c7f1-4af5-94c0-d1fa31c27a16','野意','姜特立','宋','宋诗','song-poetry','','[]','謝安高卧向東山，白傅分司雒水灣。',32,'全唐诗/poet.song.127000.json','["謝安高卧向東山，白傅分司雒水灣。", "賓朋歌舞歡娛處，只在山光水色間。"]'),
('1ee46aa0-a42c-42b1-aaad-d4b47da4d61a','陳右司輓詩','姜特立','宋','宋诗','song-poetry','','[]','麟經絕學冠名儒，科甲巍峩壓雋途。',64,'全唐诗/poet.song.127000.json','["麟經絕學冠名儒，科甲巍峩壓雋途。", "兩作星郎歸省戶，五持玉節佩州符。", "義倉睦族前賢少，猶子推恩舉世無。", "忝竊親鄰違一奠，不堪老涕落寒鬚。"]'),
('6a22e7d6-d116-494e-811d-5165728aeec2','書壽穴中石壽星背四言','姜特立','宋','宋诗','song-poetry','','[]','彼石何人，云是壽者。',40,'全唐诗/poet.song.127000.json','["彼石何人，云是壽者。", "作鎮斯宮，孰分真假。", "以幻對幻，有同兒嬉。", "他日啟扃，問爾是誰。"]'),
('e4b506b4-8694-4bfc-b978-807fb14e4f61','老饞','姜特立','宋','宋诗','song-poetry','','[]','八十血氣衰，交累身口故。',96,'全唐诗/poet.song.127000.json','["八十血氣衰，交累身口故。", "喜讀奉親書，竊誦老饕賦。", "烹飪付家人，甘旨輒復具。", "爛軟既適宜，調芼亦合度。", "兒女各貢勤，桮羹走童孺。", "鄰里重交情，時時分果茹。", "興來一舉觴，直到醉鄉路。", "此樂冀百年，此腹恐相負。"]'),
('c4abfec2-32b2-4cfb-8fd7-fb9fe87c6284','晚起喜晴','姜特立','宋','宋诗','song-poetry','','[]','老翁喜晴色，屋角候晨曦。',48,'全唐诗/poet.song.127000.json','["老翁喜晴色，屋角候晨曦。", "圓影纔明隙，方暉已鑒帷。", "呼童聊擁褐，得火即舒眉。", "盥櫛渾無事，看山就小詩。"]'),
('d18a60f1-7cb5-4155-8d1a-3b9e08d8b66e','感物','姜特立','宋','宋诗','song-poetry','','[]','今年葉底已藏花，來歲還抽後歲芽。',32,'全唐诗/poet.song.127000.json','["今年葉底已藏花，來歲還抽後歲芽。", "代謝乘除無了日，須將定力看浮華。"]'),
('f8b2faa9-37ce-41dd-91e5-b9330613165c','甲辰歲進詩一編孝宗許其清新翌旦宣諭宰執召試再賦一首','姜特立','宋','宋诗','song-poetry','','[]','午漏奏新詩，昕朝召節飛。',24,'全唐诗/poet.song.127000.json','["午漏奏新詩，昕朝召節飛。", "若非梁武帝，誰識謝玄暉。"]'),
('537908fa-7b38-4b84-bac0-6caa9d929ecf','罨菜','姜特立','宋','宋诗','song-poetry','','[]','梅山罨菜勝羹藜，怪見賓筵玉筯齊。',32,'全唐诗/poet.song.127000.json','["梅山罨菜勝羹藜，怪見賓筵玉筯齊。", "大似雪堂真一酒，絕勝金谷韭蓱齏。"]'),
('7e8abaa3-9090-4afd-9e38-372e0172e9e1','憂患中作','姜特立','宋','宋诗','song-poetry','','[]','吉凶既同域，憂喜亦同途。',84,'全唐诗/poet.song.127000.json','["吉凶既同域，憂喜亦同途。", "萬緣互起滅，誰能久歡娛。", "歡娛既不久，悲恨常與俱。", "唯有嵇阮輩，乃能脫囚拘。", "一醉了生死，豈復念區區。", "小兒玩造物，造物亦戲渠。", "舉世憂其憂，放浪樂有餘。"]'),
('a056c2f6-61b7-4dc0-b925-df7b79362afc','虞察院生日  其一','姜特立','宋','宋诗','song-poetry','','[]','新開絃管召天和，喜氣悠揚際海涯。',32,'全唐诗/poet.song.127000.json','["新開絃管召天和，喜氣悠揚際海涯。", "向曉金焦稱壽處，歡聲更滿使君家。"]'),
('7017819d-215d-4283-90b1-198721512600','虞察院生日  其二','姜特立','宋','宋诗','song-poetry','','[]','自輟清班素望崇，凜然爭仰柏臺風。',32,'全唐诗/poet.song.127000.json','["自輟清班素望崇，凜然爭仰柏臺風。", "大姦鉅猾宜深屏，且避當年御史騘。"]'),
('7658ff4e-112b-40b5-89b8-d5ab050f4f70','虞察院生日  其三','姜特立','宋','宋诗','song-poetry','','[]','向來施設跼苕川，荒政方勞問計然。',32,'全唐诗/poet.song.127000.json','["向來施設跼苕川，荒政方勞問計然。", "今日雄藩得長袖，請君著眼看回旋。"]'),
('2477b442-877f-432a-ae11-73a101fdaf96','虞察院生日  其四','姜特立','宋','宋诗','song-poetry','','[]','雨暘時若頼君侯，萬室歡呼慶有秋。',32,'全唐诗/poet.song.127000.json','["雨暘時若頼君侯，萬室歡呼慶有秋。", "不論高原并下隰，民間稌黍一時收。"]'),
('d4d08103-2c40-44da-94f8-8bf4a7f808fa','虞察院生日  其五','姜特立','宋','宋诗','song-poetry','','[]','今年旱火欲燒空，盡是忱誠默禱功。',32,'全唐诗/poet.song.127000.json','["今年旱火欲燒空，盡是忱誠默禱功。", "尊酒豚蹄亦何用，使君心自與天通。"]'),
('8a9b3fe7-8deb-4301-a51d-e8abd7c6775e','虞察院生日  其六','姜特立','宋','宋诗','song-poetry','','[]','使君决遣烈秋霜，不許烏衣立坐傍。',32,'全唐诗/poet.song.127000.json','["使君决遣烈秋霜，不許烏衣立坐傍。", "一吏持毫供點染，向來鴈鶩不成行。"]'),
('83db52fa-9b58-427d-a4fe-0ed22d32f713','虞察院生日  其七','姜特立','宋','宋诗','song-poetry','','[]','鉏纇除荒政若神，俗安民靖絕紛紜。',32,'全唐诗/poet.song.127000.json','["鉏纇除荒政若神，俗安民靖絕紛紜。", "清宵不見犬吠盜，綠野更無羊敗羣。"]'),
('401d00bf-9ce8-4b28-bb2f-b04575c3a0c9','虞察院生日  其八','姜特立','宋','宋诗','song-poetry','','[]','下車好語敬書紳，誠意區區只爲民。',32,'全唐诗/poet.song.127000.json','["下車好語敬書紳，誠意區區只爲民。", "今歲年豐米狼戾，更須通變惠斯人。"]'),
('3f6f7ca6-3855-4105-b26e-8380edefeb40','虞察院生日  其九','姜特立','宋','宋诗','song-poetry','','["\u897f\u6e56"]','天詔飛傳速置郵，雙溪門外促行舟。',32,'全唐诗/poet.song.127000.json','["天詔飛傳速置郵，雙溪門外促行舟。", "橙黄橘綠風光好，併看西湖十里秋。"]'),
('6bf5075e-38f3-4b46-84da-e6833f8be3ae','虞察院生日  其一○','姜特立','宋','宋诗','song-poetry','','[]','文章近古追前輩，政事方今絕後塵。',32,'全唐诗/poet.song.127000.json','["文章近古追前輩，政事方今絕後塵。", "聊佩左符猶未稱，好歸黄閣試經綸。"]'),
('e3488b4e-f4ef-4afa-9134-86b3fdadb5cd','傷老','姜特立','宋','宋诗','song-poetry','','[]','老翁足力弱，踉蹡如小兒。',96,'全唐诗/poet.song.127000.json','["老翁足力弱，踉蹡如小兒。", "須杖乃能行，動步憂欹危。", "髮禿生細毛，正似出胎時。", "忽復長兒齒，輔車兩相依。", "還童既無術，衰謝乃其宜。", "載念天地間，八十者幾希。", "如我真幸民，何必暗傷悲。", "且飲北海酒，自吟東老詩。"]'),
('0b720742-280d-493b-ac67-a910c642cffd','喜敗篋中得舊詩','姜特立','宋','宋诗','song-poetry','','[]','十首詩篇久棄遺，偶翻故篋有光輝。',32,'全唐诗/poet.song.127000.json','["十首詩篇久棄遺，偶翻故篋有光輝。", "恰如建鼓求亡子，一日門前忽自歸。"]'),
('4cbf2b45-5011-4c1c-8b2b-204403705758','風色','姜特立','宋','宋诗','song-poetry','','[]','風色作吳霜，山中草木黄。',24,'全唐诗/poet.song.127000.json','["風色作吳霜，山中草木黄。", "冷烟籠碧瓦，露葉徧寒塘。"]'),
('faa33aea-af8a-4cec-a5a8-3f93d035117c','對花戲作','姜特立','宋','宋诗','song-poetry','','[]','八十衰翁歲月高，可憐老氣尚粗豪。',32,'全唐诗/poet.song.127000.json','["八十衰翁歲月高，可憐老氣尚粗豪。", "春來縱被花相惱，半是無心半搭猱。"]'),
('bade361a-a958-4e37-a64e-cbbd9d7040bb','追感三朝遭遇今如一夢','姜特立','宋','宋诗','song-poetry','','[]','本是蓬篳姿，偶作帝王客。',48,'全唐诗/poet.song.127000.json','["本是蓬篳姿，偶作帝王客。", "日日上金門，時時分玉食。", "自忘身世賤，不覺仙凡隔。", "幾多賢達人，饑寒卧空澤。"]'),
('26d1e02e-c876-4be2-bd92-5c9daa243b23','余垂老於居之西偏營小堂面對南山一峰卓然榜曰如山蓋取詩人意也','姜特立','宋','宋诗','song-poetry','','[]','一峯高插丙丁間，南極星光伴我閒。',32,'全唐诗/poet.song.127000.json','["一峯高插丙丁間，南極星光伴我閒。", "不向仙君乞如願，只從造物覓如山。"]'),
('71c11352-1d90-435d-897b-af774210db9a','菘苣初冬稍茂喜而有作','姜特立','宋','宋诗','song-poetry','','[]','紫苣生春荑，助我作湯餠。',48,'全唐诗/poet.song.127000.json','["紫苣生春荑，助我作湯餠。", "黄菘養土膏，冰壺添雋永。", "凡物貴適口，何必須九鼎。", "况我藜藿腸，萬錢慚食頃。"]'),
('acc3fd96-d265-46d6-bf89-6ae6189a2651','再賦如山','姜特立','宋','宋诗','song-poetry','','[]','小堂草草屋三間，暇日徜徉養壽閒。',32,'全唐诗/poet.song.127000.json','["小堂草草屋三間，暇日徜徉養壽閒。", "揭榜如山還自笑，何人不老似青山。"]'),
('49b13aed-ac6e-4248-bb16-ab5a4ade63bd','肉𩟎萊菔','姜特立','宋','宋诗','song-poetry','','[]','玉食舊游寧作我，藜羹故態未忘吾。',32,'全唐诗/poet.song.127000.json','["玉食舊游寧作我，藜羹故態未忘吾。", "爛爊萊菔甜如蜜，細點豬臕滑似酥。"]'),
('1033998a-26df-4bc3-9a1d-4a18a6c0889b','又賦如山','姜特立','宋','宋诗','song-poetry','','[]','如山堂上好登臨，羅列堂前紫翠岑。',64,'全唐诗/poet.song.127000.json','["如山堂上好登臨，羅列堂前紫翠岑。", "萬古烟霞供坐嘯，四時風月伴閒吟。", "海鷗心性滄洲遠，野鹿精神草樹深。", "却笑井蛙并轍鮒，只知缺甃與蹄涔。"]'),
('f939ed63-7bca-43ce-ada1-c742728177da','懷古','姜特立','宋','宋诗','song-poetry','','[]','古來一代文章事，自有風騷翰墨臣。',32,'全唐诗/poet.song.127000.json','["古來一代文章事，自有風騷翰墨臣。", "今日蘇門四君子，異時鄴下七詩人。"]'),
('b93f44c3-496f-429c-a2be-bf2304261a02','月','姜特立','宋','宋诗','song-poetry','','[]','萬古長空月，虧盈不計年。',24,'全唐诗/poet.song.127000.json','["萬古長空月，虧盈不計年。", "魄生蟾共沒，光滿蛤同圓。"]'),
('063150fe-7ec3-405d-899a-b3c14da9f8a8','春物','姜特立','宋','宋诗','song-poetry','','["\u897f\u6e56"]','一春天富貴，萬象物光華。',24,'全唐诗/poet.song.127000.json','["一春天富貴，萬象物光華。", "遥想西湖上，風流賣酒家。"]'),
('8b25ebba-a610-431c-8223-b889f046e726','和王粹中','姜特立','宋','宋诗','song-poetry','','[]','非農非吏本同塵，胸次何時不是春。',64,'全唐诗/poet.song.127000.json','["非農非吏本同塵，胸次何時不是春。", "戶外松筠隨意好，山中風景逐時新。", "擇鄉幸喜仁爲里，省己深慚德有鄰。", "事契姻聯非一日，嚮來俱是異邦人。"]'),
('fbd35be3-fc96-4e63-a5c9-86ab36e78206','長至後','姜特立','宋','宋诗','song-poetry','','[]','遲遲晝景轉庭除，似覺今朝化日舒。',32,'全唐诗/poet.song.127000.json','["遲遲晝景轉庭除，似覺今朝化日舒。", "印篆旋添香晷刻，繡牀暗積線工夫。"]'),
('326f20bd-e788-46fd-8ac6-708448ee5550','劉益之判院輓章','姜特立','宋','宋诗','song-poetry','','[]','傾蓋如今五十春，中間還得綴華姻。',64,'全唐诗/poet.song.127000.json','["傾蓋如今五十春，中間還得綴華姻。", "單于萬里同哀使，馬援一鄉稱善人。", "告老已能官及子，頒恩更喜爵榮親。", "佳城一閉成千古，無復傳觴酒入唇。"]'),
('802ce30d-6e37-4944-8a9e-2f61a127aa39','潘夫人輓章','姜特立','宋','宋诗','song-poetry','','[]','登堂曾拜太夫人，秀偉端方迥不羣。',64,'全唐诗/poet.song.127000.json','["登堂曾拜太夫人，秀偉端方迥不羣。", "爲子求官因白屋，有孫擢第自青雲。", "身兼富壽人應少，眼見曾玄世罕聞。", "已被榮封猶未已，更看褒贈賁新墳。"]'),
('31e4e97e-7dfc-4e68-9537-a3802fa903e6','過行在宿詹塘','姜特立','宋','宋诗','song-poetry','','[]','三十年間倦路岐，今朝猶自羨輕肥。',64,'全唐诗/poet.song.127000.json','["三十年間倦路岐，今朝猶自羨輕肥。", "敝輿衝雨方行役，朴論干時未息機。", "日暮腸枵聊命酒，夜寒衾薄旋牽衣。", "一廛三徑何時遂，且待相如駟馬歸。"]'),
('7d72949c-c272-4980-a495-499a650a5527','遇雪','姜特立','宋','宋诗','song-poetry','','[]','艱難要經歷，勿爲居所移。',48,'全唐诗/poet.song.127000.json','["艱難要經歷，勿爲居所移。", "方茲冒雪行，有愧在家時。", "杯酒全無力，春寒易著肌。", "誰能念此老，團坐有癡兒。"]'),
('f113870e-da1c-4170-9443-f575ebbdb855','留題雪峰','姜特立','宋','宋诗','song-poetry','','[]','雪峰未到意先猜，只恐冰崖凍不開。',64,'全唐诗/poet.song.127000.json','["雪峰未到意先猜，只恐冰崖凍不開。", "多謝天公憐倦客，故將暖律入踈梅。", "龍湫慘淡驚神物，象緯崢嶸逼斗魁。", "顧我區區亦何者，扶藤能爲此山來。"]'),
('577c28ce-dbc0-4879-9c0f-2000a271dc65','代陳公實上通守王剛父四首  其一','姜特立','宋','宋诗','song-poetry','','[]','我識通川守，人才世所稀。',48,'全唐诗/poet.song.127000.json','["我識通川守，人才世所稀。", "金陵傳正印，葉縣悟圓機。", "國論曾三接，邊城且一麾。", "從今雌甲子，洗眼看雄飛。"]'),
('d0e8dd8b-0529-4474-a36d-e260c2aa42d0','代陳公實上通守王剛父四首  其二','姜特立','宋','宋诗','song-poetry','','[]','戍解淮山月，波平瀚海秋。',48,'全唐诗/poet.song.127000.json','["戍解淮山月，波平瀚海秋。", "主憂銷北顧，賓宴接南樓。", "自愧成村叟，無因接勝流。", "鈴齋聽客鴈，應念稻粱謀。"]'),
('adafc8a3-98cf-4dd8-ba70-83f29b03cbdc','代陳公實上通守王剛父四首  其三','姜特立','宋','宋诗','song-poetry','','[]','淮上津程遠，山陰信息稀。',48,'全唐诗/poet.song.127000.json','["淮上津程遠，山陰信息稀。", "有塵生曉甑，無帛剪寒機。", "稚子莫垂泣，故人今把麾。", "歲闌歸意速，目斷鴈南飛。"]'),
('16a837b7-ca54-4778-a577-355401af1c75','代陳公實上通守王剛父四首  其四','姜特立','宋','宋诗','song-poetry','','[]','洗甲通盟後，同庚緩带秋。',48,'全唐诗/poet.song.127000.json','["洗甲通盟後，同庚緩带秋。", "邊聲寒卧鼓，海色靜明樓。", "冉冉歲云莫，栖栖詩者流。", "不才同社櫟，一飽愧身謀。"]'),
('c9c5c4b5-b4c6-4fd9-8233-a6b750cb60e2','和雪詩','姜特立','宋','宋诗','song-poetry','','[]','怪見司寒着意濃，巧裁六出羨天工。',64,'全唐诗/poet.song.127000.json','["怪見司寒着意濃，巧裁六出羨天工。", "烏翻樹拂梨花月，鷺起沙平玉篆風。", "勢合深連雲渚北，光寒淡抹粉牆東。", "梁園賦就驚先手，末至相如敢擅雄。"]'),
('7b776b0d-6e38-4686-955c-a24442fe3122','通守田太尉生辰二首  其一','姜特立','宋','宋诗','song-poetry','','[]','犀庭淵角凜英姿，褒鄂凌烟想畫時。',64,'全唐诗/poet.song.127000.json','["犀庭淵角凜英姿，褒鄂凌烟想畫時。", "建武堂深閒緩带，籌邊樓迥靜哦詩。", "曾乘神驥參天仗，還插宮花賜寶巵。", "今日北門方借重，九重久已結深知。"]'),
('90901809-944e-4df8-90ee-54abce0daefe','通守田太尉生辰二首  其二','姜特立','宋','宋诗','song-poetry','','[]','吳頭楚尾幾名邦，公以循良達舜廊。',64,'全唐诗/poet.song.127000.json','["吳頭楚尾幾名邦，公以循良達舜廊。", "未把勳庸齊寇鄧，直將教化繼龔黄。", "蠹蠲前政人云樂，最上諸司議曰臧。", "只恐周廬頼彈壓，芝泥趣召覲清光。"]'),
('b5283852-ba0f-4796-9c20-11e67ee71050','昭君','姜特立','宋','宋诗','song-poetry','','[]','漢宮胡地真天壤，一別長門隔塞雲。',32,'全唐诗/poet.song.127000.json','["漢宮胡地真天壤，一別長門隔塞雲。", "莫謂琵琶慰行役，琴心不比卓文君。"]'),
('f6d0bb36-147b-4626-9720-a6b96acac688','賦孫宰知魚亭','姜特立','宋','宋诗','song-poetry','','[]','萬物各有適，所樂乃其天。',168,'全唐诗/poet.song.127000.json','["萬物各有適，所樂乃其天。", "達人默識之，此意妙難傳。", "賢哉漆園吏，知魚豈其然。", "客問子非魚，烏知魚樂全。", "答云我所知，知之濠梁間。", "問者固已遠，答者不亦難。", "要知知魚樂，當作夢蝶觀。", "周與蝶非兩，魚我寧相懸。", "海門孫夫子，讀書必鈎玄。", "結茅製小亭，下瞰碧玉灣。", "因魚揭佳名，理賾非言詮。", "夫子固知魚，魚亦知君賢。", "我欲從之游，褰裳濯清泉。", "魚乎可勿猜，久矣忘機緣。"]'),
('59558cc9-5f48-4c38-bac0-e4d59888a7c6','江口阻風寄琅山衷老','姜特立','宋','宋诗','song-poetry','','[]','人間有浄境，咫尺不易通。',144,'全唐诗/poet.song.127000.json','["人間有浄境，咫尺不易通。", "今朝解塵縛，始到天人宮。", "疊嶂擁崔嵬，夏木鬰青葱。", "白鳥巢半山，掩映畫圖中。", "高低闢窗牖，綠陰翳芳叢。", "境寂意自佳，坐久心彌空。", "更茲主人賢，晤語禪味融。", "歸途若有得，便欲超樊籠。", "奈此塵緣深，蹤跡如驚鴻。", "驅車出蘭若，俯首坐踈篷。", "連日滯江干，風雨渺冥濛。", "緬懷支道林，此會何時逢。"]'),
('52aeb45e-ad61-408a-9f01-f085109b3782','贈孫宰雪中招飲','姜特立','宋','宋诗','song-poetry','','[]','令尹宣和氣，冰花兩度開。',48,'全唐诗/poet.song.127000.json','["令尹宣和氣，冰花兩度開。", "德星方此聚，瑞應瞥然來。", "玉篆縈紅炬，天酥落酒杯。", "相持索新句，慙愧謫仙才。"]'),
('9b916486-64ee-4062-98ec-fc5b29b7b5ac','施元用醉謁邑大夫胡公公賢者也不以爲浼己翌旦袖刺見之元用以喜雨十詩爲謝仙尉孫公贈詩曰甕邊不識畢吏部筆下方知李翰林釋其嫌一時和者相繼其族兄德茂復有詩箴之元用遂銳然止酒事有曲折情存彼此然百里不失爲通德茂合於義元用勇於决皆是也括蒼姜子爲長篇以合之簡元用兼呈諸公庶幾期於大同泯然無迹矣','姜特立','宋','宋诗','song-poetry','','[]','肩吾有雲孫，磊砢東州瑞。',288,'全唐诗/poet.song.127000.json','["肩吾有雲孫，磊砢東州瑞。", "一誦能萬言，落筆忽千字。", "才抽獨繭緒，態湧春雲思。", "喜慕高陽徒，時追習池醉。", "笑被僒囚拘，跌宕每自肆。", "心知令尹賢，詭迹姑爾試。", "誰知趙藺卿，復袖禰衡刺。", "非意忽相得，直到古人地。", "施君激深知，十詩手自贄。", "梅仙亦奇才，睨此一時事。", "新篇發佳話，冰釋兩公意。", "賡載皆文豪，璀璨明璣墜。", "西鄰有伯氏，規切豈亡謂。", "甘言古所戒，矯枉未傷義。", "昔人有火攻，達士胡足累。", "施君真勇者，念酒寧我祟。", "指天誓止飲，忽改開羣視。", "邴原恐廢業，陶侃憂親恚。", "獨醒向清湘，自責當先隧。", "古來有若人，於我適相類。", "勿學劉伯倫，詛婦儕兒戲。", "勿學陶元亮，止酒詩非志。", "自此真止矣，惟當醉經笥。", "湎然啜醇醲，抖擻糟粕棄。"]'),
('803ca14d-a39d-49bd-80ae-da9f386b3096','爲通州守賦綠漪亭二首  其一','姜特立','宋','宋诗','song-poetry','','[]','亭占佳名淮海東，六丁擁上水仙宮。',64,'全唐诗/poet.song.127000.json','["亭占佳名淮海東，六丁擁上水仙宮。", "簷牙簾額烟霏裏，人語歌聲荷氣中。", "酒醆吸殘千斛月，釣竿擲下一絲風。", "使君清德真如水，潭影人心盡日空。"]'),
('8d25c05c-9dd0-4c3d-bb61-95268ecadf16','爲通州守賦綠漪亭二首  其二','姜特立','宋','宋诗','song-poetry','','[]','景物天開四面寬，如披百幅畫圖看。',64,'全唐诗/poet.song.127000.json','["景物天開四面寬，如披百幅畫圖看。", "有時鷗鷺下蒼靄，無數菰蒲生碧瀾。", "獨立晚凉秋思動，醉呼小艇水雲寒。", "他年虎節重來訪，唯有恩波不解乾。"]'),
('dc68a74f-4fde-46f0-9a77-4a2619bf53b6','題琅山大江','姜特立','宋','宋诗','song-poetry','','[]','初出岷峨一線微，波濤到此浩無涯。',64,'全唐诗/poet.song.127000.json','["初出岷峨一線微，波濤到此浩無涯。", "坤隅橫貫五千里，天塹雄當百萬師。", "虎戰龍爭猶可記，鷗閒鷺靜幾曾知。", "莫言天意限南北，正是中興混一時。"]'),
('80180029-c3ec-469b-8540-7cf92097082b','明月歌','姜特立','宋','宋诗','song-poetry','','[]','月在天兮何高，我居世兮何卑。',58,'全唐诗/poet.song.127000.json','["月在天兮何高，我居世兮何卑。", "高卑相去幾萬里，年年夜夜長相隨。", "明月入我懷，我攬明月輝。", "妙明中間含萬象，此時此境誰能知。"]'),
('55bbd06d-553a-4d65-bb70-ff17d7201e7e','閒退自適','姜特立','宋','宋诗','song-poetry','','[]','老退保餘生，不愧身與口。',24,'全唐诗/poet.song.127000.json','["老退保餘生，不愧身與口。", "大似劉真長，東山亦何有。"]'),
('baa6bf96-22c8-4a2a-bfd5-465c00c85d42','對酒','姜特立','宋','宋诗','song-poetry','','[]','老態日日增，歡意時時改。',24,'全唐诗/poet.song.127000.json','["老態日日增，歡意時時改。", "唯有對壺觴，依然此心在。"]'),
('c1535cc8-b3d5-43a6-8d24-32a236d4b0e6','春事','姜特立','宋','宋诗','song-poetry','','[]','春事動勾芒，閒行嗅嫩芳。',24,'全唐诗/poet.song.127000.json','["春事動勾芒，閒行嗅嫩芳。", "人無前日興，花有舊時香。"]'),
('43849299-573d-4937-97a7-b6d1f7c16521','寄虞大卿四首  其一','姜特立','宋','宋诗','song-poetry','','[]','韋郎昔日在蘇州，唯許丘丹共唱酬。',32,'全唐诗/poet.song.127000.json','["韋郎昔日在蘇州，唯許丘丹共唱酬。", "今日故人天上去，誰將好句慰清愁。"]'),
('ecf77d4a-7813-4de8-a6e8-93269712d44f','寄虞大卿四首  其二','姜特立','宋','宋诗','song-poetry','','[]','彩鳳鏘鳴瑞上都，秋蛩春蚓謾吟哦。',32,'全唐诗/poet.song.127000.json','["彩鳳鏘鳴瑞上都，秋蛩春蚓謾吟哦。", "寄言郊島休聯句，且聽臯夔賡帝歌。"]'),
('53855cef-c649-46f6-a4f8-fb6ad7557adb','寄虞大卿四首  其三','姜特立','宋','宋诗','song-poetry','','[]','聞道新詩日漸多，珍藏未放落江湖。',32,'全唐诗/poet.song.127000.json','["聞道新詩日漸多，珍藏未放落江湖。", "拋甎此語真相戲，和璧如何肯抵烏。"]'),
('35683079-33dc-4d29-b2cd-62dbf8fecca1','寄虞大卿四首  其四','姜特立','宋','宋诗','song-poetry','','[]','昔年寓郡獲親依，句妙時時得解頤。',32,'全唐诗/poet.song.127000.json','["昔年寓郡獲親依，句妙時時得解頤。", "每過雙溪溪上路，邦人猶誦使君詩。"]'),
('ec66c4ec-bd17-45b1-94a1-cea80e499b92','春到','姜特立','宋','宋诗','song-poetry','','[]','春到天寒花未芳，老人寸寸惜流光。',32,'全唐诗/poet.song.127000.json','["春到天寒花未芳，老人寸寸惜流光。", "攀條先試東風手，蜂蝶如知合斷腸。"]'),
('3ae5929c-b35a-4bba-9486-709bcb35238e','寄題須記亭','姜特立','宋','宋诗','song-poetry','','[]','橙橘年年熟，青黄滿故枝。',60,'全唐诗/poet.song.127000.json','["橙橘年年熟，青黄滿故枝。", "坡仙自有見，妙語寄新詩。", "好處須令記，欲記難爲辭。", "公意非我意，我樂公不知。", "體會在何所，請觀濠上時。"]'),
('4a114fbd-4dda-4114-b8e9-966cc6d9828e','梅山','姜特立','宋','宋诗','song-poetry','','[]','欲識梅山境，回環列萬峯。',24,'全唐诗/poet.song.127000.json','["欲識梅山境，回環列萬峯。", "朱門依綠水，粉堵出青松。"]'),
('af986253-c025-4c24-b33b-957b6cf4835c','劉晁之家園六詠 梅澗','姜特立','宋','宋诗','song-poetry','','[]','勝事人間少，芳堤盡種梅。',120,'全唐诗/poet.song.127000.json','["勝事人間少，芳堤盡種梅。", "橫枝出踈影，蠹枿長蒼苔。", "瀟灑依湍瀨，飄零落酒杯。", "戲魚時躍去，凍蝶忽飛來。", "宛似孤山見，還如庾嶺開。", "只將松作友，更與竹爲媒。", "迥出千林表，真成百卉魁。", "羞爭桃李豔，自是棟梁材。", "止渴將軍智，調羹上相才。", "風光無着處，吟思發春雷。"]'),
('e9fe8766-fd70-4bfb-a13b-e52bd12c333f','劉晁之家園六詠 紅雲','姜特立','宋','宋诗','song-poetry','','[]','海棠亭上號紅雲，晴日青天絳綵新。',32,'全唐诗/poet.song.127000.json','["海棠亭上號紅雲，晴日青天絳綵新。", "疑是羣仙朝玉闕，一時都戴紫霞巾。"]'),
('ab8d44fb-b9c5-410d-8c88-0788381580a5','劉晁之家園六詠 竚棹','姜特立','宋','宋诗','song-poetry','','[]','青溪一曲似清湘，刳木臨流製小航。',32,'全唐诗/poet.song.127000.json','["青溪一曲似清湘，刳木臨流製小航。", "莫怪時時來竚棹，一生心事水雲鄉。"]'),
('104a1f29-28ff-42a7-b65e-dc09460f8fc8','劉晁之家園六詠 浸碧','姜特立','宋','宋诗','song-poetry','','[]','澄潭喬木插晴煙，樹影溪光相接連。',32,'全唐诗/poet.song.127000.json','["澄潭喬木插晴煙，樹影溪光相接連。", "我欲呼兒操小艇，醉時坐看水中天。"]'),
('46994828-42eb-4c28-a016-d325a3138a18','劉晁之家園六詠 露華','姜特立','宋','宋诗','song-poetry','','[]','水氣澄鮮暑氣微，一池菡萏映漣漪。',32,'全唐诗/poet.song.127000.json','["水氣澄鮮暑氣微，一池菡萏映漣漪。", "精神妙處無人見，只在風清月冷時。"]'),
('a09204cf-7dde-4dc6-89fa-59cfd9e3499a','劉晁之家園六詠 翠螺','姜特立','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','繞旋曾不費躋攀，累土爲基聳髻鬟。',32,'全唐诗/poet.song.127000.json','["繞旋曾不費躋攀，累土爲基聳髻鬟。", "恰似洞庭湖上望，爛銀槃裏對君山。"]'),
('6b6ed875-9f51-4c10-a431-025c753c8861','汪尚書輓章二首  其一','姜特立','宋','宋诗','song-poetry','','[]','昔年宦路意相傾，四紀中間一寄聲。',64,'全唐诗/poet.song.127000.json','["昔年宦路意相傾，四紀中間一寄聲。", "賢嗣登門如對面，新詩緘興見輸情。", "安輿方擬來巖邑，急訃俄傳上玉京。", "歎息于今尠人物，短章吟罷淚霑纓。"]'),
('fa62cebf-0785-434c-ad88-037b634c8b80','汪尚書輓章二首  其二','姜特立','宋','宋诗','song-poetry','','[]','文章事業蓋羣工，盛世明良喜會同。',64,'全唐诗/poet.song.127000.json','["文章事業蓋羣工，盛世明良喜會同。", "千首歌詩如白傅，百篇奏議似宣公。", "貳師失道違中制，元帥基謀喪後功。", "二十年間遂高志，鴟夷一舸鑑湖東。"]'),
('23d80f6a-f0c9-4087-9706-edff749cff23','足弱','姜特立','宋','宋诗','song-poetry','','[]','足弱老態增，顛仆人共駭。',24,'全唐诗/poet.song.127000.json','["足弱老態增，顛仆人共駭。", "無趾真吾師，天刑烏可解。"]'),
('244fa6b0-1c2c-431b-899a-dbe87fcddb1c','偶題','姜特立','宋','宋诗','song-poetry','','[]','冷澹清虛未是貧，吾家富貴自天真。',32,'全唐诗/poet.song.127000.json','["冷澹清虛未是貧，吾家富貴自天真。", "江山風月元無禁，只許閒人作主人。"]'),
('726274b6-dd7c-4aa9-a7af-e4a88b26a960','壓酒','姜特立','宋','宋诗','song-poetry','','[]','酒到劉伶墳，斯人已枯槁。',24,'全唐诗/poet.song.127000.json','["酒到劉伶墳，斯人已枯槁。", "不如營糟丘，吾將此中老。"]'),
('cec40ffa-84d2-40b1-8ea4-13c2f886d611','喜晴','姜特立','宋','宋诗','song-poetry','','[]','晴日曬江臯，人心散鬰陶。',48,'全唐诗/poet.song.127000.json','["晴日曬江臯，人心散鬰陶。", "天地忽開泰，萬象分秋毫。", "瀉我竹葉青，烹我翠雲濤。", "勿與俗士對，且讀楚人騷。"]'),
('22062a62-75d5-40dc-9f87-ca46488d66b0','晴雲','姜特立','宋','宋诗','song-poetry','','[]','晴雲行太虛，浩蕩本無心。',48,'全唐诗/poet.song.127000.json','["晴雲行太虛，浩蕩本無心。", "隨風忽變化，倏忽成古今。", "卓爾起奇峯，萬目競瞻仰。", "本自無心高，莫作有心想。"]'),
('74c188cc-3ec3-4838-8edc-029b21c7f9f9','重九','姜特立','宋','宋诗','song-poetry','','[]','淵明頗愛重九名，我亦愛飲重九酒。',32,'全唐诗/poet.song.127000.json','["淵明頗愛重九名，我亦愛飲重九酒。", "已辦黄菊與紅萸，喚起陶公爲四友。"]'),
('a566a0db-ef11-4815-9c96-3313516456f2','林和叔山園九詠 安坻','姜特立','宋','宋诗','song-poetry','','[]','規創仙舟傍水涯，搜名揭榜號安坻。',32,'全唐诗/poet.song.127000.json','["規創仙舟傍水涯，搜名揭榜號安坻。", "于今措足如平地，無復風波十二時。"]'),
('4da2042b-0f77-425d-be48-35cdc4a92b1e','林和叔山園九詠 娛老','姜特立','宋','宋诗','song-poetry','','[]','老來何事可娛嬉，堂枕崔嵬瞰綠漪。',32,'全唐诗/poet.song.127000.json','["老來何事可娛嬉，堂枕崔嵬瞰綠漪。", "自有山光并水色，不須花貌與蛾眉。"]'),
('6067e98b-8fd0-4981-98dc-dd9e05eb5846','林和叔山園九詠 西望','姜特立','宋','宋诗','song-poetry','','[]','江山靜處遠紅塵，出郭肩輿意自真。',32,'全唐诗/poet.song.127000.json','["江山靜處遠紅塵，出郭肩輿意自真。", "西望市喧聲合處，中間幾箇是閒人。"]'),
('2b6adf09-a5bb-4895-a7bd-2149f174ca82','林和叔山園九詠 數花','姜特立','宋','宋诗','song-poetry','','[]','橫身障簏又何癡，睡聽朝雞欲曉時。',32,'全唐诗/poet.song.127000.json','["橫身障簏又何癡，睡聽朝雞欲曉時。", "唯有先生無一事，偶來閒坐數花枝。"]'),
('f0c2fb34-2d60-47d8-be07-2510455197f6','林和叔山園九詠 霞隠','姜特立','宋','宋诗','song-poetry','','[]','流水桃花幾換春，花溪溪上好棲真。',32,'全唐诗/poet.song.127000.json','["流水桃花幾換春，花溪溪上好棲真。", "此中自有神仙伴，不是秦時避世人。"]'),
('02792f07-81e8-46b5-8b67-ce77f335f9b6','林和叔山園九詠 秀野','姜特立','宋','宋诗','song-poetry','','[]','坡仙獨樂賦新詩，秀野於公兩得之。',32,'全唐诗/poet.song.127000.json','["坡仙獨樂賦新詩，秀野於公兩得之。", "山卉名花同一囿，調元妙手本無私。"]'),
('dc3f7c66-089e-40f5-a290-c2a040f6222b','林和叔山園九詠 霜餘','姜特立','宋','宋诗','song-poetry','','[]','龜殻浮游不問津，壺中日月自長春。',32,'全唐诗/poet.song.127000.json','["龜殻浮游不問津，壺中日月自長春。", "向來橘隠商山樂，今日中間添一人。"]'),
('aed688aa-d051-4e1c-af45-a684fe44c69d','林和叔山園九詠 鷗渚','姜特立','宋','宋诗','song-poetry','','[]','歸來林下久忘機，表裏虛明更不疑。',32,'全唐诗/poet.song.127000.json','["歸來林下久忘機，表裏虛明更不疑。", "俯仰自知無愧怍，此心何止白鷗知。"]'),
('5ac3b9f8-5e57-4cda-830a-fb79da1ca935','林和叔山園九詠 細香','姜特立','宋','宋诗','song-poetry','','[]','翠莖綠蔭散高岡，老氣崢嶸耐雪霜。',32,'全唐诗/poet.song.127000.json','["翠莖綠蔭散高岡，老氣崢嶸耐雪霜。", "不獨清虛符有德，紫綳纔脫便馨香。"]'),
