('8bbd60c3-5cca-4dc7-b30c-1465a1c22bca','賜節','姜特立','宋','宋诗','song-poetry','','[]','潛藩伴讀六年餘，賜鉞君王念老儒。',32,'全唐诗/poet.song.127000.json','["潛藩伴讀六年餘，賜鉞君王念老儒。", "祿厚養成閒意思，日長添得睡工夫。"]'),
('024fc56c-801f-49c4-b177-529c5e4b467d','足弱二首  其一','姜特立','宋','宋诗','song-poetry','','[]','八十頹齡血氣微，杖而後起固其宜。',32,'全唐诗/poet.song.127000.json','["八十頹齡血氣微，杖而後起固其宜。", "堯夫有句君聽取，脚力衰時藥不醫。"]'),
('6922c67e-2bea-48bf-a46c-d55037b840f6','足弱二首  其二','姜特立','宋','宋诗','song-poetry','','[]','脚力雖云弱，心靈尚宛然。',24,'全唐诗/poet.song.127000.json','["脚力雖云弱，心靈尚宛然。", "休輕刖孫臏，猶解殺龐涓。"]'),
('a81500a2-83ca-4380-8bdb-9d42a561bcfc','竹翠','姜特立','宋','宋诗','song-poetry','','[]','竹翠凉虛寢，爐薰養道情。',24,'全唐诗/poet.song.127000.json','["竹翠凉虛寢，爐薰養道情。", "日長無一事，燕坐有餘清。"]'),
('979ef72f-221b-4d61-83cf-fead4e74f564','劉景文','姜特立','宋','宋诗','song-poetry','','[]','憶昔劉景文，其父死西戰。',48,'全唐诗/poet.song.127000.json','["憶昔劉景文，其父死西戰。", "出身與我同，詩文亦璀璨。", "結交蘇與黄，秦張同一貫。", "文武初不分，西班不須換。"]'),
('fd0d548b-b44a-4e39-8c14-194a2d65919f','和丁使君八詠樓  其一','姜特立','宋','宋诗','song-poetry','','[]','八詠詩成沈隠侯，樓中風月盡兼收。',64,'全唐诗/poet.song.127000.json','["八詠詩成沈隠侯，樓中風月盡兼收。", "三千題裏無新語，七百年間有勝流。", "領客登臨聊一快，舉杯相屬更無憂。", "令威早晚沖天去，華表歸時記舊游。"]'),
('77a16b2b-dc32-4071-bd79-507aad898806','和丁使君八詠樓  其二','姜特立','宋','宋诗','song-poetry','','[]','使君政事妙如神，更有新詩字字新。',64,'全唐诗/poet.song.127000.json','["使君政事妙如神，更有新詩字字新。", "方仰高深如海嶽，豈知出沒尚參辰。", "愛公自昔稱賢守，喜我如今有主人。", "况是蘇州許酬唱，丘丹應得寄閒身。"]'),
('ea4ca020-ad4d-466e-8c1d-8bd2067b8f9a','中夏','姜特立','宋','宋诗','song-poetry','','[]','正此恢台夏，園池綠蔭交。',24,'全唐诗/poet.song.127000.json','["正此恢台夏，園池綠蔭交。", "高荷擎羽蓋，新笋出旗梢。"]'),
('2b5d5199-284a-49bb-948f-8595453c0ba5','暇日家人饋酒食','姜特立','宋','宋诗','song-poetry','','[]','王度清夷無忌諱，私家甘旨自充庖。',32,'全唐诗/poet.song.127000.json','["王度清夷無忌諱，私家甘旨自充庖。", "不須乞食歌姬院，自有佳人送酒肴。"]'),
('ba220d7e-d985-40bb-ad04-ca1a7ee6708b','老醜戲題','姜特立','宋','宋诗','song-poetry','','[]','目深顴起貌嶄然，長臂厖眉聳兩肩。',32,'全唐诗/poet.song.127000.json','["目深顴起貌嶄然，長臂厖眉聳兩肩。", "宛似阿羅老尊者，不妨時說小乘禪。"]'),
('ce7675cc-47ce-4f5c-87b8-92124c7ef26c','喜雨','姜特立','宋','宋诗','song-poetry','','[]','身居焰焰祝融堆，一夜西風捲雨來。',32,'全唐诗/poet.song.127000.json','["身居焰焰祝融堆，一夜西風捲雨來。", "酷吏手中逃得活，故人別後共銜盃。"]'),
('a9353a51-ccfb-4862-9d4a-e2f21690429a','山中','姜特立','宋','宋诗','song-poetry','','[]','不到山中久，山寒景益奇。',24,'全唐诗/poet.song.127000.json','["不到山中久，山寒景益奇。", "凍泉零雪谷，墜葉弄風絲。"]'),
('327e0d8f-0aa2-42d9-a041-7773c191f0c7','和丁使君惠贈  其一','姜特立','宋','宋诗','song-poetry','','["\u897f\u6e56"]','浙江茅土幾諸侯，美譽唯公一日收。',64,'全唐诗/poet.song.127000.json','["浙江茅土幾諸侯，美譽唯公一日收。", "馮翊望之新得郡，潁川黄霸舊承流。", "西湖一火愁中禁，東郡三霖慰客憂。", "早晚秋風吹紫桂，百錢應伴使君游。"]'),
('d015cc56-78cd-4f94-9d45-402c64f9eb94','和丁使君惠贈  其二','姜特立','宋','宋诗','song-poetry','','[]','杜老才高筆有神，却誇庾信句清新。',64,'全唐诗/poet.song.127000.json','["杜老才高筆有神，却誇庾信句清新。", "方慚醜女依西子，更覺常星望北辰。", "眼底向來無作者，世間此去有詩人。", "交情何似吟情好，託契猶堪慰老身。"]'),
('99181fc0-3cf0-42b7-89f8-e80867af3686','和叔豹詠家園','姜特立','宋','宋诗','song-poetry','','[]','小園繚繞瞰滄灣，搜抉天藏不放閒。',64,'全唐诗/poet.song.127000.json','["小園繚繞瞰滄灣，搜抉天藏不放閒。", "愧我筆端無錦繡，羨君胸次有江山。", "規模未出經營外，物象先歸賦詠間。", "何日携笻來共醉，每於勝處一開顔。"]'),
('abc09a9f-f861-412f-ac5d-10a3d819813c','夏夜露坐','姜特立','宋','宋诗','song-poetry','','[]','脫幘思悠哉，崢嶸望斗魁。',48,'全唐诗/poet.song.127000.json','["脫幘思悠哉，崢嶸望斗魁。", "好風蘋末起，清興月邊來。", "天地供吟筆，星河落酒杯。", "神仙去不遠，便欲跨蓬萊。"]'),
('7b2014c5-675c-40b2-b792-7841af0fc86a','舟喻','姜特立','宋','宋诗','song-poetry','','[]','樓船萬險出驚湍，未到安坻未是安。',32,'全唐诗/poet.song.127000.json','["樓船萬險出驚湍，未到安坻未是安。", "萬一暗逢羅剎石，破舟覆族有何難。"]'),
('5102fd5e-f0fc-4f1a-b2a9-e6417522cd1a','養雞抱犢摩詰語也戲廣其說','姜特立','宋','宋诗','song-poetry','','[]','雲裏養雞非是達，山頭抱犢未爲真。',32,'全唐诗/poet.song.127000.json','["雲裏養雞非是達，山頭抱犢未爲真。", "何如老奉閒香火，醉卧林間了此身。"]'),
('e38d92f9-03d1-40c0-ab90-88ccff345779','苦樂','姜特立','宋','宋诗','song-poetry','','[]','人生苦樂與俱生，不問侯王及庶氓。',32,'全唐诗/poet.song.127000.json','["人生苦樂與俱生，不問侯王及庶氓。", "萬事隨緣安樂法，莫求好處一邊行。"]'),
('68c27fb7-5059-49c8-97d2-fefa000ef73a','喜晴','姜特立','宋','宋诗','song-poetry','','[]','日出天開眼，雲收見物華。',48,'全唐诗/poet.song.127000.json','["日出天開眼，雲收見物華。", "不餐還自飽，無酒却須賒。", "綠遍千絲柳，紅添幾樹花。", "如何酬造物，爛醉是生涯。"]'),
('8ce6e964-2ffb-4048-ab1e-ac71b6106c47','紀恩詩','姜特立','宋','宋诗','song-poetry','','[]','百首清詩夜上，九重溫詔晨頒。',28,'全唐诗/poet.song.127000.json','["百首清詩夜上，九重溫詔晨頒。", "自古封侯賜璧，慷慨只立談間。"]'),
('bf0e8e24-9e20-42d9-9bce-6efcaa2aeac9','驟寒擁爐','姜特立','宋','宋诗','song-poetry','','[]','雪霰曉漫漫，天公剩作寒。',24,'全唐诗/poet.song.127000.json','["雪霰曉漫漫，天公剩作寒。", "林梢棲白鳳，爐焰舞紅鸞。"]'),
('3918d855-bde3-4462-bd3e-ac3817814699','足弱感劉賓客跛牛歎','姜特立','宋','宋诗','song-poetry','','[]','劉子憐跛牛，行將就庖宰。',48,'全唐诗/poet.song.127000.json','["劉子憐跛牛，行將就庖宰。", "云斯竟不免，觳觫有何罪。", "爲善無近名，月刀用則匱。", "莊氏其至言，超然出形器。"]'),
('79fbe7f9-2111-4252-8df3-8ceb3f63f26c','余丞相薨長沙','姜特立','宋','宋诗','song-poetry','','[]','一紀歸來老薜蘿，須知養壽是蹉跎。',32,'全唐诗/poet.song.127000.json','["一紀歸來老薜蘿，須知養壽是蹉跎。", "幾人盡向忙中去，我比時賢日已多。"]'),
('bd13f1dc-d64c-4e1c-9c66-ca74aea919f9','寄邦佐弟歸鄉','姜特立','宋','宋诗','song-poetry','','[]','馮公嶺上翠摩空，下視羣山千萬重。',32,'全唐诗/poet.song.127000.json','["馮公嶺上翠摩空，下視羣山千萬重。", "想得行人歸意速，又穿雲樹過前峯。"]'),
('aef64cbe-4f21-4432-adbf-c04b06a88349','旌節','姜特立','宋','宋诗','song-poetry','','[]','君恩華我老，旌節到柴門。',72,'全唐诗/poet.song.127000.json','["君恩華我老，旌節到柴門。", "我本一書生，乃忝侯伯尊。", "憶昔有鼻祖，漁釣干周文。", "既已成王業，營丘垂後昆。", "功德雖不同，齒貌略可論。", "相望數千載，但愧非賢孫。"]'),
('b5d124d6-8bab-40b8-855e-c7fd683faf3c','把酒','姜特立','宋','宋诗','song-poetry','','[]','淺把涓涓酒，風流杜少陵。',24,'全唐诗/poet.song.127000.json','["淺把涓涓酒，風流杜少陵。", "是中有真趣，全勝醉瞢騰。"]'),
('07bb51bb-e544-4a6c-af80-01dbdb755118','竹杖','姜特立','宋','宋诗','song-poetry','','[]','竹杖點湘斑，長隨掌握間。',24,'全唐诗/poet.song.127000.json','["竹杖點湘斑，長隨掌握間。", "老來方得力，伴我一生閒。"]'),
('1ad775b6-1c29-4ece-b9bb-560d20e423af','足弱再賦','姜特立','宋','宋诗','song-poetry','','[]','四大假合成，足弱非我病。',72,'全唐诗/poet.song.127000.json','["四大假合成，足弱非我病。", "但作如是觀，乃悟真實性。", "當時維摩詰，聊示世間身。", "凡欲問疾者，正墮煩惱因。", "我若於爾時，便當作禮去。", "病既無從生，自有歡喜處。"]'),
('187812b0-b565-4b5c-8a0d-0bf1dc9dc3ca','不寐','姜特立','宋','宋诗','song-poetry','','[]','老人夜不瞑，宿鳥未安棲。',24,'全唐诗/poet.song.127000.json','["老人夜不瞑，宿鳥未安棲。", "送睡憑盃酒，思晨聽曉雞。"]'),
('0e392b20-1308-475a-9c42-30b716930a84','秋後得雨','姜特立','宋','宋诗','song-poetry','','[]','亢夏草木死，旱火熾如焚。',72,'全唐诗/poet.song.127000.json','["亢夏草木死，旱火熾如焚。", "秋深得雨凉，萬物生精神。", "庭蕉抽綠書，野草秀芳茵。", "風露洗芙蓉，豔質照商旻。", "我亦病體蘇，楚楚整冠巾。", "乘時一尊酒，豈曰非良辰。"]'),
('1380f76e-9ab7-4edd-80a1-b75d63178be8','九月赴郡燕旄節適至','姜特立','宋','宋诗','song-poetry','','[]','賢侯佳節初開燕，誰是風流晉孟嘉。',64,'全唐诗/poet.song.127000.json','["賢侯佳節初開燕，誰是風流晉孟嘉。", "已判百年唯白髮，不羞九日對黄花。", "擁旄遥佩藩臣印，把盞重來刺史家。", "希事此邦應未有，一時千里借光華。"]'),
('c5737cb4-e73a-4071-8a01-fa2b4323c4bf','郡中九日賞菊及牡丹時樂禁未開','姜特立','宋','宋诗','song-poetry','','[]','兩朵牡丹開國豔，千叢黄菊散秋葩。',32,'全唐诗/poet.song.127000.json','["兩朵牡丹開國豔，千叢黄菊散秋葩。", "可憐賓主歡娛地，只向尊前不語花。"]'),
('f555b599-7e41-4fc4-8ea6-57f1e386ae54','和丁大卿韻','姜特立','宋','宋诗','song-poetry','','[]','久回俗駕向山中，無復詩騷見古風。',64,'全唐诗/poet.song.127000.json','["久回俗駕向山中，無復詩騷見古風。", "方喜故人千里至，更容清夜一尊同。", "賓筵談笑知無敵，筆力追陪愧未工。", "自古詩人難並世，歸期那敢話匆匆。"]'),
('96865cad-a459-45a5-98a6-55a9181fefa2','別大卿','姜特立','宋','宋诗','song-poetry','','[]','我來菊始華，我去菊方好。',72,'全唐诗/poet.song.127000.json','["我來菊始華，我去菊方好。", "主人遠招客，懽意不草草。", "投轄陳孟公，哦詩杜陵老。", "不憂垂橐歸，珠璣已盈抱。", "天寵忽鼎來，擁旄行就道。", "賢侯借輝光，春風發枯槁。"]'),
('c1d47b7f-83cf-4aeb-a7a2-fcf4767f0311','潘提屬拱翠樓','姜特立','宋','宋诗','song-poetry','','[]','拱翠千峯列髻鬟，危樓百尺破天慳。',64,'全唐诗/poet.song.127000.json','["拱翠千峯列髻鬟，危樓百尺破天慳。", "九霄星斗朱欄外，萬井人家綠樹間。", "水勢大江橫北固，地形小魯望東山。", "何當襆被從君住，借我時時豁醉顔。"]'),
('5fe2b042-f8a3-437c-b2cd-d30e6186f3fd','偶題','姜特立','宋','宋诗','song-poetry','','[]','平生事業詩千首，蓋世聲名黍一炊。',32,'全唐诗/poet.song.127000.json','["平生事業詩千首，蓋世聲名黍一炊。", "濩落中間偶成事，凉凉踽踽欲何爲。"]'),
('b26b5661-37f5-4c4e-8493-f8ba92b9fc6a','老饕','姜特立','宋','宋诗','song-poetry','','[]','東坡嘗作老饕賦，姜子年來老更饕。',128,'全唐诗/poet.song.127000.json','["東坡嘗作老饕賦，姜子年來老更饕。", "血氣已衰肌肉瘦，正如槁木渴春膏。", "伯仁若見求牛炙，畢卓如逢覓蟹螯。", "頷𦞦酒鯖和海錯，晚菘春韭雜溪毛。", "搜尋奇味須兒輩，調芼精能付主庖。", "君子固知居遠殺，老人詎可食無肴。", "鄰翁時喜分甘脆，侍妓偏能佐酒醪。", "萬事灰心唯有此，婆娑牖下任陶陶。"]'),
('5bd88d61-1bc7-4931-ab10-96d079da967e','偶題','姜特立','宋','宋诗','song-poetry','','[]','自是繩樞子，夤緣登宦途。',24,'全唐诗/poet.song.127000.json','["自是繩樞子，夤緣登宦途。", "閒情入魚鳥，歲晚卧江湖。"]'),
('5bd7383a-11c1-4c8c-9f55-da26f87e158f','沈約','姜特立','宋','宋诗','song-poetry','','[]','懷情既不盡，謚隠亦何疑。',24,'全唐诗/poet.song.127000.json','["懷情既不盡，謚隠亦何疑。", "截舌帝其怒，在天靈可欺。"]'),
('1c03d897-6651-45b1-903a-888d76670144','地爐','姜特立','宋','宋诗','song-poetry','','[]','穴處嘗聞太古時，規爐鑿地亦幾希。',32,'全唐诗/poet.song.127000.json','["穴處嘗聞太古時，規爐鑿地亦幾希。", "便成簡易真淳俗，坐喚兒孫共打圍。"]'),
('d0578d19-143b-4e6f-b08a-1782894968d9','和葉叔豹','姜特立','宋','宋诗','song-poetry','','[]','暮齡旌節寵旋歸，感謝皇恩念細微。',64,'全唐诗/poet.song.127000.json','["暮齡旌節寵旋歸，感謝皇恩念細微。", "已是丘園添盛事，更兼山水借清暉。", "老來自合深韜晦，語妙偏能相發揮。", "祝我青松君意厚，尚嫌詩瘦損腰圍。"]'),
('a71af772-a2da-442d-837a-0414fb0d97e6','酒徒','姜特立','宋','宋诗','song-poetry','','[]','酒徒狂態少威儀，看碧成朱兀似癡。',32,'全唐诗/poet.song.127000.json','["酒徒狂態少威儀，看碧成朱兀似癡。", "何似花時風月夕，提携歡伯緩相隨。"]'),
('54dc23e9-6248-434e-a7c3-51c156cf7b80','送丁大卿知廬州','姜特立','宋','宋诗','song-poetry','','[]','寄迹雙溪喜盍簪，剖符廬子遽分襟。',64,'全唐诗/poet.song.127000.json','["寄迹雙溪喜盍簪，剖符廬子遽分襟。", "伏波威著羌夷界，叔子恩懷江漢心。", "萬里烟塵入長筭，二邊風月待清吟。", "促歸早晚飛丹詔，新鴈回時有好音。"]'),
('df5125f2-2df2-4dfa-a32b-6273ff90bdbc','和弟邦佐邦達賀得節  其一','姜特立','宋','宋诗','song-poetry','','[]','初出鄉關歎屢空，行人愁見暮雲重。',32,'全唐诗/poet.song.127000.json','["初出鄉關歎屢空，行人愁見暮雲重。", "倦投山館憐吾足，踏徧千峯與萬峯。"]'),
('1254fb0a-5ca1-4157-8ac0-63117d878d21','和弟邦佐邦達賀得節  其二','姜特立','宋','宋诗','song-poetry','','[]','吾祖平生學苦空，至今餘慶尚重重。',32,'全唐诗/poet.song.127000.json','["吾祖平生學苦空，至今餘慶尚重重。", "佳城氣象年來別，秀出南屏第一峯。"]'),
('a7ace750-05a5-4ba7-a17a-0f1350327d96','和弟邦佐邦達賀得節  其三','姜特立','宋','宋诗','song-poetry','','[]','平生畫虎半成空，歲晚歸來好事重。',32,'全唐诗/poet.song.127000.json','["平生畫虎半成空，歲晚歸來好事重。", "屈指燎黄應不遠，金冠章紱看駝峯。"]'),
('920d7fb9-dbc7-492a-8383-4518dfdb0b50','春來葺圃','姜特立','宋','宋诗','song-poetry','','[]','園林索寞已飄梅，且喜東皇勒駕回。',32,'全唐诗/poet.song.127000.json','["園林索寞已飄梅，且喜東皇勒駕回。", "磨拭石臺需客至，支撐花架待春來。"]'),
('da10a3f2-bc7d-4cf4-859b-52dfb21791ae','夜永','姜特立','宋','宋诗','song-poetry','','[]','夜永醉還醒，隣雞已有聲。',24,'全唐诗/poet.song.127000.json','["夜永醉還醒，隣雞已有聲。", "衾寒霜令急，木落睡魂清。"]'),
('bc411913-a703-494f-b0fe-45a5ec66043b','吟詩  其一','姜特立','宋','宋诗','song-poetry','','[]','平生性僻愛吟詩，驅使風光如使兒。',32,'全唐诗/poet.song.127000.json','["平生性僻愛吟詩，驅使風光如使兒。", "縱橫妙用無凝滯，問著機緘自不知。"]'),
('061c3e29-7165-4ec8-96f1-4989d385eb51','吟詩  其二','姜特立','宋','宋诗','song-poetry','','[]','四始詩之至，源流治世音。',24,'全唐诗/poet.song.127000.json','["四始詩之至，源流治世音。", "後來無鄭衛，蛙蚓謾呻吟。"]'),
('18765b30-7ee3-49ff-adc7-f16653868cd7','王大卿輓詩','姜特立','宋','宋诗','song-poetry','','[]','少年登鴈塔，晚歲列鵷行。',48,'全唐诗/poet.song.127000.json','["少年登鴈塔，晚歲列鵷行。", "賈傅心憂漢，宣公疏奏唐。", "細氈親沃日，白簡舊凝霜。", "才大施猶狹，清名玉雪揚。"]'),
('04bfb485-ae87-4630-8900-08be4a518a69','報恩','姜特立','宋','宋诗','song-poetry','','[]','報恩須烈士，拂意是忠臣。',24,'全唐诗/poet.song.127000.json','["報恩須烈士，拂意是忠臣。", "君看傾邪輩，哨哨似婦人。"]'),
('2a93c20b-b3c4-46c6-afae-0e84dca99f44','臘殘','姜特立','宋','宋诗','song-poetry','','[]','臘殘梅破靨，春近柳含滋。',24,'全唐诗/poet.song.127000.json','["臘殘梅破靨，春近柳含滋。", "指日驩娛地，東風浩蕩時。"]'),
('373fcdf0-9c47-47df-866f-c35aa5b05bd9','村翁','姜特立','宋','宋诗','song-poetry','','[]','茅茨西日暖，翁媼自相依。',24,'全唐诗/poet.song.127000.json','["茅茨西日暖，翁媼自相依。", "不識鴛鴦意，雙雙作伴飛。"]'),
('50faf881-ec2c-4215-b467-c2a15111abb5','夜半','姜特立','宋','宋诗','song-poetry','','[]','夜半霜鋪瓦，渾如水潑衾。',24,'全唐诗/poet.song.127000.json','["夜半霜鋪瓦，渾如水潑衾。", "爐紅朝易起，衣重老難任。"]'),
('dafae85d-a77c-45d9-8e12-a3ca45a30ebf','芡實','姜特立','宋','宋诗','song-poetry','','[]','芡實徧芳塘，明珠截錦囊。',24,'全唐诗/poet.song.127000.json','["芡實徧芳塘，明珠截錦囊。", "風流熏麝氣，包裹借荷香。"]'),
('9209a2cd-7724-42e8-8373-362f8f816c8c','里中驅儺','姜特立','宋','宋诗','song-poetry','','[]','大儺存古禮，彩髮映雕冠。',24,'全唐诗/poet.song.127000.json','["大儺存古禮，彩髮映雕冠。", "如今身老大，不似小時看。"]'),
('491eb1e6-f950-4508-b588-efc516cd5f3b','余曩官都下有一鐵缾甚古貯湯宿火以供朝謁歸來置床下有年矣偶一日得之因磨洗以備飲酒不時之需','姜特立','宋','宋诗','song-poetry','','[]','冶鑄求來不記年，貯湯宿火早朝天。',32,'全唐诗/poet.song.127000.json','["冶鑄求來不記年，貯湯宿火早朝天。", "如今冷落渾無用，且與鴟夷伴醉眠。"]'),
('d44dc412-b798-43aa-8970-06df47142767','感歎','姜特立','宋','宋诗','song-poetry','','[]','日月爭其所，昏曉成古今。',48,'全唐诗/poet.song.127000.json','["日月爭其所，昏曉成古今。", "桑榆能幾何，可但惜分陰。", "有花須共賞，有酒須頻斟。", "追念舊交遊，半卧青楓林。"]'),
('080df12d-dcb4-4840-9eb3-fbd28a8f8f89','偶題','姜特立','宋','宋诗','song-poetry','','[]','平生不作守錢虜，萬事隨緣了即休。',32,'全唐诗/poet.song.127000.json','["平生不作守錢虜，萬事隨緣了即休。", "收拾詩篇閒事業，追隨歌酒老風流。"]'),
('bfd5885a-84b7-467a-b8cb-5295759feca0','立春作時七十八','姜特立','宋','宋诗','song-poetry','','[]','老覺冬衣重，慵便春服輕。',48,'全唐诗/poet.song.127000.json','["老覺冬衣重，慵便春服輕。", "衰翁脚力弱，拄杖乃能行。", "八秩今時少，何人福壽并。", "仰惟文與呂，盛德兩耆英。"]'),
('87840338-4660-424c-b185-8787c9fb0685','送升之南宮','姜特立','宋','宋诗','song-poetry','','[]','銀袍金带吾家有，黄榜青衫未有人。',32,'全唐诗/poet.song.127000.json','["銀袍金带吾家有，黄榜青衫未有人。", "此去須君立門戶，桂林先折一枝春。"]'),
('e47f7788-5880-46b2-a671-92b317c990fb','思親','姜特立','宋','宋诗','song-poetry','','[]','富貴來時不見親，永懷恩德倍酸辛。',32,'全唐诗/poet.song.127000.json','["富貴來時不見親，永懷恩德倍酸辛。", "如今有祿肥妻子，誰念孀孤泉下人。"]'),
('18e6e5de-d62a-4f32-b8a7-5a434420a22d','呈府判兄','姜特立','宋','宋诗','song-poetry','','[]','端憂傷逝者，花事欲如何。',48,'全唐诗/poet.song.127000.json','["端憂傷逝者，花事欲如何。", "春色愁邊少，悲悰酒後多。", "溪桃方著臉，區木漸成窠。", "擬作開眉計，何當掃障魔。"]'),
('fb231110-3231-4dc6-8157-dca96c696436','元宵小飲遊人填塞殊可厭','姜特立','宋','宋诗','song-poetry','','[]','一燈何似千燈，千燈爭如一月。',70,'全唐诗/poet.song.127000.json','["一燈何似千燈，千燈爭如一月。", "雖云屋下熒煌，不若空中皎潔。", "笙歌萬井喧譁，車馬九衢填咽。", "老子靜對嬋娟，自是一般奇絕。", "混沌燈意略同，矯俗救奢良訣。"]'),
('193bd115-2c45-442a-9026-6b514a390b54','歸括蒼如山堂挈家出宅  其一','姜特立','宋','宋诗','song-poetry','','[]','今日如山堂，携家如逆旅。',24,'全唐诗/poet.song.127000.json','["今日如山堂，携家如逆旅。", "爲誰十日留，南山看煙雨。"]'),
('f6756052-f9e2-4595-8739-9b070a71fef8','歸括蒼如山堂挈家出宅  其二','姜特立','宋','宋诗','song-poetry','','[]','且唱還鄉曲，初非衣錦衣。',24,'全唐诗/poet.song.127000.json','["且唱還鄉曲，初非衣錦衣。", "不須華表望，丁令此時歸。"]'),
('54a8ab90-555e-4162-98d3-6af099afd383','贈葉樞相','姜特立','宋','宋诗','song-poetry','','[]','一別鄉閭五十秋，今朝作意省松楸。',64,'全唐诗/poet.song.127000.json','["一別鄉閭五十秋，今朝作意省松楸。", "山川良是人民改，故舊無多歲月流。", "不學錢侯誇駟馬，聊同范子泛扁舟。", "風流二老今重會，把酒慇懃說舊遊。"]'),
('7440684e-9475-484e-823d-29a35687899d','歸鄉二首  其一','姜特立','宋','宋诗','song-poetry','','[]','憶昔東坡老，曾吟陌上花。',24,'全唐诗/poet.song.127000.json','["憶昔東坡老，曾吟陌上花。", "我今歸故里，卉木正光華。"]'),
('054898b9-551f-49ed-ab91-766a38a9b68b','歸鄉二首  其二','姜特立','宋','宋诗','song-poetry','','[]','五十餘年別故山，今朝底事挈家還。',32,'全唐诗/poet.song.127000.json','["五十餘年別故山，今朝底事挈家還。", "老來報本思宗祖，不爲豪夸里巷間。"]'),
('d4ee592e-8d58-4f42-a7c1-7fcf9d68ddbe','小池觀魚','姜特立','宋','宋诗','song-poetry','','[]','戲投餠餌方塘上，無限魚兒翻翠浪。',32,'全唐诗/poet.song.127000.json','["戲投餠餌方塘上，無限魚兒翻翠浪。", "向來瓠瑟聽遺音，今日梅山識清唱。"]'),
('2c48f03c-47ca-4f70-95b4-bb60f0fcdbcf','過馮公嶺','姜特立','宋','宋诗','song-poetry','','[]','盤嶠中間十里灣，遶山如躡翠連環。',32,'全唐诗/poet.song.127000.json','["盤嶠中間十里灣，遶山如躡翠連環。", "兩岐盡處忽回首，只在尋常一望間。"]'),
('417d5476-1f39-4be6-b3cb-68b8c0d29ebc','嘉泰二年得京祠','姜特立','宋','宋诗','song-poetry','','[]','八十衰翁灰冷時，君恩忽許奉京祠。',32,'全唐诗/poet.song.127000.json','["八十衰翁灰冷時，君恩忽許奉京祠。", "夜行不已非吾事，歸日磻溪理釣絲。"]'),
('3d5e9963-8f47-43e5-a9e6-d2c71d6ebae0','千葉海棠','姜特立','宋','宋诗','song-poetry','','[]','二八女兒初弄容，妝成意態有纖穠。',32,'全唐诗/poet.song.127000.json','["二八女兒初弄容，妝成意態有纖穠。", "點亂胭脂痕片片，潮生醉臉暈重重。"]'),
('99d85cf0-19e0-454a-a541-62c48fd039ae','賦括蒼郡齋','姜特立','宋','宋诗','song-poetry','','[]','括蒼雲水窟，刺史神仙宅。',144,'全唐诗/poet.song.127000.json','["括蒼雲水窟，刺史神仙宅。", "窈窕九折通，髣髴三山隔。", "千峯鬰崔嵬，一派繞清激。", "境浄不可唾，崖傾誰敢迫。", "崇桃炫春紅，積李縞夜白。", "樵唱遞往來，漁舠時出沒。", "閒招鸞鳳侶，間訪煙霞客。", "替玉肌花貌，有水光山色。", "使君玩世士，愛奇忘寢食。", "不憂橐無金，自喜足有力。", "欲具航海舟，從公登山屐。", "早晚歸去來，飄然謝朝幘。"]'),
('f21e8392-c070-414c-8400-f57030207d9e','香風樓','姜特立','宋','宋诗','song-poetry','','[]','太乙真人一葉蓮，浮游萬頃思悠然。',32,'全唐诗/poet.song.127000.json','["太乙真人一葉蓮，浮游萬頃思悠然。", "我今不願瀛洲去，願作香風水上仙。"]'),
('a38a0577-7cb1-4298-8cdd-62599dc965cf','遊三巖','姜特立','宋','宋诗','song-poetry','','[]','一見便非凡世界，恍然兜率化成宮。',64,'全唐诗/poet.song.127000.json','["一見便非凡世界，恍然兜率化成宮。", "未分混沌天無巧，已鑿谽谺鬼有功。", "百尺飛泉晴亦雨，四時陰穴夜吹風。", "莫將俗駕污仙境，明日紅塵在眼中。"]'),
('7e67920b-149f-4a95-9da8-4fdeb7eefc77','感興','姜特立','宋','宋诗','song-poetry','','[]','八秩歸鄉井，交遊一二存。',24,'全唐诗/poet.song.127000.json','["八秩歸鄉井，交遊一二存。", "固知年及耄，似覺老而尊。"]'),
('7aee5cfa-1c6b-4e92-97db-2c7224768c3a','和葉樞相送芍藥  其一','姜特立','宋','宋诗','song-poetry','','[]','平生出處半參辰，胸臆今朝獲重陳。',64,'全唐诗/poet.song.127000.json','["平生出處半參辰，胸臆今朝獲重陳。", "二老白頭欣得侶，千枝紅豔欲無春。", "已拚把酒同中聖，况是司花別有神。", "來歲如今好時節，詩翁著句更芳新。"]'),
('89b74381-0e69-4b87-8ba4-a387f689262f','和葉樞相送芍藥  其二','姜特立','宋','宋诗','song-poetry','','[]','暮齡携挈特東歸，紅藥翻階正得時。',32,'全唐诗/poet.song.127000.json','["暮齡携挈特東歸，紅藥翻階正得時。", "不是花容相嫵媚，風流要索兩翁詩。"]'),
('1ddd1fbf-152b-4bb9-9a91-acbcea050807','門前柳','姜特立','宋','宋诗','song-poetry','','[]','一桁門前柳，亭亭翠插空。',48,'全唐诗/poet.song.127000.json','["一桁門前柳，亭亭翠插空。", "悲秋宋玉宅，學舞楚王宮。", "夜映樓臺月，朝牽菱荇風。", "多情二三月，亂絮撲房櫳。"]'),
('2f2aefc3-cc13-442f-860a-b00b1adcad48','苦熱','姜特立','宋','宋诗','song-poetry','','[]','老人氣血少，日夜遭煎煮。',24,'全唐诗/poet.song.127000.json','["老人氣血少，日夜遭煎煮。", "點檢槁形骸，能禁幾寒暑。"]'),
('fb881f97-3c8a-4cc9-a040-939b4701044c','聽箏','姜特立','宋','宋诗','song-poetry','','[]','鶢鶋設鐘鼓，固已非所樂。',48,'全唐诗/poet.song.127000.json','["鶢鶋設鐘鼓，固已非所樂。", "我今對秦箏，聽之亦藐藐。", "老人難遣日，藉此慰牢落。", "此意只自知，勿令兒輩覺。"]'),
('35bb0fc4-dc96-4d3c-a9af-e4fdfb99e5a0','賦蓮城堂','姜特立','宋','宋诗','song-poetry','','[]','此是吾邦別洞天，樓臺高下白雲邊。',64,'全唐诗/poet.song.127000.json','["此是吾邦別洞天，樓臺高下白雲邊。", "鳥聲人語相酬答，山影溪光共接連。", "便欲棄家來學道，不須航海去求仙。", "媿無冰雪清新句，且讀騷經點易編。"]'),
('b0b7870d-4dd4-445e-ac76-1b8de471c4b2','和葉樞密題謝清音道人扇面','姜特立','宋','宋诗','song-poetry','','[]','紛紛朝市利名忙，唯有山林興寄長。',64,'全唐诗/poet.song.127000.json','["紛紛朝市利名忙，唯有山林興寄長。", "樞相好奇聊玩物，道人弄筆欲專房。", "方嫌小景鮫綃窄，忽辱新詩繭紙香。", "潭府炎蒸無著處，聊將三伏助清凉。"]'),
('9996c8ef-ef08-466c-9262-f2f6cae3758b','和葉樞密同游南明','姜特立','宋','宋诗','song-poetry','','[]','出郭眼增明，遐觀酒共傾。',48,'全唐诗/poet.song.127000.json','["出郭眼增明，遐觀酒共傾。", "好風吹暑氣，快雨送雷聲。", "僧磬清敲寂，鶑簧巧弄晴。", "論交方繾綣，奈此別時情。"]'),
('95b293ca-fc73-4b57-8a67-33c4f3827928','和趙釴夫見惠','姜特立','宋','宋诗','song-poetry','','[]','歸來揩眼望南明，山水光中慰此行。',64,'全唐诗/poet.song.127000.json','["歸來揩眼望南明，山水光中慰此行。", "不把篇章供世好，肯將姓字占時名。", "才踈我合回三舍，語妙君能敵七兵。", "自此定交非造次，許陪詩社莫寒盟。"]'),
('69a30ab7-80d5-40bd-bfe2-97169cfaaa50','別樞相','姜特立','宋','宋诗','song-poetry','','[]','未冠雞窗友，于今鶴髮翁。',48,'全唐诗/poet.song.127000.json','["未冠雞窗友，于今鶴髮翁。", "功名各自致，齒髮略相同。", "欲去情懷惡，臨分禮意隆。", "百年纔一瞬，無惜寄詩筒。"]'),
('aac612dc-e6f3-4803-bc9e-2ea60337c716','巖泉別諸弟','姜特立','宋','宋诗','song-poetry','','[]','久矣忘鄉井，歸人問故蹊。',48,'全唐诗/poet.song.127000.json','["久矣忘鄉井，歸人問故蹊。", "無金隨力散，有柱把詩題。", "初見心增喜，臨分意轉迷。", "人生重恩意，去住兩含悽。"]'),
('71a84bd3-7564-429d-ba1b-2b5a7c71f8d1','居室','姜特立','宋','宋诗','song-poetry','','[]','居室要須存野意，不求輪奐炳丹青。',32,'全唐诗/poet.song.127000.json','["居室要須存野意，不求輪奐炳丹青。", "王侯第宅他崇貴，麋鹿山林我性靈。"]'),
('b23e30eb-2fcb-4efe-8389-e293a4de1022','度暑','姜特立','宋','宋诗','song-poetry','','[]','度暑有餘樂，虛堂閒炷香。',60,'全唐诗/poet.song.127000.json','["度暑有餘樂，虛堂閒炷香。", "清風左右至，翠竹兩三行。", "既無衣食憂，更喜壽命長。", "與物雖同流，於世實相忘。", "所以陶徵君，高卧到羲皇。"]'),
('2f091653-233b-4699-be6d-971ed90799f4','贈曾少卿','姜特立','宋','宋诗','song-poetry','','[]','我誦茶山詩，不識茶山面。',72,'全唐诗/poet.song.127000.json','["我誦茶山詩，不識茶山面。", "今朝逢嫡孫，論詩得關鍵。", "李杜不再傳，蘇黄纔一見。", "茶山子有孫，夜光同一串。", "故家妙人物，筆底波瀾健。", "何當直兩鋒，看取空中箭。"]'),
('06394b1b-602b-4d50-b1b5-5f4feb344450','小蠻','姜特立','宋','宋诗','song-poetry','','[]','小蠻方豔色，老傅已華顛。',36,'全唐诗/poet.song.127000.json','["小蠻方豔色，老傅已華顛。", "念彼當春花，能得幾時妍。", "勸君莫留花，花亦悲流年。"]'),
('b3203cad-9249-4e45-873b-6666102707f6','寄齋','姜特立','宋','宋诗','song-poetry','','[]','君齋以寄名，寄齋有何義。',120,'全唐诗/poet.song.127000.json','["君齋以寄名，寄齋有何義。", "豈非異邦人，偶爾寓斯地。", "靜觀浮世間，何物不是寄。", "天地即蘧廬，吾身一郵置。", "百年聊託宿，六鑿共遊戲。", "一朝撒手行，妻子却復棄。", "寶貨不隨身，主人若箇是。", "不如飲無何，日就醉鄉睡。", "四海皆弟兄，何必桑與梓。", "若問吾故家，滕公是同里。"]'),
('b03862b0-465a-423f-9b5a-b015d408c715','積日','姜特立','宋','宋诗','song-poetry','','[]','積日乃成歲，積歲不覺老。',84,'全唐诗/poet.song.127000.json','["積日乃成歲，積歲不覺老。", "始焉泉涓涓，末乃海浩浩。", "少年玩時日，事業良草草。", "况復鈍滯資，謀身苦不早。", "只今在桑榆，風燭那可保。", "譬如秋後花，能得幾時好。", "遇酒且舒眉，前程付蒼昊。"]'),
('a4ab4f1e-0dc2-48c4-b81e-3a6e81c01048','月俸至','姜特立','宋','宋诗','song-poetry','','[]','祿厚君恩重，才踈德性迂。',24,'全唐诗/poet.song.127000.json','["祿厚君恩重，才踈德性迂。", "入門隨手散，不作守錢愚。"]'),
('876a6f2b-16e7-4751-a909-5286cae5e878','和潘德久舍人見惠','姜特立','宋','宋诗','song-poetry','','[]','詩人擁節古來稀，郊島詩窮彼一時。',64,'全唐诗/poet.song.127000.json','["詩人擁節古來稀，郊島詩窮彼一時。", "愛子篇章孤鶴唳，愧予門戶兩狼垂。", "遥知靖節閒栽菊，不見儀休慍拔葵。", "別去脩門莫嗟惋，時來如摘頷邊髭。"]'),
('cd23f682-9afb-4ae1-90f4-de710dcef861','嘉泰壬戌歸省墳墓感仲叔舊所惠詩及延慶堂夢二首  其一','姜特立','宋','宋诗','song-poetry','','[]','吾叔非凡士，從來眼目長。',24,'全唐诗/poet.song.127000.json','["吾叔非凡士，從來眼目長。", "相期在今日，此意最難忘。"]'),
('65be8833-ac78-4daa-bdb1-43a48c14047b','嘉泰壬戌歸省墳墓感仲叔舊所惠詩及延慶堂夢二首  其二','姜特立','宋','宋诗','song-poetry','','[]','延慶堂中夢，人言積善家。',24,'全唐诗/poet.song.127000.json','["延慶堂中夢，人言積善家。", "翠娥環繞句，今日定如何。"]'),
('b775bf4d-7cef-4948-91ce-111135e93454','感戚夫人事','姜特立','宋','宋诗','song-poetry','','[]','女以色而死，士以才而亡。',96,'全唐诗/poet.song.127000.json','["女以色而死，士以才而亡。", "處才不才間，此語最深長。", "我昔愚自信，遭逐方悲傷。", "投迹歸山林，爲樂特未央。", "失馬反爲福，始悟得不償。", "向來尤其人，今乃佩恩光。", "忮心成美意，陷穽爲康莊。", "寄語斯鞅輩，善刀宜早藏。"]'),
('2fa5ffd7-a51a-41d1-b046-7bca224a618a','喜雨寄曾少卿','姜特立','宋','宋诗','song-poetry','','[]','畎畝欲龜坼，好雨忽滂沱。',96,'全唐诗/poet.song.127000.json','["畎畝欲龜坼，好雨忽滂沱。", "豪民不蓄穀，一旱將如何。", "早晚炊香秔，呼奴蒸瓠壺。", "爲我謳一曲，便是擊壤歌。", "皆由使君恩，盛德致時和。", "豈有六七月，溪流揚素波。", "爾民亦何知，飽食輸王租。", "誦我喜雨詩，百世永不磨。"]'),
('ceae7f60-48a2-4ec4-871e-b1471a3ab9f0','漁舍','姜特立','宋','宋诗','song-poetry','','[]','漁舍枕滄灣，如游赤壁間。',48,'全唐诗/poet.song.127000.json','["漁舍枕滄灣，如游赤壁間。", "羨魚雖迹似，匪釣却心閒。", "松古龍千尺，溪清玉一環。", "無人相伴醉，沙觜弄潺湲。"]'),
('d67f457c-1cdd-44e2-8d35-4713f95e9576','得雨乍凉','姜特立','宋','宋诗','song-poetry','','[]','老火忽西流，凉飈應蓐收。',48,'全唐诗/poet.song.127000.json','["老火忽西流，凉飈應蓐收。", "倦懷辭濁暑，爽意入清秋。", "得句新逾潔，炊秔香正浮。", "身閒仍有酒，此外更何求。"]'),
('9c9b2abd-f931-469e-9962-bea06ea9ca32','清閒','姜特立','宋','宋诗','song-poetry','','[]','清閒自是神仙福，不是神仙不得閒。',32,'全唐诗/poet.song.127000.json','["清閒自是神仙福，不是神仙不得閒。", "我雖凡骨居塵世，十有三年守故山。"]'),
('fcc76c4e-8f9f-421e-98ac-993fec8ec4d8','魚燕','姜特立','宋','宋诗','song-poetry','','[]','拍岸魚遺子，排簷燕引雛。',24,'全唐诗/poet.song.127000.json','["拍岸魚遺子，排簷燕引雛。", "有生俱有欲，情愛豈其無。"]'),
('919699f7-264b-4738-b0cb-e6684c4a35dc','暮年即事','姜特立','宋','宋诗','song-poetry','','[]','八十衰翁如小兒，愛餐梨栗作兒嬉。',64,'全唐诗/poet.song.127000.json','["八十衰翁如小兒，愛餐梨栗作兒嬉。", "有時淡飲三盃酒，無事閒吟兩首詩。", "還丹却老吾不知，頭童齒豁一聽之。", "但願造物相扶持，壽考或可登期頤。"]'),
('6eb76d62-a5a4-4d81-a2d1-8f9e1522092c','賀葉樞密得孫','姜特立','宋','宋诗','song-poetry','','[]','鸞鳳難爲種，尋常羽族繁。',48,'全唐诗/poet.song.127000.json','["鸞鳳難爲種，尋常羽族繁。", "共期公入相，又見子生孫。", "衣鉢傳親手，箕裘付後昆。", "韋平今遠矣，衮衮屬高門。"]'),
('55895759-41b8-4df4-bb64-0af11fde3541','秋晴得雨','姜特立','宋','宋诗','song-poetry','','[]','片雲飛白雨，萬壑變清秋。',48,'全唐诗/poet.song.127000.json','["片雲飛白雨，萬壑變清秋。", "甕螘思新酒，河魚失舊愁。", "嫩凉生枕簟，爽氣入梧楸。", "喜得平安報，天如爲我謀。"]'),
('59b45052-aae7-4079-86cc-5bf5b3ea335f','子美','姜特立','宋','宋诗','song-poetry','','[]','倉卒朝行在，間關到蜀都。',48,'全唐诗/poet.song.127000.json','["倉卒朝行在，間關到蜀都。", "維舟錦江上，卜宅少城隅。", "藥市橋春過，江村酒夜沽。", "風騷天不靳，故遣走荆吳。"]'),
('e922ddf0-cc9a-4777-a1cf-b818ffc0bbeb','感物','姜特立','宋','宋诗','song-poetry','','[]','四時有代謝，卉物互相踰。',96,'全唐诗/poet.song.127000.json','["四時有代謝，卉物互相踰。", "紅者方蕊萼，白者已芬敷。", "人生一氣中，不出造化爐。", "乘除無了時，逝者如斯夫。", "願作澗松老，莫作朝菌枯。", "壽夭又在天，顔跖歸一途。", "爲顔不爲跖，趣向各異殊。", "已矣勿復言，有酒且驩娛。"]'),
('3b02752e-faf9-4aad-ae3a-e2927dddd18e','送酒劉公達','姜特立','宋','宋诗','song-poetry','','[]','詩翁詩膽如酒膽，底事豪詩不豪酒。',32,'全唐诗/poet.song.127000.json','["詩翁詩膽如酒膽，底事豪詩不豪酒。", "麴生聊遣伴清尊，會有醉吟三百首。"]'),
('2e26860b-6307-4f57-b91e-5b8728e7c714','送光孫崇元讀書','姜特立','宋','宋诗','song-poetry','','[]','吾兒毛骨已森然，會見排風上紫煙。',64,'全唐诗/poet.song.127000.json','["吾兒毛骨已森然，會見排風上紫煙。", "但把文章博科第，便成陸地作神仙。", "胸中滔裕書多讀，筆下縱橫業要專。", "卜者相期非止此，後生進學在丁年。"]'),
('f79fef68-efa6-4b04-8331-71b07c46d262','水窠贈王元聘','姜特立','宋','宋诗','song-poetry','','[]','對此一拳石，便有滄洲趣。',48,'全唐诗/poet.song.127000.json','["對此一拳石，便有滄洲趣。", "可笑祖龍癡，轍環山海路。", "贏得鮑魚腥，屬車無覓處。", "何如蓬蓽人，低頭簷下住。"]'),
('48edc4fc-8b2d-427f-80db-1bb0bb2b2633','看花','姜特立','宋','宋诗','song-poetry','','[]','是花皆有態，品格不須論。',48,'全唐诗/poet.song.127000.json','["是花皆有態，品格不須論。", "方其得意時，掀舞春風前。", "正如東西施，彼此兩爭妍。", "有萬吹不同，各自矜其天。"]'),
('905312b9-8232-4546-832e-6f379c3caea2','喜歲豐','姜特立','宋','宋诗','song-poetry','','[]','六月禾將槁，天公一雨蘇。',48,'全唐诗/poet.song.127000.json','["六月禾將槁，天公一雨蘇。", "旱時苗化草，稔後米如珠。", "食足安田里，年饑死路衢。", "豐凶才反手，捫腹媿微軀。"]'),
('c077f317-c945-4359-879e-59c18fd96b46','詩人','姜特立','宋','宋诗','song-poetry','','[]','自古詩人多坎壈，早達唯有蘇長公。',96,'全唐诗/poet.song.127000.json','["自古詩人多坎壈，早達唯有蘇長公。", "流離嶺外七年謫，受盡人間半世窮。", "我方六十遇明主，前此獨卧空山中。", "豈唯食粥動經月，門外往往羅蒿蓬。", "嗚呼詩人天愛惜，不與富貴唯窮空。", "彼蒼於我亦厚矣，但畀明月和清風。"]'),
('dce98c3a-c11a-4ae4-a866-df414206d874','看詩卷','姜特立','宋','宋诗','song-poetry','','[]','蘇黄自是今時友，李杜還爲異代豪。',32,'全唐诗/poet.song.127000.json','["蘇黄自是今時友，李杜還爲異代豪。", "八十衰翁無老伴，唯渠終日話風騷。"]'),
('5a81e16a-229f-4b77-9be3-6cdef0ffc972','東坡','姜特立','宋','宋诗','song-poetry','','[]','文章聲價有東坡，歲晚親逢春夢婆。',52,'全唐诗/poet.song.127000.json','["文章聲價有東坡，歲晚親逢春夢婆。", "一聞千悟無餘事，背負大瓢還唱歌。", "惜哉龍眠不好事，不爲寫作東坡海外郊行圖。"]'),
('fc899cbf-0a0d-48b8-91be-f43d29cf6685','野步','姜特立','宋','宋诗','song-poetry','','[]','晚來行野色，晴意滿江山。',48,'全唐诗/poet.song.127000.json','["晚來行野色，晴意滿江山。", "舊得貧中樂，今於老後閒。", "淵明五柳下，顔子一瓢間。", "此道如能會，孤標不可攀。"]'),
('35253052-a1c0-4a93-ba1a-2411d8a8ec93','朝雲','姜特立','宋','宋诗','song-poetry','','[]','東坡真天人，萬事早超悟。',120,'全唐诗/poet.song.127000.json','["東坡真天人，萬事早超悟。", "生死固了然，刀鋸不足怖。", "方其謫嶺海，負瓢歌道路。", "此已遺形骸，死埋隨到處。", "朝雲爾何人，從公不忍去。", "萬里煙瘴深，此豈有羨慕。", "當時士大夫，反眼相背負。", "孰料禍患中，義行唯妾婦。", "懿哉配坡公，清名照縑素。", "惠州松樹林，不是小蠻墓。"]'),
('6e83a2b6-a59d-4050-8c6a-42a79bf742ba','詩人有至樂','姜特立','宋','宋诗','song-poetry','','[]','詩人有至樂，俗士不知味。',72,'全唐诗/poet.song.127000.json','["詩人有至樂，俗士不知味。", "可以安賤貧，可以輕富貴。", "可以履憂患，可以散淹滯。", "如彼逐臭夫，終日鮑魚肆。", "方其樂其樂，蛭蛆甘所嗜。", "天特私吾徒，慎勿洩其秘。"]'),
('1a30e375-c835-4c7a-a817-441c06d2eeef','雨中巖桂','姜特立','宋','宋诗','song-poetry','','[]','社後十日雨，壞却山桂花。',48,'全唐诗/poet.song.127000.json','["社後十日雨，壞却山桂花。", "不見日車行，但見雨脚斜。", "悶坐室何有，辭眠情不佳。", "安得萬里風，浩蕩吹晴霞。"]'),
('bf7979de-9e0e-43ff-a160-0a40d0aa7263','飯間戲作','姜特立','宋','宋诗','song-poetry','','[]','平生無事業，只是養此腹。',48,'全唐诗/poet.song.127000.json','["平生無事業，只是養此腹。", "雖曰負將軍，念爾相隨逐。", "一朝我若行，枵然入空木。", "問爾將何之，無功難受祿。"]'),
('5ea0ca94-ab1a-4657-9a41-5e2fb39a20d4','心迹','姜特立','宋','宋诗','song-poetry','','[]','心迹清虛絕點塵，更無俗慮得相親。',32,'全唐诗/poet.song.127000.json','["心迹清虛絕點塵，更無俗慮得相親。", "可憐一片浮雲性，付與逍遥自在人。"]'),
('85a39f50-0a55-4210-80b6-5f769dd652ff','秋夜月','姜特立','宋','宋诗','song-poetry','','[]','新月秀彎彎，高懸碧落間。',24,'全唐诗/poet.song.127000.json','["新月秀彎彎，高懸碧落間。", "何當依玉戶，瀟灑看江山。"]'),
('85d832ab-249b-4243-9d13-c293da254a3c','招客賞菊','姜特立','宋','宋诗','song-poetry','','[]','今年月有閏，菊花開較遲。',72,'全唐诗/poet.song.127000.json','["今年月有閏，菊花開較遲。", "明年無贏縮，花開當及時。", "有花與無花，摘蕊泛酒巵。", "况是好時節，風日生光輝。", "但願身老健，長與花爲期。", "猶勝陶徵君，無酒空賦詩。"]'),
('44bed2f2-cb83-45a3-b6a1-fbd02368497f','火閤創壁厨','姜特立','宋','宋诗','song-poetry','','[]','壁厨殊易成，製度亦苟簡。',72,'全唐诗/poet.song.127000.json','["壁厨殊易成，製度亦苟簡。", "二邊各一柱，四齒橫兩板。", "重重疊書冊，造次可抽揀。", "猶勝堆案頭，兒女恣翻混。", "鄴侯懸牙籤，况復余性嬾。", "聊欲備闕遺，時時遮老眼。"]'),
('823c5bfb-65c2-4cb9-8fa4-7f0771cdd950','余有足疾因感柳子厚跂烏篇','姜特立','宋','宋诗','song-poetry','','[]','跂烏肖翹叢薄間，低頭塌翅人所憐。',32,'全唐诗/poet.song.127000.json','["跂烏肖翹叢薄間，低頭塌翅人所憐。", "既無三足相疑妬，恐可夤緣到日邊。"]'),
('d84f9a0d-f7f5-4aac-94f0-13c6947d8453','拒霜盛開','姜特立','宋','宋诗','song-poetry','','[]','拒霜秋後散紅葩，賸有風光到我家。',32,'全唐诗/poet.song.127000.json','["拒霜秋後散紅葩，賸有風光到我家。", "堤上晚來相照耀，分明一片赤城霞。"]'),
('abc884d6-46fe-4d68-8864-e5f1735169ae','王元聘惠石菖蒲','姜特立','宋','宋诗','song-poetry','','[]','靜坐對珍叢，人疑道氣充。',48,'全唐诗/poet.song.127000.json','["靜坐對珍叢，人疑道氣充。", "軒裳路益遠，巖壑意潜通。", "石自鎪鎸巧，苗因灌溉功。", "暮年無嗜好，所向略相同。"]'),
('f1c716e6-e803-4c35-8d81-59593546e5c0','初寒','姜特立','宋','宋诗','song-poetry','','[]','露冷天寒欲隕霜，夜眠輾轉怯更長。',32,'全唐诗/poet.song.127000.json','["露冷天寒欲隕霜，夜眠輾轉怯更長。", "衰翁枕上閒尋句，風入家林月到床。"]'),
('483b176e-c74b-4491-bc13-449f3bf21299','移菊','姜特立','宋','宋诗','song-poetry','','[]','旋移菊本對茲辰，汲灑清泉浥細塵。',32,'全唐诗/poet.song.127000.json','["旋移菊本對茲辰，汲灑清泉浥細塵。", "底事今猶這箇在，向來曾是惜花人。"]'),
('7c088b53-87f0-41d4-9403-ffc5f7f5029e','大笑菊','姜特立','宋','宋诗','song-poetry','','[]','玉瓣金心磊落花，天姿高灑出常葩。',32,'全唐诗/poet.song.127000.json','["玉瓣金心磊落花，天姿高灑出常葩。", "標名大笑緣何事，開口相逢有幾家。"]'),
('e60b57fd-44cd-4fe4-961b-576d27b91ba8','學道','姜特立','宋','宋诗','song-poetry','','[]','學道不須奇，無爲勝有爲。',48,'全唐诗/poet.song.127000.json','["學道不須奇，無爲勝有爲。", "氣平無間斷，心靜自清夷。", "意釣非關餌，行歌不爲詩。", "隨緣皆自在，何患不期頤。"]'),
('cf38fd45-7ae8-4b4c-b479-123cb5fb1524','山居二首  其一','姜特立','宋','宋诗','song-poetry','','[]','山居少交遊，在家仍嬾出。',48,'全唐诗/poet.song.127000.json','["山居少交遊，在家仍嬾出。", "忽得佳友生，開懷可銷日。", "盃盤隨所有，新故皆如一。", "客醉不肯留，我懽終未畢。"]'),
('278217b9-7312-43ce-9970-05bb19edb420','山居二首  其二','姜特立','宋','宋诗','song-poetry','','[]','吾雖享厚祿，自是一書生。',48,'全唐诗/poet.song.127000.json','["吾雖享厚祿，自是一書生。", "炙背隨日車，噓酒依瓶笙。", "教兒讀古書，課僕蒔春榮。", "野意自足樂，澹然違世情。"]'),
('4fed6c82-7502-4b49-9118-22e5655ea2ea','偶題','姜特立','宋','宋诗','song-poetry','','[]','平生踈散性，萬事皆真率。',48,'全唐诗/poet.song.127000.json','["平生踈散性，萬事皆真率。", "唯於五字城，如用蕭何律。", "爲官既無稱，治生亦無術。", "濩落每如斯，一長何足述。"]'),
('6835ea0d-603c-4926-b4e2-7416b059fbc5','晨起信筆','姜特立','宋','宋诗','song-poetry','','[]','老翁夜不寐，最愛晨起早。',168,'全唐诗/poet.song.127000.json','["老翁夜不寐，最愛晨起早。", "既欣鄰雞鳴，更喜林烏噪。", "紅日忽上窗，亟呼具衣襖。", "下床一爐火，便覺春浩浩。", "須臾盥洗罷，覺我神氣好。", "鬚眉白如銀，大似商山皓。", "因思履道賢，六十未爲老。", "本朝六君子，二張同一趙。", "陳杜與鄭公，富貴俱壽考。", "嗟我亦何人，八十明年到。", "不敢儗前賢，後來何足道。", "糞丸誇隋珠，但可付一笑。", "耳目幸聰明，時時吟續藁。", "金釵雖零落，盃酒不草草。"]'),
('09b7656b-873a-464f-b6a6-24b770f3b690','余無常産癸亥歲方舍穡事','姜特立','宋','宋诗','song-poetry','','[]','往歲事耕稼，正以飯不足。',48,'全唐诗/poet.song.127000.json','["往歲事耕稼，正以飯不足。", "今年不服田，賸有代耕祿。", "種瓜與蓺蔬，未免課童僕。", "四體不復勤，有愧前脩躅。"]'),
('22781d3a-9842-4b61-84dc-58b339752f60','和樂天爲張建封侍兒盼盼作仍繼五篇  其一','姜特立','宋','宋诗','song-poetry','','[]','黄金不惜買蛾眉，揀得如花四五枝。',32,'全唐诗/poet.song.127000.json','["黄金不惜買蛾眉，揀得如花四五枝。", "撒手行時無罣礙，更無一物可相隨。"]'),
('10ecde1c-e498-4d7d-848b-6e1c397b7955','和樂天爲張建封侍兒盼盼作仍繼五篇  其二','姜特立','宋','宋诗','song-poetry','','[]','黄金不惜買蛾眉，揀得如花四五枝。',32,'全唐诗/poet.song.127000.json','["黄金不惜買蛾眉，揀得如花四五枝。", "遇有酒時須飲酒，得吟詩處且吟詩。"]'),
('e783240f-4b12-4b28-a654-24cc88625e9a','和樂天爲張建封侍兒盼盼作仍繼五篇  其三','姜特立','宋','宋诗','song-poetry','','[]','黄金不惜買蛾眉，揀得如花四五枝。',32,'全唐诗/poet.song.127000.json','["黄金不惜買蛾眉，揀得如花四五枝。", "日月其除歲云暮，詩人此意報君知。"]'),
('4282509d-a1eb-4197-8a25-93526b1c7b1e','和樂天爲張建封侍兒盼盼作仍繼五篇  其四','姜特立','宋','宋诗','song-poetry','','[]','黄金不惜買蛾眉，揀得如花四五枝。',32,'全唐诗/poet.song.127000.json','["黄金不惜買蛾眉，揀得如花四五枝。", "池塹臺傾何足怪，雍門彈處不須悲。"]'),
('14cf5693-b604-41a7-aa71-b2d673c522ce','和樂天爲張建封侍兒盼盼作仍繼五篇  其五','姜特立','宋','宋诗','song-poetry','','[]','黄金不惜買蛾眉，揀得如花四五枝。',32,'全唐诗/poet.song.127000.json','["黄金不惜買蛾眉，揀得如花四五枝。", "可笑曹瞞空狡獪，西陵作伎一何癡。"]'),
('826a60b9-6b1e-4922-a783-f4e08dd49991','對芳樽廣韋蘇州詩作','姜特立','宋','宋诗','song-poetry','','[]','對芳樽，老來萬事不足論。',40,'全唐诗/poet.song.127000.json','["對芳樽，老來萬事不足論。", "朱唇皓腕年少伴，青山白雲居士鄰。", "對芳樽，老來萬事不足論。"]'),
('d1a33d4e-6f4c-4cc8-a92a-42d13a1bc219','菜羹','姜特立','宋','宋诗','song-poetry','','[]','凡物貴適口，何必費橐金。',60,'全唐诗/poet.song.127000.json','["凡物貴適口，何必費橐金。", "蓴羹與菰菜，千里起歸心。", "野人美芹獻，重意有所臨。", "淡薄斯近道，厚味腊毒深。", "彼哉膏粱徒，藜藿非知音。"]'),
('45f30cbb-25cc-480f-9d8d-0e60b953d4eb','次韻湯寬仲惠四季木犀清烈妙甚','姜特立','宋','宋诗','song-poetry','','[]','一歲常隨斗柄回，四時各占一時開。',32,'全唐诗/poet.song.127000.json','["一歲常隨斗柄回，四時各占一時開。", "仙娥別有栽培術，長與山翁薦壽杯。"]'),
('aeeb6b9d-6200-4c8e-9c66-8e3d4be2dde6','再賦漁舍','姜特立','宋','宋诗','song-poetry','','[]','皆言漁者樂，不知漁者憂。',120,'全唐诗/poet.song.127000.json','["皆言漁者樂，不知漁者憂。", "方其未得魚，蓑雨立寒流。", "正可入圖畫，屋壁供王侯。", "呂尚與子陵，工釣漢與周。", "初不事鈎餌，終日心優游。", "我今築斯舍，發興在滄洲。", "范子既伯越，去泛湖海舟。", "季鷹思吳中，不爲鱸魚秋。", "所以數君子，聲名天壤侔。", "我非真漁人，一醉萬事休。"]'),
('f8019774-2816-4508-a19c-637e0245458e','觀種麥','姜特立','宋','宋诗','song-poetry','','[]','麥隴收寒煙，曉鋤穿日影。',48,'全唐诗/poet.song.127000.json','["麥隴收寒煙，曉鋤穿日影。", "什伍每爲朋，坎種分畦町。", "稟氣該四時，收成近炎景。", "灌溉須春前，明年足湯餠。"]'),
('9edc000a-b53c-43fd-944a-f32c837efcb7','閒吟','姜特立','宋','宋诗','song-poetry','','[]','千首詩輕萬戶侯，富如猗頓亦何求。',32,'全唐诗/poet.song.127000.json','["千首詩輕萬戶侯，富如猗頓亦何求。", "六義中間有至樂，不須苦作楚人騷。"]'),
('d9be4547-70e2-4295-beff-63b9917f98fe','雲山','姜特立','宋','宋诗','song-poetry','','[]','茫茫幾雲山，中有萬古人。',48,'全唐诗/poet.song.127000.json','["茫茫幾雲山，中有萬古人。", "人間有生死，出沒如浮雲。", "山雲有銷歇，世人無斷絕。", "所以西方尊，不言生與滅。"]'),
('5c573e2e-08cb-4611-8959-0642a7a00200','喜雨','姜特立','宋','宋诗','song-poetry','','[]','昨宵榾榾車聲喧，人情嗷嗷不得眠。',128,'全唐诗/poet.song.127000.json','["昨宵榾榾車聲喧，人情嗷嗷不得眠。", "今朝一雨忽大足，人聲車聲俱寂然。", "吁嗟血汗滴焦土，寸寸灌田亦良苦。", "天工作用瞬息間，百頃平疇如翠羽。", "須知造物心至公，遠近高下皆一同。", "豈唯吾里俱有歲，一凉到骨恩無窮。", "昊天莫道高難測，試聽神龍驅霹靂。", "爾農一飽不自知，爲爾哦詩歌帝力。"]'),
('3d5e2720-2f17-4fda-8416-b00d13fc441e','大雷雨','姜特立','宋','宋诗','song-poetry','','[]','驅逐風雷撼海潮，迢迢已覺度山椒。',64,'全唐诗/poet.song.127000.json','["驅逐風雷撼海潮，迢迢已覺度山椒。", "金蛇照夜三千尺，銀竹傾雲百萬條。", "起舞不辭巾角墊，捲廊從聽藥囊漂。", "吾家雖乏千倉積，一飯何妨共祝堯。"]'),
('9655849d-51d3-4589-a589-b88b70fbec8e','送胡守','姜特立','宋','宋诗','song-poetry','','[]','括蒼都誌勒堅珉，賢守推公第一人。',64,'全唐诗/poet.song.127000.json','["括蒼都誌勒堅珉，賢守推公第一人。", "政似龔黄專愷悌，詩如李杜更清新。", "諸司交薦動旒冕，七邑爭留號吏民。", "此去定須登省戶，老成人物表朝紳。"]'),
('858eb55c-b713-4ea5-a7e8-d46d11c1538f','中古','姜特立','宋','宋诗','song-poetry','','[]','中古風俗醇，田野多賢人。',72,'全唐诗/poet.song.127000.json','["中古風俗醇，田野多賢人。", "沮溺識孔丘，漁父辭伍員。", "後世多薄俗，往往妖孽作。", "小則爲勝廣，大則爲莽卓。", "物壞蟲生之，俗壞姦生之。", "古道日已遠，嗚呼其可悲。"]'),
('abef3ba8-a52e-405b-9a65-949207256d9e','樓安撫輓詩','姜特立','宋','宋诗','song-poetry','','[]','花溪溪水出僊源，正對樞臣舊戟門。',64,'全唐诗/poet.song.127000.json','["花溪溪水出僊源，正對樞臣舊戟門。", "聊把一麾隨宦牒，只尋三徑樂丘園。", "傳家遠繼東樓國，好客長開北海尊。", "胸次魁奇無一物，百年厚德畀兒孫。"]'),
('02b78859-1589-42fe-b6d6-5ab63de0388b','偶作','姜特立','宋','宋诗','song-poetry','','[]','酒力欺人老，花容笑客衰。',24,'全唐诗/poet.song.127000.json','["酒力欺人老，花容笑客衰。", "自憐花與酒，終是不相宜。"]'),
('cdd9f133-514d-40f9-9733-e56b4b490a1e','曉晴','姜特立','宋','宋诗','song-poetry','','[]','晴光弄曉色，雲物共昭回。',48,'全唐诗/poet.song.127000.json','["晴光弄曉色，雲物共昭回。", "豈唯山川豁，覺我懷抱開。", "便欲御泠風，飄颻跨蓬萊。", "下視人世間，往往隔囂埃。"]'),
('47befa6c-7ed2-4d38-9bac-fb83ff5e5886','歲稔','姜特立','宋','宋诗','song-poetry','','[]','今歲稔熟收田禾，籠雞擔穀主人家。',32,'全唐诗/poet.song.127000.json','["今歲稔熟收田禾，籠雞擔穀主人家。", "農人時節一醉飽，擨𢶖起舞相喧譁。"]'),
('cc415d5c-a723-4f28-b1b0-00081283d320','雲岑','姜特立','宋','宋诗','song-poetry','','[]','雲岑抱秋陰，水木起夜色。',24,'全唐诗/poet.song.127000.json','["雲岑抱秋陰，水木起夜色。", "原野漸蕭條，田禾捲阡陌。"]'),
('f0e019ad-15c3-4a54-aaaf-0e08154fb1a1','買雞','姜特立','宋','宋诗','song-poetry','','[]','野處買雞專報曉，從今不問夜何其。',32,'全唐诗/poet.song.127000.json','["野處買雞專報曉，從今不問夜何其。", "老夫輾轉苦無寐，恰似度關初聽時。"]'),
('7202669b-230a-4c24-b81d-603697f46a2c','火宅','姜特立','宋','宋诗','song-poetry','','[]','火宅煩惱窟，塵世憂患海。',36,'全唐诗/poet.song.127000.json','["火宅煩惱窟，塵世憂患海。", "唯有顔氏子，簞瓢無吝悔。", "有聖人依歸，其樂故不改。"]'),
('95792328-5267-40be-a271-787a04b56f54','文潞公洛中會四同甲皆丙午七十八予乙巳生與丙午相屬歲數偶同戲作','姜特立','宋','宋诗','song-poetry','','[]','洛中四老會同甲，太歲俱生丙午年。',32,'全唐诗/poet.song.127000.json','["洛中四老會同甲，太歲俱生丙午年。", "我亦聯翩七十八，惜無一客伴華顛。"]'),
('d5cc730c-3a1d-43f3-b058-69b811c1518a','除夜書門牌','姜特立','宋','宋诗','song-poetry','','[]','君恩華老境，慶事接新春。',24,'全唐诗/poet.song.127000.json','["君恩華老境，慶事接新春。", "門戶嚴呵禁，神應護吉人。"]'),
('2cb3c75b-f4eb-469f-b09b-b5e0ada4eca5','洗竹','姜特立','宋','宋诗','song-poetry','','[]','脩篁君子性，枝蔓謾相妨。',24,'全唐诗/poet.song.127000.json','["脩篁君子性，枝蔓謾相妨。", "一自刪除後，侁侁弟子行。"]'),
('51d3a751-adfd-4d92-81c2-4542b0e17f2e','幼子娶婦','姜特立','宋','宋诗','song-poetry','','[]','六十得幼子，薄者以爲嗤。',48,'全唐诗/poet.song.127000.json','["六十得幼子，薄者以爲嗤。", "新婦拜阿翁，茲事在何時。", "翁今已八秩，又見兒婦歸。", "不遠年歲間，更作弄璋詩。"]'),
('09979dd6-6ae7-4eee-b63a-53da15ef1fdb','和曾少卿婺學建稽古閣三賢堂','姜特立','宋','宋诗','song-poetry','','[]','君侯敏手鎮星城，傑閣巍堂指日成。',64,'全唐诗/poet.song.127000.json','["君侯敏手鎮星城，傑閣巍堂指日成。", "經籍大恢新教化，英賢重振舊聲名。", "勢雄三洞雙溪境，義動千秋萬古情。", "一唯家傳人共仰，盍將此道覺諸生。"]'),
('6f2ddbbf-fac0-40ac-a56b-83ab617f7f5b','題南明','姜特立','宋','宋诗','song-poetry','','[]','木末禪扃小徑通，杖藜春晚日沖融。',64,'全唐诗/poet.song.127000.json','["木末禪扃小徑通，杖藜春晚日沖融。", "四圍山色參空遠，一带溪光入座雄。", "俯仰舊遊渾似夢，琢磨新句愧難工。", "浩歌笑指城隅路，和氣分明醉眼中。"]'),
('f24de19d-70a2-4a03-8eed-3417519ef098','偶題','姜特立','宋','宋诗','song-poetry','','[]','富貴來時人已老，光陰去後事如何。',32,'全唐诗/poet.song.127000.json','["富貴來時人已老，光陰去後事如何。", "有時無事閒思省，我獨人間歲月多。"]'),
('4783f899-257d-4c0e-9b0d-8c67dbba8239','說神篇','姜特立','宋','宋诗','song-poetry','','[]','天道若不神，何以驚物而懼人。',47,'全唐诗/poet.song.127000.json','["天道若不神，何以驚物而懼人。", "君道若不神，何以號令鼓萬民。", "故聖人以是而設教，奄有四海，爲天下君。"]'),
('6c6d2fc3-78d2-4095-9e07-96dc6929a95e','晨起','姜特立','宋','宋诗','song-poetry','','[]','晨興一爐火，焰焰如鎔金。',48,'全唐诗/poet.song.127000.json','["晨興一爐火，焰焰如鎔金。", "大明忽東升，陽暉散重陰。", "家人過平劑，有酒向我斟。", "此外更何求，便可老山林。"]'),
('85c2cc7c-87b6-4a83-a90f-058c768002c0','野居','姜特立','宋','宋诗','song-poetry','','[]','野居富薪炭，一煖敵重裘。',48,'全唐诗/poet.song.127000.json','["野居富薪炭，一煖敵重裘。", "雖無四方味，魚鱉亦易求。", "古人愛山林，豈爲口腹謀。", "簞瓢顔不臞，樂道固無憂。"]'),
('81f2108d-a9d2-4267-b673-f83647cb0041','六十遇明主','姜特立','宋','宋诗','song-poetry','','[]','六十遇明主，家空無一廛。',24,'全唐诗/poet.song.127000.json','["六十遇明主，家空無一廛。", "百年今共盡，五福晚兼全。"]'),
('8586d49c-d09b-4f34-8ec2-47cf8dd6f516','劉元亨輓章','姜特立','宋','宋诗','song-poetry','','[]','舉世無非逐臭夫，卜鄰幸喜得文儒。',64,'全唐诗/poet.song.127000.json','["舉世無非逐臭夫，卜鄰幸喜得文儒。", "堵居原憲貧而樂，瓢飲顔回退若愚。", "粗有田園供菽水，更無酒肉混庖厨。", "古來隠士無過此，歎息吾今德已孤。"]'),
('77de888d-7fcc-481a-8391-e3834c0c3c7a','胡郎中輓章','姜特立','宋','宋诗','song-poetry','','[]','雞窗同隸習，鴈塔獨飛翔。',48,'全唐诗/poet.song.127000.json','["雞窗同隸習，鴈塔獨飛翔。", "薦牘盈丹扆，封章列皂囊。", "錦衣榮梓里，符竹耀江鄉。", "三逕方謀適，琴尊忽破亡。"]'),
('2a276bcd-5169-4946-b459-63f7338ecf06','劉巖居士再和去年中秋見貽次韻','姜特立','宋','宋诗','song-poetry','','[]','蒼茫雲海渺無津，玉戶初圓絕點塵。',64,'全唐诗/poet.song.127000.json','["蒼茫雲海渺無津，玉戶初圓絕點塵。", "萬里共欣雲葉浄，一年爭看桂華新。", "狂吟定約六七友，低唱可無三兩人。", "今日公來賡舊曲，梅山驚動主林神。"]'),
('e12595e2-707c-45d5-9916-e8f8e7d360d3','偶賦','姜特立','宋','宋诗','song-poetry','','[]','勇退知幾自古難，人情宦路險於山。',32,'全唐诗/poet.song.127000.json','["勇退知幾自古難，人情宦路險於山。", "勸君休唱眉間曲，放我山中自在閒。"]'),
('284635db-adf4-437c-a260-1d446c19e14b','木芙蓉  其一','姜特立','宋','宋诗','song-poetry','','[]','西風颯颯吹紅蘭，千林摇落無容顔。',64,'全唐诗/poet.song.127000.json','["西風颯颯吹紅蘭，千林摇落無容顔。", "芙蓉花高猩血殷，爍爍對此紅玉盤。", "冰霜駸駸花事寢，坐對此花須痛飲。", "安得蠻戶千張機，爲我織此明霞錦。"]'),
('15aca814-8719-4f27-a18e-7de99d5c23c1','木芙蓉  其二','姜特立','宋','宋诗','song-poetry','','[]','商氣正慘慄，商花忽紅芳。',48,'全唐诗/poet.song.127000.json','["商氣正慘慄，商花忽紅芳。", "有如乍貧婦，猶飾盛時妝。", "衆目驚賞心，所見非所望。", "此後少朱榮，寂寞橘柚黄。"]'),
('c0a22e3d-9148-4482-866f-32923c8bd4ee','木芙蓉  其三','姜特立','宋','宋诗','song-poetry','','[]','美人㛹娟隔秋江，翠羅織裳楸葉光。',32,'全唐诗/poet.song.127000.json','["美人㛹娟隔秋江，翠羅織裳楸葉光。", "醉香艷粉凋斜陽，更使詩人感杏殤。"]'),
('c5ef0139-6576-4175-9d72-6f4e0d898457','二色芙蓉花','姜特立','宋','宋诗','song-poetry','','[]','拒霜一樹碧叢叢，兩色花開迥不同。',32,'全唐诗/poet.song.127000.json','["拒霜一樹碧叢叢，兩色花開迥不同。", "疑是酒邊西子在，半醒半醉立西風。"]'),
('9f480149-4236-457f-8631-4d332ef83b24','紅梅','姜特立','宋','宋诗','song-poetry','','[]','玄冥也自不落莫，探借春風紅樹枝。',64,'全唐诗/poet.song.127000.json','["玄冥也自不落莫，探借春風紅樹枝。", "姑射身全映霞珮，壽陽粧誤點臙脂。", "長於山杏難爲弟，配以江梅合作妃。", "滿面發紅緣底事，如逢宋玉莫相窺。"]'),
('6c29a0f4-2581-4a17-93f4-c5e3eb81960d','蠟梅','姜特立','宋','宋诗','song-poetry','','[]','百花結成蠟，花香蠟不香。',108,'全唐诗/poet.song.127000.json','["百花結成蠟，花香蠟不香。", "如何此枝上，似蠟更芬芳。", "意彼百花魂，結聚無所發。", "英靈爲此花，色香相假合。", "虞姬死爲草，舞動應樂節。", "蜀主化杜鵑，啼染枝頭血。", "輪回有託化，亦聞金仙說。", "花月自有妖，未易以理察。", "烏知此花魂，爲香不爲蠟。"]'),
('35971b17-a1a4-43d2-9208-a1a59e52d8b4','賦潛庵墨梅','姜特立','宋','宋诗','song-poetry','','["\u897f\u6e56"]','季倫珊瑚光奪目，元載胡椒高柱屋。',64,'全唐诗/poet.song.127000.json','["季倫珊瑚光奪目，元載胡椒高柱屋。", "潛庵紙上一枝梅，富比王侯誇不足。", "此花清絕更無倫，和粉磨丹吾所嗔。", "向來華光最入神，幻出西湖煙雨春。"]'),
('45574101-5044-4ef5-8659-d2341befa284','水村','姜特立','宋','宋诗','song-poetry','','[]','一水瀉寒玉，數峰羅翠屏。',24,'全唐诗/poet.song.127000.json','["一水瀉寒玉，數峰羅翠屏。", "漁樵自來往，不悟落丹青。"]'),
('49900c05-89ab-4cf9-9e70-5712f439230d','游鼓山喝水巖','姜特立','宋','宋诗','song-poetry','','[]','昔聞鼓山名，未到鼓山寺。',240,'全唐诗/poet.song.127000.json','["昔聞鼓山名，未到鼓山寺。", "勝游不易得，一失恐難值。", "今朝忽勇猛，便作入山計。", "雖無濟勝具，尚可策疲致。", "松下止呵導，山前屏車騎。", "仰窺白雲峰，俯躡青螺髻。", "半天開佛剎，傑閣照金翠。", "路窮兩崖間，巨石擘元氣。", "何年瀉白虹，一喝回狂勢。", "衝波落山後，餘力泄厚地。", "山靈畏定力，仙鬼吝幽閟。", "至今千仞底，不見波流駛。", "尋師水倒回，卓錫泉湧沸。", "異事驚倒人，此理本無二。", "亭邊數蒼石，刻畫幾大字。", "顧憐身後名，慘戚當時意。", "茫茫千萬古，存滅可勝記。", "灰劫同一盡，要自濟兒戲。", "不如生前酒，對石聊一醉。", "醉到無何鄉，却就僧床睡。"]'),
('602ed85b-3694-45fc-801a-71feac6120b6','雞伏鶩','姜特立','宋','宋诗','song-poetry','','[]','水游陸走不同生，濡足相隨有至情。',32,'全唐诗/poet.song.127000.json','["水游陸走不同生，濡足相隨有至情。", "早晚拍浮春浪去，豈知垂翅到天明。"]'),
('799107e8-878c-48bc-b881-bd8f315e7a69','閩中元夕','姜特立','宋','宋诗','song-poetry','','[]','晴色動春暉，春宵三五時。',48,'全唐诗/poet.song.127000.json','["晴色動春暉，春宵三五時。", "無風開菡萏，有月瑩瑠璃。", "老境逢佳節，他鄉賦小詩。", "囝妻渾勿藥，竈婦亦開眉。"]'),
('ea154dc7-e3d7-420d-9d7b-9767752f1e92','一年佳節惟立春元夕併在一日亦盛事也燈火笙簧處處有之斗城且爾况京都乎追想舊游成一詩聊攄鬰鬰  其一','姜特立','宋','宋诗','song-poetry','','[]','揭地東風作曉晴，峭寒別是一般清。',64,'全唐诗/poet.song.127000.json','["揭地東風作曉晴，峭寒別是一般清。", "五更綵燕歸鈴閣，一夜金蓮撒斗城。", "歲稔歌謠欣越俗，酒闌魂夢遶神京。", "幾多携手天街月，行聽簾幃笑語聲。"]'),
('adb326f4-6489-481d-98ad-55017709a2b8','一年佳節惟立春元夕併在一日亦盛事也燈火笙簧處處有之斗城且爾况京都乎追想舊游成一詩聊攄鬰鬰  其二','姜特立','宋','宋诗','song-poetry','','[]','公堂宴處萬燈明，竈鼓鼕鼕脆管清。',64,'全唐诗/poet.song.127000.json','["公堂宴處萬燈明，竈鼓鼕鼕脆管清。", "莫厭青裙分作隊，那無艷粉笑傾城。", "甘心撾鼓投荒裔，敢望傳柑近上京。", "咫尺賓朋若胡越，語音嘈雜隠雷聲。"]'),
('f1885ffd-0dbc-4c75-9261-8984e01e7167','一年佳節惟立春元夕併在一日亦盛事也燈火笙簧處處有之斗城且爾况京都乎追想舊游成一詩聊攄鬰鬰  其三','姜特立','宋','宋诗','song-poetry','','[]','試聽樓頭報幾更，暗塵漸歇夜方清。',64,'全唐诗/poet.song.127000.json','["試聽樓頭報幾更，暗塵漸歇夜方清。", "但知貪賞千家月，不問滯留三里城。", "延得簪纓還洞府，移將星斗下瑶京。", "道心與俗元無礙，感耳何嫌下俚聲。"]'),
('bb820b9d-9f43-4d54-86f1-23d5fb20ed8a','客中元夕','姜特立','宋','宋诗','song-poetry','','[]','病起春工漸有涯，燒燈時節未還家。',64,'全唐诗/poet.song.127000.json','["病起春工漸有涯，燒燈時節未還家。", "老無筋力追年少，閑有詩篇紀物華。", "風暖欲吹殘雪盡，月明不着片雲遮。", "山中兒女應思我，孤負江梅幾樹花。"]'),
('2250ff05-459f-47e2-aa42-dc33b4154f67','賀兄得節寄詩二首  其一','姜邦佐','宋','宋诗','song-poetry','','[]','千年華表插高空，歸日呼聲徹九重。',32,'全唐诗/poet.song.127000.json','["千年華表插高空，歸日呼聲徹九重。", "城郭人民儼如昨，不應忘却白雲峰。"]'),
('5a507c0a-bd9c-4a82-9d2c-8cabaca2750f','賀兄得節寄詩二首  其二','姜邦佐','宋','宋诗','song-poetry','','[]','老氣崢嶸薄遠空，才名一世許誰重。',32,'全唐诗/poet.song.127000.json','["老氣崢嶸薄遠空，才名一世許誰重。", "已將功業酬身了，却把梅山作隠峰。"]'),
('f7e2539e-4313-4007-9f34-a283f5f6b5a4','賀兄得節二首  其一','姜邦達','宋','宋诗','song-poetry','','[]','難兄位品亞司空，腰下金章指日重。',32,'全唐诗/poet.song.127000.json','["難兄位品亞司空，腰下金章指日重。", "晝錦榮歸何太晚，舉頭何啻仰高峰。"]'),
('1567a3ff-8186-4e1d-9eea-3888bd78601e','賀兄得節二首  其二','姜邦達','宋','宋诗','song-poetry','','[]','夜雨當年舊話空，草廬應記亂山重。',32,'全唐诗/poet.song.127000.json','["夜雨當年舊話空，草廬應記亂山重。", "歸來若上松楸望，前對南屏巾子峰。"]'),
('5ed96b08-9280-4aab-af8e-56c9271846ac','贈姜邦傑','趙釴夫','宋','宋诗','song-poetry','','[]','括蒼水秀更山明，山水鍾情故一行。',64,'全唐诗/poet.song.127000.json','["括蒼水秀更山明，山水鍾情故一行。", "黄卷本無閑事業，白頭却有懶聲名。", "幸逢哲匠求詩範，何用愁城戰酒兵。", "三歎遺音今絕少，先生還須預茲盟。"]'),
('a33bcfd8-3197-4406-9f3e-f9e915c416ff','盤齋','趙釴夫','宋','宋诗','song-poetry','','[]','退之送李愿，歸歟兩山間。',24,'全唐诗/poet.song.127000.json','["退之送李愿，歸歟兩山間。", "而今乃有此，坐能悅吾顔。"]'),
('cd2d89d5-9aff-4285-ba3d-23dd4428bc5a','冰齋','趙釴夫','宋','宋诗','song-poetry','','[]','生於水而寒於水，都在君家燕座中。',32,'全唐诗/poet.song.127000.json','["生於水而寒於水，都在君家燕座中。", "只個從來堪受用，何須更遠挹清風。"]'),
('2a672fbd-ff95-4f58-90b4-071ea9d6030b','舫齋','趙釴夫','宋','宋诗','song-poetry','','[]','浮家泛宅謾區區，一閣安然特迥殊。',32,'全唐诗/poet.song.127000.json','["浮家泛宅謾區區，一閣安然特迥殊。", "題作舫齋還解否，登臨寄傲在江湖。"]'),
('e3265c9c-03ea-4272-8a95-b2696f2c5282','暮村','趙釴夫','宋','宋诗','song-poetry','','[]','孤村烟樹暝黄昏，一簇人家半掩門。',32,'全唐诗/poet.song.127000.json','["孤村烟樹暝黄昏，一簇人家半掩門。", "看盡棲鴉啼噪後，牧童歸去雨聲繁。"]'),
('b2e0047b-d1b3-4996-b155-b4e9d74f13d4','醉和顔美中元夕絕句','趙釴夫','宋','宋诗','song-poetry','','[]','年年人月喜團圓，好在詩邊又酒邊。',32,'全唐诗/poet.song.127000.json','["年年人月喜團圓，好在詩邊又酒邊。", "莫道玄真只漁釣，也隨世俗夜無眠。"]'),
('7d140c82-2bcd-406c-a6bc-db96fe05c36b','句  其一','周必正','宋','宋诗','song-poetry','','[]','八月分圓二十年。',8,'全唐诗/poet.song.127000.json','["八月分圓二十年。"]'),
('97507ae2-55ae-47b3-8e5d-9cf7f985c2d5','句  其二','周必正','宋','宋诗','song-poetry','','[]','摛雲摇碧露繁星。',8,'全唐诗/poet.song.127000.json','["摛雲摇碧露繁星。"]'),
('6414455e-a640-41d0-ae51-93b047429ee2','送新茶李聖喻郎中','陳仲諤','宋','宋诗','song-poetry','','[]','頭綱別樣建溪春，小璧蒼龍浪得名。',64,'全唐诗/poet.song.127000.json','["頭綱別樣建溪春，小璧蒼龍浪得名。", "細瀉谷簾珠顆露，打成寒食杏花餳。", "鷓斑碗面雲縈字，兔褐甌心雪作泓。", "不待清風生兩腋，清風先向舌端生。"]'),
('507cb66b-ccfa-48f4-8b4d-fc5b686e5b55','題玉霄亭','王廉清','宋','宋诗','song-poetry','','[]','憶昔新亭敞玉霄，使君髯舅意飄飄。',64,'全唐诗/poet.song.127000.json','["憶昔新亭敞玉霄，使君髯舅意飄飄。", "春風瀲灧黄金琖，明月參差紫玉簫。", "歌吹舊蹤空草木，風流閑話屬漁樵。", "憑欄無限淒愴意，寂寞寒江落暮潮。"]'),
('605d7f8a-b0ea-4585-bf2c-bdf7ba710a9f','送桑澤還天台','王廉清','宋','宋诗','song-poetry','','[]','桃花風起竹輿寒，寒食天晴石路乾。',64,'全唐诗/poet.song.127000.json','["桃花風起竹輿寒，寒食天晴石路乾。", "正是東君好春色，不妨詞客駐歸鞍。", "金聲賦就方騰踏，鐵硯才高尚考槃。", "如到瓊臺與華頂，爲儂試拂舊題看。"]'),
('d22d8182-1c40-4ea8-9c02-6ae4e0affc04','鼎湖','朱熙載','宋','宋诗','song-poetry','','[]','顒卬萬仞插雲端，極目令人心膽寒。',64,'全唐诗/poet.song.127000.json','["顒卬萬仞插雲端，極目令人心膽寒。", "直上欲衝牛斗暗，彌高方覺太虛寬。", "鬼神捧出擎天柱，海底移來壓地盤。", "仙骨何時跨神馬，御風飛上鼎湖看。"]'),
('7e693079-5a7d-4d5d-b5d4-06045e4f6f9b','題琴堂','連澗','宋','宋诗','song-poetry','','[]','堂下肅且清，琴聲淡而古。',24,'全唐诗/poet.song.127000.json','["堂下肅且清，琴聲淡而古。", "學道則愛人，豈獨聞其語。"]'),
('e537d6c6-3ba2-4de8-9aae-c0ba0c4e67a0','題莞爾堂','連澗','宋','宋诗','song-poetry','','[]','人心深百川，世路險九折。',24,'全唐诗/poet.song.127000.json','["人心深百川，世路險九折。", "牛刀豈非宜，能巧不如拙。"]'),
('a0f54341-d29c-4b6f-b4b2-b330611fa6c3','奉送自强明府之官崑山','曾逮','宋','宋诗','song-poetry','','[]','吳中大縣數崑山，心定庭空亦不難。',64,'全唐诗/poet.song.127000.json','["吳中大縣數崑山，心定庭空亦不難。", "多事要將無事治，萬人須作一人看。", "牀頭有易何妨讀，琴上無弦不用彈。", "况是威名賢太守，吏民誰敢半言謾。"]'),
('046858cb-5867-45e7-843a-407fc6232496','清樾軒','曾逮','宋','宋诗','song-poetry','','[]','開軒在獨園，繞屋得清樾。',96,'全唐诗/poet.song.127000.json','["開軒在獨園，繞屋得清樾。", "不知何年樹，殆爲今日設。", "窗扉落林影，時復亂風月。", "喧聲了不聞，幽弄極可悅。", "玉溪僧所廬，無似許明潔。", "頗疑三昧手，斷取從三浙。", "禪房花木深，此語信佳絕。", "何以落其成，爐烹薦茗雪。"]'),
('d0836c7a-51ad-40d2-bf4a-01af91be3ed8','丈人觀','師渾甫','宋','宋诗','song-poetry','','[]','甯君始學道，敢據五嶽尊。',24,'全唐诗/poet.song.127000.json','["甯君始學道，敢據五嶽尊。", "及爲帝東在，便與天長存。"]'),
('7bda8d6d-0236-42de-9add-e7befdb4f4b5','清都觀','師渾甫','宋','宋诗','song-poetry','','[]','清都視諸方，事力良不齊。',36,'全唐诗/poet.song.127000.json','["清都視諸方，事力良不齊。", "幽賞豈不勝，門當白雲溪。", "劍峯誓罔象，丹井藏虹蜺。"]'),
('2e1f9183-1b46-475f-b22a-52d3a6670c62','句','范中立','宋','宋诗','song-poetry','','[]','我本雲山窟裏人，每憐雪嶺照人清。',16,'全唐诗/poet.song.127000.json','["我本雲山窟裏人，每憐雪嶺照人清。"]'),
('3bb5b452-15f9-4a01-b626-6e91230e011c','登北固樓','釋法平','宋','宋诗','song-poetry','','[]','不負南徐眼，來看北固雲。',48,'全唐诗/poet.song.127000.json','["不負南徐眼，來看北固雲。", "金焦兩山小，吳楚一江分。", "雨氣生蒼壁，秋聲起夕曛。", "半生流落恨，此日重殷勤。"]'),
('8666c11e-99c7-4154-b08f-252fa4bf60fc','絕句','釋法平','宋','宋诗','song-poetry','','[]','春風吹枕小屏寒，客舍無聊夢不安。',32,'全唐诗/poet.song.127000.json','["春風吹枕小屏寒，客舍無聊夢不安。", "花葉暗時人已去，夕陽光滿舊欄干。"]'),
('4dbe6d06-c966-41fd-9756-c0210dd6328a','曉上人還浙東','釋法平','宋','宋诗','song-poetry','','[]','鳥宿柴門靜，更深別意傾。',48,'全唐诗/poet.song.127000.json','["鳥宿柴門靜，更深別意傾。", "孤燈寒有暈，細雨夜無聲。", "渡曉人爭立，潮平櫓亂鳴。", "君今成獨往，老罷苦爲情。"]'),
('38f72de7-b159-462c-a0df-3ade8ff38b1c','句','釋法平','宋','宋诗','song-poetry','','[]','夢魂不入人閒世。',8,'全唐诗/poet.song.127000.json','["夢魂不入人閒世。"]'),
('ba523ace-fe5b-42e2-addb-d13cf270f532','句  其一','陳槐卿','宋','宋诗','song-poetry','','[]','浩歎但傷前輩少，此懷難與俗人論。',16,'全唐诗/poet.song.127000.json','["浩歎但傷前輩少，此懷難與俗人論。"]'),
('420f865b-2a28-461b-9ba3-e4d80b032494','句  其二','陳槐卿','宋','宋诗','song-poetry','','[]','誰能作文冢，反魂爲瘞埋。',12,'全唐诗/poet.song.127000.json','["誰能作文冢，反魂爲瘞埋。"]'),
('eab33ee3-63cd-40ae-a0f6-32682b754800','絕句','盧蹈','宋','宋诗','song-poetry','','[]','客懷耿耿自難寬，老傍京塵更鮮歡。',32,'全唐诗/poet.song.127000.json','["客懷耿耿自難寬，老傍京塵更鮮歡。", "遠夢已回窗不曉，杏花同度五更寒。"]'),
('a7c11088-1432-4e60-b34f-f6369179987e','遇舊有感','潘檉','宋','宋诗','song-poetry','','[]','人間百寒暑，正似須臾期。',72,'全唐诗/poet.song.127000.json','["人間百寒暑，正似須臾期。", "當年同袍子，一見雪滿頤。", "不惟形容變，亦復聲音移。", "坐定問姓字，始省從師時。", "見此發咏嘆，勞生果何爲。", "不如多飲酒，滿腹同鴟夷。"]'),
('5073b5b0-e02e-42f1-a935-359c7ab9a0f0','客舍','潘檉','宋','宋诗','song-poetry','','[]','急雨鳴空壁，輕寒上薄幃。',48,'全唐诗/poet.song.127000.json','["急雨鳴空壁，輕寒上薄幃。", "愁多空被酒，夢短不成歸。", "暗想桃花落，遥憐燕子飛。", "偷兒欺客寢，夜靜卷春衣。"]'),
('65804193-c5b4-4fd1-a49c-df1b2e9dadc2','題釣臺','潘檉','宋','宋诗','song-poetry','','[]','蟬冠未必似羊裘，出處當時已熟籌。',64,'全唐诗/poet.song.127000.json','["蟬冠未必似羊裘，出處當時已熟籌。", "但得諸公依日月，不妨老子卧林丘。", "英雄陳迹千年在，香火空山萬木秋。", "自笑黄塵吹鬢客，愛來祠下繫孤舟。"]'),
('3707bcce-459b-4940-a074-26d2070638d3','送友人游金陵','潘檉','宋','宋诗','song-poetry','','[]','酒盡譚餘意轉新，北風一舸下寒津。',64,'全唐诗/poet.song.127000.json','["酒盡譚餘意轉新，北風一舸下寒津。", "遥知白下登樓處，正欠黄初着句人。", "往事省來多歲月，舊游疎似曉星辰。", "半山斜日荒凉寺，更有殘碑待拂塵。"]'),
('0299f552-9168-48e3-94e9-02c270691936','簡徐判院','潘檉','宋','宋诗','song-poetry','','[]','風誼崢嶸昔未親，正懸一榻待高人。',64,'全唐诗/poet.song.127000.json','["風誼崢嶸昔未親，正懸一榻待高人。", "當年曾接東萊話，今日寧嫌北阮貧。", "世味梅花開野水，詩情馬首沒黄塵。", "何時載酒從君去，靈鷲峯前借早春。"]'),
('6953dc75-5be6-48a3-869c-362d7d3f8352','出郭','潘檉','宋','宋诗','song-poetry','','[]','酤酒三家市，題詩十里塘。',48,'全唐诗/poet.song.127000.json','["酤酒三家市，題詩十里塘。", "薄雲鷗外影，空翠馬頭香。", "出郭知無事，尋僧有底忙。", "終當成野逸，小築近滄浪。"]'),
('225cefc8-e4e5-4b3e-a76a-c1e978b876ee','歲莫懷舊','潘檉','宋','宋诗','song-poetry','','[]','白髮將朱顔，一去幾時返。',48,'全唐诗/poet.song.127000.json','["白髮將朱顔，一去幾時返。", "懷哉不能寐，展轉復展轉。", "雀噪曉窗白，雞鳴芳歲晚。", "梅花眼中春，故情千里遠。"]'),
('a6da6b5b-6f0a-4566-b486-a9a4802e0ff8','還自錢塘道中','潘檉','宋','宋诗','song-poetry','','[]','江上青山落照邊，江頭歸客木蘭船。',32,'全唐诗/poet.song.127000.json','["江上青山落照邊，江頭歸客木蘭船。", "春鷗自共潮回去，一點飛來是柳綿。"]'),
('aa071aa4-f234-45ac-9539-7f155cc6f433','自滁陽回至烏衣鎮','潘檉','宋','宋诗','song-poetry','','[]','行人元不恨長途，下馬旗亭酒可沽。',32,'全唐诗/poet.song.127000.json','["行人元不恨長途，下馬旗亭酒可沽。", "回首瑯琊山不見，西風吹起豆田烏。"]'),
('bb8ed3af-f563-4a3d-b25f-37abe8696993','雁蕩道中','潘檉','宋','宋诗','song-poetry','','[]','千丈巖頭一點紅，春風吹落淺莎中。',32,'全唐诗/poet.song.127000.json','["千丈巖頭一點紅，春風吹落淺莎中。", "山僧倚杖移時去，說似溪邊采藥翁。"]'),
('fe9527be-78f3-4d8e-a0c1-13b2eff1e69c','次韻酬陸放翁','潘檉','宋','宋诗','song-poetry','','[]','瘦藤白苧岸烏紗，隨分酬春領物華。',64,'全唐诗/poet.song.127000.json','["瘦藤白苧岸烏紗，隨分酬春領物華。", "西崦三椽休問舍，南湖一带近栽花。", "眼昏客枕多儲菊，肺渴僧庖屢借茶。", "無事閒門便早睡，清燈喚起爲吟家。"]'),
('3b85a11e-2a7f-4bcf-8427-e479706356e9','霅上簡婁舜章','潘檉','宋','宋诗','song-poetry','','[]','鷄頭旋煮蓮新拗，簇鳳排花鱠更鮮。',32,'全唐诗/poet.song.127000.json','["鷄頭旋煮蓮新拗，簇鳳排花鱠更鮮。", "清夜故人情客到，小船載酒大船邊。"]'),
('940c0f89-0b49-4766-b7e8-4c1839487461','平江道中','潘檉','宋','宋诗','song-poetry','','[]','不載圖書載酒杯，姑蘇臺下小徘徊。',32,'全唐诗/poet.song.127000.json','["不載圖書載酒杯，姑蘇臺下小徘徊。", "東風不識人心老，擺柳吹花一併來。"]'),
('cc9d66bb-bf14-4fc1-ac24-949772f1815a','書姜夔昔遊詩後','潘檉','宋','宋诗','song-poetry','','[]','我行半天下，未能到瀟湘。',48,'全唐诗/poet.song.127000.json','["我行半天下，未能到瀟湘。", "君詩如畫圖，歷歷記所嘗。", "起我遠遊興，其如鬚毛霜。", "何以舒此懷，轉軫移清商。"]'),
('63710516-9620-4f66-bea1-637ff06cf028','贈姜邦傑','潘檉','宋','宋诗','song-poetry','','[]','詩人擁節古來稀，今見梅山際盛時。',64,'全唐诗/poet.song.127000.json','["詩人擁節古來稀，今見梅山際盛時。", "傳世篇章紅錦爛，去天門戶碧油垂。", "風霜氣老同陳柏，亭館花開對蜀葵。", "應記灞橋人寂寞，依然風雪撚霜髭。"]'),
('250d812a-1667-4786-95e1-cc04cae406a5','贈姜白石','潘檉','宋','宋诗','song-poetry','','[]','世間官職似樗蒲，采到枯松亦大夫。',32,'全唐诗/poet.song.127000.json','["世間官職似樗蒲，采到枯松亦大夫。", "白石道人新拜號，斷無繳駮任稱呼。"]'),
('9ae14734-d728-4b54-bfdf-a1d8bfacf169','麗春花','潘檉','宋','宋诗','song-poetry','','[]','梁苑花銷去，黄臺果自薰。',48,'全唐诗/poet.song.127000.json','["梁苑花銷去，黄臺果自薰。", "不同鶑子粟，別是石榴裙。", "婀娜纔勝掌，參差莫夢雲。", "王郎尋水竹，駐履幾殷勤。"]'),
('b03f8c85-16d5-4dcf-99ac-a860ffdc5485','鷺','潘檉','宋','宋诗','song-poetry','','[]','銀潢何限鵲查查，看得橋成度寶車。',32,'全唐诗/poet.song.127000.json','["銀潢何限鵲查查，看得橋成度寶車。", "如許風標無用處，年年分占水葓花。"]'),
('9361250a-e855-4a08-b185-d972b0168886','過虞美人墓','潘檉','宋','宋诗','song-poetry','','[]','樽前一曲奈何歌，千古英雄恨不磨。',64,'全唐诗/poet.song.127000.json','["樽前一曲奈何歌，千古英雄恨不磨。", "女子在軍今莫問，君王愎諫向來多。", "最憐秋雨添狐穴，誰與春醪酹棘窠。", "一朽何須論異域，寄聲青冢太媕婀。"]'),
('cc8a24b9-eeb4-49c8-bd64-2606b446f7ee','上龜山寺','潘檉','宋','宋诗','song-poetry','','[]','菜花開處認遺基，荒屋殘僧未忍離。',64,'全唐诗/poet.song.127000.json','["菜花開處認遺基，荒屋殘僧未忍離。", "寺付丙丁應有數，岸分南北最堪悲。", "金鈴塔上如相語，鐵佛風前亦斂眉。", "野匠不知行客意，競磨濃墨打頑碑。"]'),
('c2abed31-0be1-4b57-b3f4-9611450ad975','句','潘檉','宋','宋诗','song-poetry','','[]','一樹黄葵金盞側，勸人相對醉西風。',16,'全唐诗/poet.song.127000.json','["一樹黄葵金盞側，勸人相對醉西風。"]'),
('2305b29b-67f8-4334-b548-cb7f17e6ea9a','投魏先輩二首  其一','劉應時','宋','宋诗','song-poetry','','[]','長驅决文陣，眇古百戰場。',96,'全唐诗/poet.song.127000.json','["長驅决文陣，眇古百戰場。", "朔風吹梅花，塞日淡無光。", "一將功業成，千屯草木香。", "高談靜寰宇，袖手歸巖廊。", "纍纍腰下印，奕奕眉間黄。", "霖雨四海心，鼎鼐衆口嘗。", "園林多勝事，豈久居其旁。", "縱令猿鶴怨，出處庸何傷。"]'),
('3cfd1a87-00fa-49d4-9046-977a19403764','投魏先輩二首  其二','劉應時','宋','宋诗','song-poetry','','[]','跕跕飛鳶墜，歷歷風瓢聲。',84,'全唐诗/poet.song.127000.json','["跕跕飛鳶墜，歷歷風瓢聲。", "青冥不折桂，澗阿甘采苓。", "踉蹡憶束髮，忽焉迫衰齡。", "嚼蠟心忘味，胡爲羨久生。", "藹藹春空雲，聚散無根蒂。", "縱得屠龍術，孰爲苞桑計。", "稽首問彌伽，輪宇煩舉似。"]'),
('62474e71-0840-4bfa-acf8-04faf7071419','次韻聞人參議來賢巖','劉應時','宋','宋诗','song-poetry','','[]','僊事不可考，靈蹤閟幽微。',108,'全唐诗/poet.song.127000.json','["僊事不可考，靈蹤閟幽微。", "我懷采芝人，寤寐心目怡。", "松陰月華冷，竹露晨光晞。", "福地萃七賢，語屑落霏霏。", "鳳鳴悵莫聞，鶴駕邈難追。", "斲石出秀句，神物尚憑依。", "眷茲玄雲英，挺然柱石姿。", "孰能鞭萬牛，挽此歲寒枝。", "臧孫信有後，深慰魯人思。"]'),
('9a868267-289b-4bd5-8798-d00455d4d522','寄張武子','劉應時','宋','宋诗','song-poetry','','[]','霽月耿東南，流光浄如洗。',144,'全唐诗/poet.song.127000.json','["霽月耿東南，流光浄如洗。", "幽人懷夜光，掬水弄清泚。", "春雲多態度，蒸縕出山麓。", "舒卷無定蹤，形容勞遠目。", "可人古錦囊，多乎斯二者。", "造物發天藏，筆端妙陶冶。", "我具擇法眼，僅得窺一斑。", "恨無餐玉法，謾入藍田山。", "別來歲月換，倏如飛鳥過。", "升沉不足數，交誼果如何。", "夜窗浥露氣，策策秋聲高。", "假寐發永歎，念遠心忉忉。"]'),
('7a0c1415-8b0f-4752-9946-93fb7f6da8d8','辛亥季冬雪中作','劉應時','宋','宋诗','song-poetry','','[]','凍雲橫山風捲沙，槎牙古木鳴寒鴉。',160,'全唐诗/poet.song.127000.json','["凍雲橫山風捲沙，槎牙古木鳴寒鴉。", "長空黯淡常如晚，煙景凄迷亦自佳。", "開窗未及一食頃，剪水俄傾六出花。", "須臾勢欲包天地，粲然枯卉皆璚葩。", "江村景物堪入畫，漁翁蕩槳依枯葭。", "重裘肥馬誰氏子，銀鞍蹀躞山路斜。", "臞儒事業政不惡，擁書至樂何以加。", "團圞共向榾柮火，溫然春意生吾家。", "不能半夜縛元濟，亦懶扁舟泛若耶。", "洒窗入竹有餘韻，頓覺時興清無涯。"]'),
('36cb1311-cdc3-4c86-be83-3f9a21f2bebc','讀放翁劍南集','劉應時','宋','宋诗','song-poetry','','[]','少陵先生赴奉天，烏帽麻鞋見天子。',291,'全唐诗/poet.song.127000.json','["少陵先生赴奉天，烏帽麻鞋見天子。", "乾坤瘡痍塞目慘，人煙蕭瑟胡塵起。", "八月之吉風淒然，北征徒步走三川。", "夜經戰場霜月冷，纍纍白骨生蒼煙。", "五載栖栖客蜀郡，騎馿日候平安信。", "喜聞諸將收山東，拭淚一望長安近。", "瞿唐想見放船時，回首夔府多愁思。", "蜀人至今亦好事，翠珉盛刻草堂詩。", "放翁前身少陵老，胸中如覺天地小。", "平生一飯不忘君，危言曾把姦雄掃。", "周流斯世轍已環，一笑又入劍南山。", "酒杯吸盡錦屏秀，孤劍聲鏘峽水寒。", "萬丈虹霓蟠肺腑，射虎劊鯨時一吐。", "我雖老眼向昏花，夜窗吟哦雜風雨。", "少陵間關兵亂中，放翁遭時樂且豐。", "飽參要具正法眼，切忌錯下將無同。", "茶山夜半傳機要，斷非口耳得其妙。", "君不見塔主不識古雲門，異時衣鉢還渠紹。"]'),
('38f72e80-c08a-4522-9fbe-0239eb0231c4','次韻李仲南木犀','劉應時','宋','宋诗','song-poetry','','[]','幽人何所爲，兀然坐詩窮。',192,'全唐诗/poet.song.127000.json','["幽人何所爲，兀然坐詩窮。", "萬事不復理，吟哦四壁空。", "少皞從西來，天宇淒其風。", "羣芳漸摇落，桂子開牆東。", "寒蟾駕璧月，老翠高菶菶。", "景物爾獨勝，色香誰與同。", "豈藉紅裳女，徒費丹砂工。", "不受黄金恩，桃李誰爭雄。", "風漪卷輕碧，斷霞曳微紅。", "清風襲衣袖，薄采喧兒童。", "王孫亦好事，乘興賞珍叢。", "笑掬黄金蕊，糝綴光玲瓏。", "山村酒可篘，恍如入新豐。", "胡不抱琴去，一飲醉其中。", "露濕月華冷，風約零雨濛。", "靜言參鼻觀，身在廣寒宮。"]'),
('e0d2d7f2-34e7-4d01-8e1f-b6ddafd7e7c7','感事贈周子壽二首  其一','劉應時','宋','宋诗','song-poetry','','[]','毛遂處趙庭，囊穎初不起。',48,'全唐诗/poet.song.127000.json','["毛遂處趙庭，囊穎初不起。", "昭君在匈奴，畫工一夕死。", "取士無取名，名下非真士。", "哀絃有餘音，爲君聊洗耳。"]'),
('2cc39f32-2d82-45c5-8947-48ce27005ce9','感事贈周子壽二首  其二','劉應時','宋','宋诗','song-poetry','','[]','丹丘有鸞鳳，天朝思羽儀。',48,'全唐诗/poet.song.127000.json','["丹丘有鸞鳳，天朝思羽儀。", "祥風挽不前，簫韶將致之。", "我生幸良覿，九苞容一窺。", "矯首望阿閣，自笑槍榆卑。"]'),
('d0bf1da7-afbb-4724-bbe9-72ec96d02131','史太師病愈未果走賀誕辰伊邇作古詩三首寄之  其一','劉應時','宋','宋诗','song-poetry','','["\u897f\u6e56"]','真隠出人間，了此一大事。',48,'全唐诗/poet.song.127000.json','["真隠出人間，了此一大事。", "堯舜既授受，邊障息烽燧。", "袖手辭鈞衡，澹然不色喜。", "高卧北山雲，戲掬西湖水。"]'),
('e8b625b7-873b-4262-951d-9fb5d5e34205','史太師病愈未果走賀誕辰伊邇作古詩三首寄之  其二','劉應時','宋','宋诗','song-poetry','','["\u897f\u6e56"]','真隠愛西湖，居然來卜宅。',48,'全唐诗/poet.song.127000.json','["真隠愛西湖，居然來卜宅。", "春波自溶溶，秋林何策策。", "密邇城市居，夐與囂塵隔。", "開窗放月入，好句來几席。"]'),
('7c5862dc-ddb8-4963-8926-145352300a90','史太師病愈未果走賀誕辰伊邇作古詩三首寄之  其三','劉應時','宋','宋诗','song-poetry','','[]','真隠道骨堅，能禦陰陽寇。',48,'全唐诗/poet.song.127000.json','["真隠道骨堅，能禦陰陽寇。", "不藉盧扁術，自得喬松壽。", "香馥東籬菊，樽餘北海酒。", "裁詩千百篇，年年登衮繡。"]'),
('87bac3a8-5286-4db4-bfa8-7c7b4fdebdf4','讀漢史','劉應時','宋','宋诗','song-poetry','','[]','彭蠡萬頃波，胥江八月濤。',168,'全唐诗/poet.song.127000.json','["彭蠡萬頃波，胥江八月濤。", "所蓄蓋有素，末流故滔滔。", "君子貴養源，毋事駕說勞。", "漢祖過百人，心動疑貫高。", "田孟天下士，其忍負趙敖。", "處死且不難，視身如鴻毛。", "髠鉗吾何畏，義命豈忍逃。", "乘輿忽至止，興運有所遭。", "俛首與之語，議論誠英豪。", "回視漢廷臣，誰能出爾曹。", "即日拜守相，泥塗升九皋。", "大閑不可踰，四維在所操。", "我觀忠義傳，榮如華衮褒。", "置君如奕棋，百歲猶腥臊。"]'),
('15d4720a-4b97-401a-b29b-916dc33174b9','和史魏公酬北山壽老','劉應時','宋','宋诗','song-poetry','','[]','黄髮了國事，歸來雙頰紅。',96,'全唐诗/poet.song.127000.json','["黄髮了國事，歸來雙頰紅。", "園林白日靜，樂事何豐融。", "更許柏庭友，來依春桂叢。", "境勝香山遠，辭高支遁同。", "眷茲達尊地，綽有古人風。", "梅林洗煩暑，霽色摩蒼空。", "煙霞琢秀句，咀嚼味無窮。", "徒紀盛山燕，來羨昌黎公。"]'),
('8ed6810c-cf1d-4793-8271-335435c5fa38','冬夜','劉應時','宋','宋诗','song-poetry','','[]','濁酒有真味，軟火如春和。',48,'全唐诗/poet.song.127000.json','["濁酒有真味，軟火如春和。", "跧居身嬾動，卒歲養微痾。", "世境淡無染，心源湛不波。", "舍爾短檠樂，如此良夜何。"]'),
('02fe0cd5-7c6d-4201-b3c3-402016f858eb','山行','劉應時','宋','宋诗','song-poetry','','[]','春光淡心目，乘興聊躋攀。',48,'全唐诗/poet.song.127000.json','["春光淡心目，乘興聊躋攀。", "頗識造物意，長容我輩閒。", "橫拖拄杖去，笑折梅花還。", "彼哉鐘鼎樂，不在山林間。"]'),
('98b964a2-435d-4242-8b1a-f69d322c204c','幽居','劉應時','宋','宋诗','song-poetry','','[]','煙重柳腰困，雨肥梅臉皴。',48,'全唐诗/poet.song.127000.json','["煙重柳腰困，雨肥梅臉皴。", "夜窗無鎖鑰，晨氣濕衣巾。", "日晏猶便睡，犬鳴知有人。", "西家新釀熟，祀竈請比鄰。"]'),
('521a75ee-5994-40a6-93b9-ee796c1727c6','江村','劉應時','宋','宋诗','song-poetry','','[]','前山疑抹黛，多稼欲成黳。',48,'全唐诗/poet.song.127000.json','["前山疑抹黛，多稼欲成黳。", "水滿蛙登岸，橋危馬蹙蹄。", "風高帆腹壯，雨霽月眉低。", "杖屨投村舍，兒童指舊題。"]'),
('6319b5f5-30ef-46de-8599-e789a5c5b04d','春暮','劉應時','宋','宋诗','song-poetry','','[]','愁裏青春去，年來白髮加。',48,'全唐诗/poet.song.127000.json','["愁裏青春去，年來白髮加。", "細書欺老眼，爛飯愜衰牙。", "寧夢穴中蟻，不疑杯裏蛇。", "南窗時隠几，一縷篆煙斜。"]'),
('53bc7ab8-abb8-4203-bd2e-bccee9db8062','獨飯','劉應時','宋','宋诗','song-poetry','','[]','雲破日將西，村深雞自啼。',48,'全唐诗/poet.song.127000.json','["雲破日將西，村深雞自啼。", "撐船傍林樾，獨飯寓招提。", "山柿淡無味，園蔬嫩可刲。", "滿抄雲子白，心事愧鋤犁。"]'),
('7b8997a4-5681-4718-af53-81b694d45a1f','舟行','劉應時','宋','宋诗','song-poetry','','[]','小艇出前浦，槐陰覆小橋。',48,'全唐诗/poet.song.127000.json','["小艇出前浦，槐陰覆小橋。", "雲垂疑有雨，水穩不通潮。", "山色綠自足，汀花細可描。", "枕書篷底卧，欵乃認歸樵。"]'),
('81a06547-65c4-4dad-946d-6ac569517d29','別李簿','劉應時','宋','宋诗','song-poetry','','[]','執手江亭晚，回驂澗谷深。',48,'全唐诗/poet.song.127000.json','["執手江亭晚，回驂澗谷深。", "碧山銜落照，煙樹鎖愁心。", "空擣黄金泪，誰知白石音。", "殷勤囑魚雁，他日莫浮沉。"]'),
('90503c91-04bc-430f-aa11-a01939b708f7','入夜','劉應時','宋','宋诗','song-poetry','','[]','入夜雨聲細，小窗燈影寒。',48,'全唐诗/poet.song.127000.json','["入夜雨聲細，小窗燈影寒。", "僻居成懶惰，飽食幸平安。", "時事不復問，舊書時一看。", "欣然會心處，香燼一爐殘。"]'),
('1f368b37-6c6a-478f-a956-c46b4edbe099','旅舍','劉應時','宋','宋诗','song-poetry','','[]','草市欲黄昏，吾行恰到門。',48,'全唐诗/poet.song.127000.json','["草市欲黄昏，吾行恰到門。", "僕夫思憩息，燈火喜溫存。", "一夜催花雨，數家臨水村。", "征途雖得句，默坐與誰論。"]'),
('4ecc4ef8-acb7-440e-af50-53778479e9b7','耳聾','劉應時','宋','宋诗','song-poetry','','[]','嘆昔英豪氣，俄成一老翁。',48,'全唐诗/poet.song.127000.json','["嘆昔英豪氣，俄成一老翁。", "近年頭盡白，今日耳猶聾。", "品位無丞職，是非隨曉風。", "難陀能反聽，梢境已消融。"]'),
('cdd8d954-461a-48df-b5d8-74a11efc4e69','生日','劉應時','宋','宋诗','song-poetry','','[]','屏迹衡門下，衰遲愧始生。',48,'全唐诗/poet.song.127000.json','["屏迹衡門下，衰遲愧始生。", "兒曹於此夕，杯酒致歡情。", "來日苦無幾，餘生累漸輕。", "樂親惟養志，外物本非榮。"]'),
('98d5a707-a00a-42df-a41a-319cad4c5014','登樓','劉應時','宋','宋诗','song-poetry','','[]','圖書粲東壁，星斗下西樓。',48,'全唐诗/poet.song.127000.json','["圖書粲東壁，星斗下西樓。", "滿座襟懷爽，一輪風露秋。", "雲山遺古意，江漢洗詩愁。", "更欲騎黄鶴，相隨汗漫遊。"]'),
('b1843b8f-555c-48ce-8b52-a0f67a62544e','山居三首  其一','劉應時','宋','宋诗','song-poetry','','[]','行年當耳順，涉世尚心勞。',48,'全唐诗/poet.song.127000.json','["行年當耳順，涉世尚心勞。", "倦矣歸三徑，皤然愧二毛。", "留詩羞茗供，爲客釀松醪。", "晚照橫籬落，呼兒課楚騷。"]'),
('963f583a-b0a1-4594-9dfb-778be08a098b','山居三首  其二','劉應時','宋','宋诗','song-poetry','','[]','小小園林畔，蕭蕭叢薄間。',48,'全唐诗/poet.song.127000.json','["小小園林畔，蕭蕭叢薄間。", "茅簷頗幽隠，竹徑自回環。", "犬吠溪頭客，日銜窗外山。", "遺編淡相對，身世覺高閒。"]'),
('c1a7f354-3c3a-4479-a2d7-c4d82237d22b','山居三首  其三','劉應時','宋','宋诗','song-poetry','','[]','雨濕茅茨暗，日長天氣溫。',48,'全唐诗/poet.song.127000.json','["雨濕茅茨暗，日長天氣溫。", "心閒忘物累，足嬾出柴門。", "風靜收雲脚，山高露月痕。", "兒童展編簡，燈火又黄昏。"]'),
('781686d3-90a1-4dad-9615-e00e2ec583bc','辛亥長至後二首  其一','劉應時','宋','宋诗','song-poetry','','[]','老去驚時序，冬溫少沍陰。',48,'全唐诗/poet.song.127000.json','["老去驚時序，冬溫少沍陰。", "心閒知物理，陽復見天心。", "聖主成郊禮，寰區迓德音。", "病夫思贊善，擁褐發長吟。"]'),
('175551fc-7d91-48e1-aaa1-e295011be2fe','辛亥長至後二首  其二','劉應時','宋','宋诗','song-poetry','','[]','遥想清臺上，已書雲物祥。',48,'全唐诗/poet.song.127000.json','["遥想清臺上，已書雲物祥。", "自慚身老大，漸喜日舒長。", "芹泮三益友，芸窗一炷香。", "此間無俗物，貧病亦何傷。"]'),
('9cd1e313-8f21-4905-91a3-53d8d7f96f9e','秋夜書懷','劉應時','宋','宋诗','song-poetry','','[]','金行肅物歲功成，銀漢西斜夜氣清。',64,'全唐诗/poet.song.127000.json','["金行肅物歲功成，銀漢西斜夜氣清。", "淡月似爲吾輩款，短檠深見古人情。", "候蟲促織巧能語，露葉堕林微有聲。", "自笑何爲法天運，祇將心事卜前程。"]'),
('6e3e2b62-db77-4b1f-ae7f-7f085747dfe4','杜宇','劉應時','宋','宋诗','song-poetry','','[]','花殘葉密過芳春，江北江南煙水昏。',64,'全唐诗/poet.song.127000.json','["花殘葉密過芳春，江北江南煙水昏。", "何處飛來惱歸客，小窗夢破正消魂。", "月明聲在溪橋側，雨後人行綠樹村。", "啼得崔郎腸欲斷，桃花顔色悵何存。"]'),
('578a7c47-ded2-4a00-b107-540121c5bffb','酬平上人','劉應時','宋','宋诗','song-poetry','','[]','比鄰雞犬寂無聞，煙際微風起夕曛。',64,'全唐诗/poet.song.127000.json','["比鄰雞犬寂無聞，煙際微風起夕曛。", "腸斷梅飄千樹玉，眼寒麥浪一溪雲。", "拙於生計無如我，老矣情親獨有君。", "佇立茅簷一搔首，扶春夢月與誰分。"]'),
('213c3802-e070-4cf6-b1df-c9ba8ab9f52d','夜坐有感','劉應時','宋','宋诗','song-poetry','','[]','躬耕谷口未爲貧，安得生涯似子真。',64,'全唐诗/poet.song.127000.json','["躬耕谷口未爲貧，安得生涯似子真。", "平日固知窮有鬼，年來更覺老欺人。", "短檠頗怯蠅頭字，蠹簡時揩鼠迹塵。", "兒女豈知黄卷樂，苦嫌無補廢精神。"]'),
('68671c95-ca19-4d0d-9cd0-6267892aacd7','喜會故友','劉應時','宋','宋诗','song-poetry','','[]','邂逅相逢不作難，地爐握手話悲歡。',64,'全唐诗/poet.song.127000.json','["邂逅相逢不作難，地爐握手話悲歡。", "朝廷已誦相如賦，朋舊猶嗟范叔寒。", "剪剪秋花多勝韻，纍纍霜實尚微酸。", "小春天氣能來否，同訪山家苜蓿盤。"]'),
('99b7c98e-8794-4b01-b95f-35ac283355d9','遣懷','劉應時','宋','宋诗','song-poetry','','[]','自笑平居氣吐霓，桑榆暮景轉凄迷。',64,'全唐诗/poet.song.127000.json','["自笑平居氣吐霓，桑榆暮景轉凄迷。", "縱云舉世無青眼，敢忘終身誦白圭。", "風蕊弄香依水出，凍雲銜雪壓簷低。", "兒童不識人懷抱，苦傍寒窗讀鳳兮。"]'),
('8a25a462-ae15-4e2e-a050-40d3a455aea6','送張尉至丈亭','劉應時','宋','宋诗','song-poetry','','[]','丈亭亭前暫艤舟，寒濤拍岸江煙收。',64,'全唐诗/poet.song.127000.json','["丈亭亭前暫艤舟，寒濤拍岸江煙收。", "青山空解供望眼，濁酒不能澆別愁。", "春到疏籬梅蕊破，帆歸別浦浪花浮。", "分携情緒剪不斷，有媿悠悠波上鷗。"]'),
('97d4f5d8-327e-48ed-a1a0-477a21867a7f','過田家','劉應時','宋','宋诗','song-poetry','','[]','鳩鳴桑樹雨還來，且得農夫笑口開。',64,'全唐诗/poet.song.127000.json','["鳩鳴桑樹雨還來，且得農夫笑口開。", "雖曰田疇多再植，定須天氣作重梅。", "江魚欲買全無鏹，社酒堪篘旋潑醅。", "更遣兒童炊麥飯，殷勤相勸且徘徊。"]'),
('30fdeac1-5aca-4bee-ab70-48b3138e0fb7','次韻范至能尋梅','劉應時','宋','宋诗','song-poetry','','[]','藜杖扶人趁雪乾，玉虹倒影落前灘。',64,'全唐诗/poet.song.127000.json','["藜杖扶人趁雪乾，玉虹倒影落前灘。", "竹籬短短溪頭路，雲木荒荒日暮寒。", "每愧清香留我住，苦無佳句與人看。", "孤吟不忍空歸去，霜月侵衣興未闌。"]'),
('2d61a44d-5458-4f41-b750-001d3529945e','喜兒輩歸寧','劉應時','宋','宋诗','song-poetry','','[]','凜凜寒威欲挾綿，稜稜病骨只忻眠。',64,'全唐诗/poet.song.127000.json','["凜凜寒威欲挾綿，稜稜病骨只忻眠。", "燈花璀璨人歸後，雲色蒼茫雪作天。", "百歲光陰寧有幾，四時飲啄且隨緣。", "擁爐莫厭團圞樂，節物崢嶸又一年。"]'),
('c10f56c1-f424-47bc-b147-5811fb71ba7a','春晴','劉應時','宋','宋诗','song-poetry','','[]','簾幙低垂清晝長，弄晴梅柳拂鄰牆。',64,'全唐诗/poet.song.127000.json','["簾幙低垂清晝長，弄晴梅柳拂鄰牆。", "春光潑眼何明媚，幽鳥窺人自發揚。", "覓句忍饑貧亦樂，鈔書得味老何傷。", "舍南舍北無人到，閉閤時焚一炷香。"]'),
('95cc91b5-281c-4644-9200-1d28ffbf2d05','病中偶書','劉應時','宋','宋诗','song-poetry','','[]','老來懶與俗浮沉，何况厭厭病日侵。',64,'全唐诗/poet.song.127000.json','["老來懶與俗浮沉，何况厭厭病日侵。", "身外閑愁總餘事，世間無藥勝安心。", "雨餘秋色凄然冷，風弄晚雲晴復陰。", "習氣難除還自笑，小窗時有短長吟。"]'),
('7ae1e62b-a4ae-4fa4-b249-ed8be0e7f5c9','聞范至能丐祠二首  其一','劉應時','宋','宋诗','song-poetry','','[]','自是清都紫府人，偶來應見宰官身。',64,'全唐诗/poet.song.127000.json','["自是清都紫府人，偶來應見宰官身。", "諸公有類隨陽雁，此老方爲透網鱗。", "環轍已償行去脚，擁書更結未來因。", "石湖雖有閑風月，誰許深償寂寞濱。"]'),
('358301be-8f8c-4f46-ab91-b5a70cfdd203','聞范至能丐祠二首  其二','劉應時','宋','宋诗','song-poetry','','[]','士紳知己近來無，得此吾慚上大夫。',64,'全唐诗/poet.song.127000.json','["士紳知己近來無，得此吾慚上大夫。", "酷愛新詩成異遇，每於廣坐語諸儒。", "既紓北顧思歸矣，聞返西州有是夫。", "便欲拏舟去相訪，推篷邀月話江湖。"]'),
('44579872-513c-4dce-9496-5a53c6dd580b','祐上人製紙帳作詩謝之','劉應時','宋','宋诗','song-poetry','','[]','老來何物是生涯，一榻翛然亦自佳。',64,'全唐诗/poet.song.127000.json','["老來何物是生涯，一榻翛然亦自佳。", "睡裏山禽弄霜曉，夢回明月上梅花。", "頗知常侍嫌烏布，未羨先生坐絳紗。", "最愛灑窗風雪夜，道人施法復何加。"]'),
('4c0b0472-4d9b-4dc0-863e-a5acbfa550a0','九日','劉應時','宋','宋诗','song-poetry','','[]','吟懷祇恐負嘉期，不憚登高脚力疲。',64,'全唐诗/poet.song.127000.json','["吟懷祇恐負嘉期，不憚登高脚力疲。", "滿眼關愁淡秋色，長箋入手粲明璣。", "興來不省風吹帽，醉後何愁酒濕衣。", "欲和藍田無好語，笑挼黄菊带香歸。"]'),
('8af437b9-3a7b-41a3-aa64-1683f44d46ec','石菖蒲','劉應時','宋','宋诗','song-poetry','','[]','十年夢不到丘壑，清坐喜看寒瘦姿。',64,'全唐诗/poet.song.127000.json','["十年夢不到丘壑，清坐喜看寒瘦姿。", "玉立一峯森黛色，虬蟠九節漾風漪。", "涓涓月露欲生處，漠漠溪雲未散時。", "却笑輕狂桃李眼，臞仙風韻不能窺。"]'),
('b00dcd83-3b6b-4324-bcf6-cdba035c1d58','山行','劉應時','宋','宋诗','song-poetry','','[]','瘦藤慚愧肯相携，不怕微茫雪意低。',64,'全唐诗/poet.song.127000.json','["瘦藤慚愧肯相携，不怕微茫雪意低。", "晚照荒荒迷遠岫，濕雲漠漠度前溪。", "雖無酒力禦寒色，且向梅花覓舊題。", "漫說玉堂多勝事，何如丘壑卜幽棲。"]'),
('828eb121-276d-4d29-a6cb-1c875c0b315d','雨後訪田家','劉應時','宋','宋诗','song-poetry','','[]','一雨及時晴又佳，江村農父話諠譁。',64,'全唐诗/poet.song.127000.json','["一雨及時晴又佳，江村農父話諠譁。", "旋炊麥飯非常飽，笑指苗田不用車。", "有眼何曾識朝市，逢人只喜話桑麻。", "此間賸有漁樵地，容我旁邊著一家。"]'),
('58d4fd59-def9-4e5c-abee-c6c5ac81e941','病中和蔡堅老','劉應時','宋','宋诗','song-poetry','','[]','老去光陰苦不多，孰堪疾病數驅磨。',64,'全唐诗/poet.song.127000.json','["老去光陰苦不多，孰堪疾病數驅磨。", "也知溪上春光好，奈爾牀頭藥裹何。", "日永茶甌頻索喚，睡餘詩眼旋揩摩。", "客來怕說人間話，古井須知已不波。"]'),
('a2335fd7-6b45-49fb-8226-6a1f0a337a82','山居','劉應時','宋','宋诗','song-poetry','','[]','淺淺溪流短短籬，碧於深處小茅茨。',32,'全唐诗/poet.song.127000.json','["淺淺溪流短短籬，碧於深處小茅茨。", "想無俗子知蹤跡，小款梅花細說詩。"]'),
('9975fac9-f2f8-4022-8b6c-01ee9a253375','秋郊','劉應時','宋','宋诗','song-poetry','','[]','柿葉飄零滿屋除，半山銜日落丘墟。',32,'全唐诗/poet.song.127000.json','["柿葉飄零滿屋除，半山銜日落丘墟。", "睡餘不覺西風急，亂我窗前數板書。"]'),
('0d5ed2cf-42ee-4543-8a82-86e71ed5f8d2','過飛鳬別業','劉應時','宋','宋诗','song-poetry','','[]','垂空小雨濕梅花，一嶺穿雲石逕斜。',32,'全唐诗/poet.song.127000.json','["垂空小雨濕梅花，一嶺穿雲石逕斜。", "燕子飛時春欲暮，斷橋煙水渺無涯。"]'),
('4623ff4b-88ef-4b34-a14c-6138c1535439','史魏公東湖別墅二首  其一','劉應時','宋','宋诗','song-poetry','','[]','雲抹山容疑潑綠，月涵波影自摇金。',32,'全唐诗/poet.song.127000.json','["雲抹山容疑潑綠，月涵波影自摇金。", "丈夫出處如雲月，猿鶴安能識此心。"]'),
('e912c40a-f816-4767-b116-6b257705333d','史魏公東湖別墅二首  其二','劉應時','宋','宋诗','song-poetry','','[]','徜徉綠野春波上，徙倚石樓煙靄間。',32,'全唐诗/poet.song.127000.json','["徜徉綠野春波上，徙倚石樓煙靄間。", "只恐蒼生待霖雨，未容謝傅老東山。"]'),
('a395bb7f-6190-4a3a-b5fa-cf36813da505','早行','劉應時','宋','宋诗','song-poetry','','[]','登輿睡思尚昏昏，斗柄銜山月在門。',32,'全唐诗/poet.song.127000.json','["登輿睡思尚昏昏，斗柄銜山月在門。", "雞犬未鳴潮半落，草蟲聲在荳花村。"]'),
('932707ff-34a4-4aeb-ba06-8cc1be640d3e','春晚二首  其一','劉應時','宋','宋诗','song-poetry','','[]','天氣清和晴復陰，酴醿堆雪笋抽簪。',32,'全唐诗/poet.song.127000.json','["天氣清和晴復陰，酴醿堆雪笋抽簪。", "誰知老去傷春意，自把茶甌當酒斟。"]'),
('44173e9d-dfec-44bc-8a69-bd4a7d8e33fe','春晚二首  其二','劉應時','宋','宋诗','song-poetry','','[]','子規聲裏正斜陽，風過斷橋流水香。',32,'全唐诗/poet.song.127000.json','["子規聲裏正斜陽，風過斷橋流水香。", "頗怪影侵書带綠，弄晴柳色過鄰牆。"]'),
('2202ae07-7764-4e08-9428-01bfd0bb3f21','萱花','劉應時','宋','宋诗','song-poetry','','[]','碧玉長簪出短籬，枝頭腥血耐炎暉。',32,'全唐诗/poet.song.127000.json','["碧玉長簪出短籬，枝頭腥血耐炎暉。", "北堂花在親何在，幾對薰風淚濕衣。"]'),
('db43423e-f1c6-4ab6-afb4-1ac9f6d7c1bb','開窗','劉應時','宋','宋诗','song-poetry','','[]','檐前分得小窗明，便覺翛然眼界清。',32,'全唐诗/poet.song.127000.json','["檐前分得小窗明，便覺翛然眼界清。", "香燼一爐書滿几，世間何物可關情。"]'),
('b1775c06-b877-4aa3-8809-3c76a0106ff8','西郊三首  其一','劉應時','宋','宋诗','song-poetry','','[]','紫槿綠籬愁意深，斜陽墟落動秋砧。',32,'全唐诗/poet.song.127000.json','["紫槿綠籬愁意深，斜陽墟落動秋砧。", "筆端有口江湖遠，莫寫干時老子心。"]'),
('7f5f03c8-0525-4e2f-8a29-82177b5288f0','西郊三首  其二','劉應時','宋','宋诗','song-poetry','','[]','薄雲斜日媚平川，一老來耕刈後田。',32,'全唐诗/poet.song.127000.json','["薄雲斜日媚平川，一老來耕刈後田。", "向晚歸牛尋熟路，擺頭昂鼻不須牽。"]'),
('03b14117-11b6-4965-b1ab-6eadfab08209','西郊三首  其三','劉應時','宋','宋诗','song-poetry','','[]','誰人躍馬出西郊，野水瀰瀰漲路坳。',32,'全唐诗/poet.song.127000.json','["誰人躍馬出西郊，野水瀰瀰漲路坳。", "好似吟哦方得句，時時指點舉鞭梢。"]'),
('ce9888da-0bae-43ad-abd4-c9875fcd8b51','懷瑩上人','劉應時','宋','宋诗','song-poetry','','[]','半路梅花作峭寒，懷人無地著愁酸。',32,'全唐诗/poet.song.127000.json','["半路梅花作峭寒，懷人無地著愁酸。", "幽居獨得春風力，補綴林塘漸可觀。"]'),
('b2f45038-0d91-4f24-a940-b6cf9ec26a13','梅林即事四首  其一','劉應時','宋','宋诗','song-poetry','','[]','入眼溪山記舊遊，春風籬落只供愁。',32,'全唐诗/poet.song.127000.json','["入眼溪山記舊遊，春風籬落只供愁。", "斷腸䔩䔩飄香雪，短笛一聲誰倚樓。"]'),
('f4489119-5c8f-4068-98fe-7a935306c116','梅林即事四首  其二','劉應時','宋','宋诗','song-poetry','','[]','瘦減腰圍儘不妨，豈堪三篾束枯腸。',32,'全唐诗/poet.song.127000.json','["瘦減腰圍儘不妨，豈堪三篾束枯腸。", "自憐尚有風流債，酷愛斷橋流水香。"]'),
('9cf48943-b2e7-4d81-9e46-ed0dcbee9a40','梅林即事四首  其三','劉應時','宋','宋诗','song-poetry','','[]','藜杖緣溪轉小橋，背風深處似相招。',32,'全唐诗/poet.song.127000.json','["藜杖緣溪轉小橋，背風深處似相招。", "兒童指點皆驚怪，喚作枝頭雪未消。"]'),
('d6935a9f-9b7c-4cd9-adb5-27ac71a396da','梅林即事四首  其四','劉應時','宋','宋诗','song-poetry','','[]','竹塢松溪雪半埋，興來無處著吟懷。',32,'全唐诗/poet.song.127000.json','["竹塢松溪雪半埋，興來無處著吟懷。", "茅檐盡出橫斜影，寂寞黄昏月上階。"]'),
('8357c4f2-1a96-4ca1-8db0-861bbe0198d6','懷怡雲平老三首  其一','劉應時','宋','宋诗','song-poetry','','[]','江湖夢斷十年餘，尚記寒窗誦子虛。',32,'全唐诗/poet.song.127000.json','["江湖夢斷十年餘，尚記寒窗誦子虛。", "回首扶春堂下路，別來風月果何如。"]'),
('eae48c64-8841-4fdb-ab38-d060cbb07460','懷怡雲平老三首  其二','劉應時','宋','宋诗','song-poetry','','[]','晚陰分暝與幽窗，心旆摇摇不可降。',32,'全唐诗/poet.song.127000.json','["晚陰分暝與幽窗，心旆摇摇不可降。", "隠几正爲丘壑夢，半隨柔櫓過滄江。"]'),
('87d93345-6004-4da4-acee-c2ab2325cc0e','懷怡雲平老三首  其三','劉應時','宋','宋诗','song-poetry','','[]','柔桑已密吳蠶老，簾幙低垂燕子飛。',32,'全唐诗/poet.song.127000.json','["柔桑已密吳蠶老，簾幙低垂燕子飛。", "想見石欄斜點筆，海雲深重濕山衣。"]'),
('770c9c9c-9279-46ef-9281-ce3619e1da0a','曹直夫水石短軸二首  其一','劉應時','宋','宋诗','song-poetry','','[]','奔流出峽響如雷，筆力浮天亦壯哉。',32,'全唐诗/poet.song.127000.json','["奔流出峽響如雷，筆力浮天亦壯哉。", "吳蜀興亡千古恨，白鷗時逐浪花來。"]'),
('30d0d0ce-9cde-4ee1-a317-3334475a4544','曹直夫水石短軸二首  其二','劉應時','宋','宋诗','song-poetry','','[]','清風斂霽入巴山，春漲攘人釣月灣。',32,'全唐诗/poet.song.127000.json','["清風斂霽入巴山，春漲攘人釣月灣。", "欠箇小舟青篛笠，着儂長在水雲間。"]'),
('0ef47dd0-5d1f-4f3c-98be-ae7e36d054a3','義上人歸自武林戲作四偈  其一','劉應時','宋','宋诗','song-poetry','','[]','十載江湖寄此身，足香慣踏軟紅塵。',32,'全唐诗/poet.song.127000.json','["十載江湖寄此身，足香慣踏軟紅塵。", "夢回一笑知何有，穩卧家山寂寞濱。"]'),
('f07f3007-fc6b-4480-986d-5591ae7160bc','義上人歸自武林戲作四偈  其二','劉應時','宋','宋诗','song-poetry','','[]','行脚從來笑趙州，草鞋踏破竟何求。',32,'全唐诗/poet.song.127000.json','["行脚從來笑趙州，草鞋踏破竟何求。", "百千三昧無窮義，不出頤菴拄杖頭。"]'),
('32db7df6-4bbe-4f4a-b386-07d30329405e','義上人歸自武林戲作四偈  其三','劉應時','宋','宋诗','song-poetry','','[]','老去居然懶出門，故鄉零落暗消魂。',32,'全唐诗/poet.song.127000.json','["老去居然懶出門，故鄉零落暗消魂。", "歲寒道義唯松竹，伴我東溪沙水村。"]'),
('d0373e15-9814-4830-8531-6326cf5f32aa','義上人歸自武林戲作四偈  其四','劉應時','宋','宋诗','song-poetry','','[]','身世總爲閑伎倆，生前須了惡因緣。',32,'全唐诗/poet.song.127000.json','["身世總爲閑伎倆，生前須了惡因緣。", "把茅約子歸雲壑，品字柴頭坐說禪。"]'),
('c687dd8d-fbb8-47dc-9d0e-2df4152a5dcb','謝香山禪師惠水巖新茗二首  其一','劉應時','宋','宋诗','song-poetry','','[]','雨暗水巖春意濃，尚思采采隔珍叢。',32,'全唐诗/poet.song.127000.json','["雨暗水巖春意濃，尚思采采隔珍叢。", "睡魔正壓眉楞重，珍重南屏信息通。"]'),
('0119e5e4-db29-47f5-9b0a-491cb3ce8476','謝香山禪師惠水巖新茗二首  其二','劉應時','宋','宋诗','song-poetry','','[]','趙州古佛不同時，頼有斯人慰所思。',32,'全唐诗/poet.song.127000.json','["趙州古佛不同時，頼有斯人慰所思。", "搜攪枯腸無一物，夢回日影上花枝。"]'),
('d220a7f4-2f29-4b84-83b5-af438d5c8e5a','春日即事三首  其一','劉應時','宋','宋诗','song-poetry','','[]','春來九雨一日晴，藜杖扶人出戶庭。',32,'全唐诗/poet.song.127000.json','["春來九雨一日晴，藜杖扶人出戶庭。", "柳色肯如衰俗眼，向人還似舊時青。"]'),
('d7bbe1bc-6141-4a3e-a436-da44fbff7980','春日即事三首  其二','劉應時','宋','宋诗','song-poetry','','[]','野草閑花無姓名，疎籬幽逕漸敷榮。',32,'全唐诗/poet.song.127000.json','["野草閑花無姓名，疎籬幽逕漸敷榮。", "貧居閲盡人間事，只有東風不世情。"]'),
('ef279a2b-b809-44b3-a64e-2a770488a107','春日即事三首  其三','劉應時','宋','宋诗','song-poetry','','[]','二月風光漸惱人，蒙茸細雨濕花唇。',32,'全唐诗/poet.song.127000.json','["二月風光漸惱人，蒙茸細雨濕花唇。", "可憐病目長憔悴，坐看紛紛萬卉春。"]'),
('a3abd2d5-1f52-4a55-adc8-9b191333c358','頤菴口占','劉應時','宋','宋诗','song-poetry','','[]','健即觀書困即眠，飯餘香燼濕茶煙。',32,'全唐诗/poet.song.127000.json','["健即觀書困即眠，飯餘香燼濕茶煙。", "客來莫說人間話，我是清貧無事仙。"]'),
('98846e91-c3fa-4923-8547-c0e6ad2db6c6','遣懷二首  其一','劉應時','宋','宋诗','song-poetry','','[]','小桃無力困東風，似整殘粧睡思濃。',32,'全唐诗/poet.song.127000.json','["小桃無力困東風，似整殘粧睡思濃。", "老子愁腸正如結，蒼苔滿地點殷紅。"]'),
('ab5ea655-8e13-4b5e-b2c1-a883ab5c8821','遣懷二首  其二','劉應時','宋','宋诗','song-poetry','','[]','蕭蕭叢薄倚頹垣，頗覺舒長春晝喧。',32,'全唐诗/poet.song.127000.json','["蕭蕭叢薄倚頹垣，頗覺舒長春晝喧。", "搜攪枯腸無好語，等閑日影過前軒。"]'),
('db435fee-addc-47f4-ad98-430d174c7e6a','縣庠直舍','劉應時','宋','宋诗','song-poetry','','[]','午日已過人寂寂，虛齋獨坐竹蕭蕭。',32,'全唐诗/poet.song.127000.json','["午日已過人寂寂，虛齋獨坐竹蕭蕭。", "睡魔正與詩魔戰，窗外一聲婆餠焦。"]'),
('c4318f48-e4b9-463e-a18a-b62b16c43114','早起','劉應時','宋','宋诗','song-poetry','','[]','斗轉星稀夜欲闌，月魂斜墮屋頭山。',32,'全唐诗/poet.song.127000.json','["斗轉星稀夜欲闌，月魂斜墮屋頭山。", "雞聲喚起十年事，盡在吟窗一枕間。"]'),
('3df34078-3773-42b3-bc84-b023c0ece14a','即事','劉應時','宋','宋诗','song-poetry','','[]','暖雲芳草媚晴川，花正嬌春柳欲眠。',32,'全唐诗/poet.song.127000.json','["暖雲芳草媚晴川，花正嬌春柳欲眠。", "老景侵尋生事拙，舊巢歸燕自相憐。"]'),
('e297bbb6-b7a0-42ed-a901-edbaa1e9d6d2','送人還會稽','劉應時','宋','宋诗','song-poetry','','[]','稽山佳趣勝蓬瀛，橘里漁樵畫不成。',32,'全唐诗/poet.song.127000.json','["稽山佳趣勝蓬瀛，橘里漁樵畫不成。", "我欲鑑湖分一曲，煩君先與白鷗盟。"]'),
('3329eccc-4d36-4747-ad29-a65bbb694455','郊行三首  其一','劉應時','宋','宋诗','song-poetry','','[]','少日襟懷眇古今，凶年樂歲不關心。',32,'全唐诗/poet.song.127000.json','["少日襟懷眇古今，凶年樂歲不關心。", "自憐老去多憂國，白水田頭問淺深。"]'),
('bd4c67a9-595d-4add-bc52-1a1b0548d99b','郊行三首  其二','劉應時','宋','宋诗','song-poetry','','[]','西郊穡事欲迎秋，旱魃肆兇猶未收。',32,'全唐诗/poet.song.127000.json','["西郊穡事欲迎秋，旱魃肆兇猶未收。", "卷地黑風吹雨散，稻花飄蕩滿天浮。"]'),
('49223903-002d-4418-bb20-a8512ba29a69','郊行三首  其三','劉應時','宋','宋诗','song-poetry','','[]','茫茫阡陌起黄埃，喜望片雲銜雨來。',32,'全唐诗/poet.song.127000.json','["茫茫阡陌起黄埃，喜望片雲銜雨來。", "霢霂未施風不息，依然白日照樓臺。"]'),
('9a9eacc5-ff2f-4ecd-9db3-964eef07ccdf','霞外亭二首  其一','劉應時','宋','宋诗','song-poetry','','[]','詩眼眈眈細八荒，小亭徙倚濕山光。',32,'全唐诗/poet.song.127000.json','["詩眼眈眈細八荒，小亭徙倚濕山光。", "飛鴻影落遥岑外，興與飛鴻更渺茫。"]'),
('8fcf5cf5-d891-4a92-b6c0-378eabf21385','霞外亭二首  其二','劉應時','宋','宋诗','song-poetry','','[]','數椽屹起枕林丘，雲葉蕭蕭萬木秋。',32,'全唐诗/poet.song.127000.json','["數椽屹起枕林丘，雲葉蕭蕭萬木秋。", "一縷殘紅曳微日，渺然天際識歸舟。"]'),
('4f764bdf-a605-4415-94e4-3844e9115570','雪夜二首  其一','劉應時','宋','宋诗','song-poetry','','[]','迎春寒色愈嚴凝，小閣爐殘冷欲冰。',32,'全唐诗/poet.song.127000.json','["迎春寒色愈嚴凝，小閣爐殘冷欲冰。", "寂寞黄昏愁弔影，雪窗怕上短檠燈。"]'),
('d756b382-83de-4ae1-97e1-76f570f3d4bf','雪夜二首  其二','劉應時','宋','宋诗','song-poetry','','[]','浮雲著眼不留蹤，獨與梅花共過冬。',32,'全唐诗/poet.song.127000.json','["浮雲著眼不留蹤，獨與梅花共過冬。", "淡月故移疎影去，斷魂誰杵暮山鐘。"]'),
('bfe9a44f-d4f3-48f9-9dad-74b2d9beb84b','山中三首  其一','劉應時','宋','宋诗','song-poetry','','[]','始看紅紫上花稍，倏忽春光半已消。',32,'全唐诗/poet.song.127000.json','["始看紅紫上花稍，倏忽春光半已消。", "最是幽窗斷魂處，杜鵑啼月過山腰。"]'),
('5b10936f-4cf1-42ad-a636-886877ff20bb','山中三首  其二','劉應時','宋','宋诗','song-poetry','','[]','伏櫪已無千里志，卧雲聊作一枝棲。',32,'全唐诗/poet.song.127000.json','["伏櫪已無千里志，卧雲聊作一枝棲。", "田翁笑喜桑麻長，山北山南雨意低。"]'),
('1ba7ebc3-933a-4368-bef0-e119fffd1dc6','山中三首  其三','劉應時','宋','宋诗','song-poetry','','[]','年來世路愈間關，且喜兒童放我閒。',32,'全唐诗/poet.song.127000.json','["年來世路愈間關，且喜兒童放我閒。", "百歲光陰無一半，萊衣能得幾時斑。"]'),
('d245f7e0-b96b-4452-acf3-9a5178f64fc0','聞張逸人訃二首  其一','劉應時','宋','宋诗','song-poetry','','[]','去馬來牛閲幾秋，濁涇清渭只同流。',32,'全唐诗/poet.song.127000.json','["去馬來牛閲幾秋，濁涇清渭只同流。", "斷弦掛壁知音去，旋撲塵編有許愁。"]'),
('2f578054-3d2e-4241-b5ee-d68824055e4e','聞張逸人訃二首  其二','劉應時','宋','宋诗','song-poetry','','[]','梅子黄時麥已秋，野塘高下水交流。',32,'全唐诗/poet.song.127000.json','["梅子黄時麥已秋，野塘高下水交流。", "小窗聲切哀鴻雁，添我懷人一段愁。"]'),
('4f18dd97-9b0d-40fe-a55d-3bb24fd00a6f','句  其一','劉應時','宋','宋诗','song-poetry','','[]','世事不復問，舊書時一看。',12,'全唐诗/poet.song.127000.json','["世事不復問，舊書時一看。"]'),
('99469b28-6b0a-4e77-875b-423f6f939fe8','句  其二','劉應時','宋','宋诗','song-poetry','','[]','燭與梅花共過冬，淡月故移踈影去。',16,'全唐诗/poet.song.127000.json','["燭與梅花共過冬，淡月故移踈影去。"]'),
('578184d8-316f-4c45-953d-62de8b46c3e5','羅漢石','曾季貍','宋','宋诗','song-poetry','','[]','吾聞大幻師，種種示方便。',144,'全唐诗/poet.song.127000.json','["吾聞大幻師，種種示方便。", "雖於土石中，神力亦周遍。", "君看此翠琅，乃有羅漢面。", "殷勤作禮相，形質皆可辨。", "初觀頂相殊，次觀雙足現。", "僧袍如輕綃，風舉勢轉旋。", "得非方廣尊，影落此石片。", "千年磨不盡，若堅金百煉。", "我來一瞻敬，贊歎未曾見。", "摩挲諦玩久，欲去反留戀。", "叮嚀善守護，尊者俱神變。", "會當清夜闌，神光照金殿。"]'),
('7e9f6917-a92d-413b-9a28-db21cc007b61','靈谷山','曾季貍','宋','宋诗','song-poetry','','[]','舊聞伯子記，已得靈谷名。',180,'全唐诗/poet.song.127000.json','["舊聞伯子記，已得靈谷名。", "隠然望此州，奇勝稱山靈。", "懸崖瀉瀑布，如高屋建瓴。", "喬松數十丈，下有千歲苓。", "仄足行鳥道，勢欲摶青冥。", "仙事雖渺茫，幽討未忘情。", "高秋八月後，擇勝來經行。", "黄冠兩三人，淡然亦忘形。", "煙霞到几席，爽氣來戶庭。", "瘦笻閒指點，老瓦同注傾。", "慚非換鵝手，不敢臨黄庭。", "或可聯石鼎，未必讓彌明。", "重陽無十日，黄菊漸向榮。", "佳哉此天氣，一笑未易營。", "但願脚力健，年年此尋盟。"]'),
('acbfc2c8-b4de-4208-9b05-d39d55ea64ae','躍馬泉','曾季貍','宋','宋诗','song-poetry','','[]','山靈從何來，崩騰躍萬馬。',60,'全唐诗/poet.song.127000.json','["山靈從何來，崩騰躍萬馬。", "初疑夫差軍，水犀光照夜。", "又疑閼於戰，聲撼武安馬。", "森然毛骨竦，舌拄不能下。", "對此神驂姿，可以一戰霸。"]'),
('31f04b85-9e5a-4753-82e6-7ffe534746ca','五星泉','曾季貍','宋','宋诗','song-poetry','','[]','五星耀寒芒，直射入九淵。',60,'全唐诗/poet.song.127000.json','["五星耀寒芒，直射入九淵。", "化爲石泉眠，位置相聯綿。", "相映璧月夜，上下爭珠連。", "星光本遊空，著地今何然。", "得非泉石癖，如我老不悛。"]'),
('ea241f3a-f0c5-4fdc-88d2-ed966fd8eef9','宿正覺寺','曾季貍','宋','宋诗','song-poetry','','[]','正覺江邊寺，風煙罨畫然。',48,'全唐诗/poet.song.127000.json','["正覺江邊寺，風煙罨畫然。", "庭羅合抱樹，門泊釣魚船。", "暮雨凉初過，中秋月正圓。", "無人來共賞，獨自占江天。"]'),
('00dbad50-a90a-4857-b5f1-f572ceb34658','白水寺','曾季貍','宋','宋诗','song-poetry','','[]','暫假僧房憩，炎蒸覺頓忘。',48,'全唐诗/poet.song.127000.json','["暫假僧房憩，炎蒸覺頓忘。", "誰知六月雨，已似九秋凉。", "石徑苔痕滑，稻花田水香。", "鳴蟬休聒耳，容我此徜徉。"]'),
('1c377d08-3cb4-4c0c-9229-8f7b1bd7ef18','苦竹行','曾季貍','宋','宋诗','song-poetry','','[]','碧草送春晚，綠陰迎夏凉。',48,'全唐诗/poet.song.127000.json','["碧草送春晚，綠陰迎夏凉。", "輕風摇細麥，淺水出新秧。", "歲月催人老，田園引興長。", "一廛如可辦，吾亦學耕桑。"]'),
('521b3c88-15c1-4c1c-947d-b3bd340e897e','金石臺','曾季貍','宋','宋诗','song-poetry','','[]','江上岧嶢百尺臺，摩挲塵跡但徘徊。',64,'全唐诗/poet.song.127000.json','["江上岧嶢百尺臺，摩挲塵跡但徘徊。", "不辭濁酒三杯醉，坐對晴空萬里開。", "楚澤風烟隨處好，仙家桃李有誰栽。", "黄花過了梅花發，待我扶藜得復來。"]'),
('b922bd56-b68a-4261-9af3-5d6e1d6bbc9d','南湖','曾季貍','宋','宋诗','song-poetry','','[]','葛巾藜杖興何長，爲愛南湖六月凉。',64,'全唐诗/poet.song.127000.json','["葛巾藜杖興何長，爲愛南湖六月凉。", "雨在山頭作雲氣，風來水面散荷香。", "登臨稍喜市聲遠，徙倚猶嫌歸興忙。", "後日重來携枕簟，不妨午夢到斜陽。"]'),
('e5fed71d-2b49-4bb6-aca1-9a64d8fc78ef','積翠樓  其一','曾季貍','宋','宋诗','song-poetry','','[]','手捫霄漢摘天星，脚踏丹梯最上層。',32,'全唐诗/poet.song.127000.json','["手捫霄漢摘天星，脚踏丹梯最上層。", "須信神仙足官府，能令雞犬亦飛昇。"]'),
('f4f0a2eb-9f9d-4344-992c-33c77fa40d57','積翠樓  其二','曾季貍','宋','宋诗','song-poetry','','[]','少日便懷丘壑情，看山看水飽曾經。',32,'全唐诗/poet.song.127000.json','["少日便懷丘壑情，看山看水飽曾經。", "如今積翠樓頭望，看盡江南未了青。"]'),
('c1c0bd4f-2203-41f2-884b-e5f94e28c5a2','西隠寺','曾季貍','宋','宋诗','song-poetry','','[]','彷彿兒時住此間，重來不記舊山川。',32,'全唐诗/poet.song.127000.json','["彷彿兒時住此間，重來不記舊山川。", "却因坐久僧相問，細數如今二十年。"]'),
('b7f82430-ac83-445d-b438-95d0ad191b72','疏山道中','曾季貍','宋','宋诗','song-poetry','','[]','村深谷鳥近人鳴，暮靄收時雨又晴。',32,'全唐诗/poet.song.127000.json','["村深谷鳥近人鳴，暮靄收時雨又晴。", "極目春山隨處好，笋輿穿盡綠陰行。"]'),
('a2e64c92-92ec-4c2b-a336-b5489f40b1cd','苦竹舟行','曾季貍','宋','宋诗','song-poetry','','[]','船頭觸處浪花生，船尾隨人山影行。',32,'全唐诗/poet.song.127000.json','["船頭觸處浪花生，船尾隨人山影行。", "一水到家能幾許，順流東下片時程。"]'),
('921faef4-189f-42ba-a9a9-8b05149eed9d','危全楓祠','曾季貍','宋','宋诗','song-poetry','','[]','香火頹然寄梵宮，精英不與衆禪同。',32,'全唐诗/poet.song.127000.json','["香火頹然寄梵宮，精英不與衆禪同。", "臨川千古人心在，猶說當年保障功。"]'),
('4e623417-4b33-430a-8db0-8b3c460acde8','疏山','曾季貍','宋','宋诗','song-poetry','','[]','來往疏山四十年，主人與客兩華顛。',64,'全唐诗/poet.song.127000.json','["來往疏山四十年，主人與客兩華顛。", "此心不改澄河見，往事休論過鳥然。", "無復仙舟遺跡在，空餘矮叔一燈傳。", "危亭獨上窮登眺，古木蒼藤繞暮煙。"]'),
('c719cf38-79e7-4e3e-b58b-b857b3d52f79','楊源寺','曾季貍','宋','宋诗','song-poetry','','[]','落日郊原獨杖藜，偶尋蕭寺坐移時。',64,'全唐诗/poet.song.127000.json','["落日郊原獨杖藜，偶尋蕭寺坐移時。", "下臨稻壟如棋局，細數僧房似蜜脾。", "風裏長松能遠韻，霜餘殘菊尚多姿。", "因吟竹院詩人語，笑我勞生力已疲。"]'),
('9c2e117c-0d25-4197-b789-8da563a309e5','疏山三首  其一','曾季貍','宋','宋诗','song-poetry','','[]','江南九月未飛霜，木葉蕭蕭已半黄。',32,'全唐诗/poet.song.127000.json','["江南九月未飛霜，木葉蕭蕭已半黄。", "行遍疏山山下路，滿山唯有桂花香。"]'),
('12c074bd-aa1a-4bb4-a3c7-630404f9cbe2','疏山三首  其二','曾季貍','宋','宋诗','song-poetry','','[]','垍湖潭畔呼舟渡，苦竹林邊策杖回。',32,'全唐诗/poet.song.127000.json','["垍湖潭畔呼舟渡，苦竹林邊策杖回。", "衣濕爲穿山雨過，手香因折野梅來。"]'),
('d4b3c619-5506-49bf-8ab4-29547073ed7c','疏山三首  其三','曾季貍','宋','宋诗','song-poetry','','[]','草封支徑路欲斷，雨洗野花山更寒。',32,'全唐诗/poet.song.127000.json','["草封支徑路欲斷，雨洗野花山更寒。", "西嶺東岡烟漠漠，南溪北澗水潺潺。"]'),
('b272fe46-5c43-4b34-a724-e8106ddf371b','鳴玉泉','曾季貍','宋','宋诗','song-poetry','','[]','何人邀我來，白晝朝鈞天。',60,'全唐诗/poet.song.127000.json','["何人邀我來，白晝朝鈞天。", "千官正雜沓，佩有蒼玉懸。", "衝牙互擊觸，遠韻聲泠然。", "律呂相應和，宮徵更相宣。", "應笑居鄛人，玉斗空碎捐。"]'),
('dc9b8144-13c6-4800-8f92-42c46902d1c7','梅花','曾季貍','宋','宋诗','song-poetry','','[]','桃李艷陽態，笑我不入時。',24,'全唐诗/poet.song.127000.json','["桃李艷陽態，笑我不入時。", "松竹貧賤交，却是同襟期。"]'),
('8f34a0e9-c483-4436-b735-a4010f0e213f','桃花','曾季貍','宋','宋诗','song-poetry','','[]','衣裁緗纈態纖穠，猶在瑶池午醉中。',32,'全唐诗/poet.song.127000.json','["衣裁緗纈態纖穠，猶在瑶池午醉中。", "嫌近清明時節令，趁渠新火一番紅。"]'),
('f46af14e-2b0f-41c7-be60-b09c84a0713c','秦女行','曾季貍','宋','宋诗','song-poetry','','[]','妾家家世居淮海，郎罷聲名傳海內。',288,'全唐诗/poet.song.127000.json','["妾家家世居淮海，郎罷聲名傳海內。", "自從貶死古藤州，門戶凋零三十載。", "可憐生長深閨裏，耳濡目染知文字。", "亦嘗强學謝娘詩，未敢女子稱博士。", "年長以來逢世亂，黄頭鮮卑來入漢。", "妾身亦復墮兵間，往事不堪回首看。", "飄然一身逐胡兒，被驅不異犬與雞。", "奔馳萬里向沙漠，天長地久無還期。", "北風蕭蕭易水寒，雪花席地經燕山。", "千杯虜酒安能醉，一曲琵琶不忍彈。", "吞聲飲恨從誰訴，偶然信口題詩句。", "眼前有路可還鄉，馬上無人容我去。", "詩成吟罷只茫然，豈意漢地能流傳。", "當時情緒亦可想，至今聞者猶悲酸。", "憶昔中郎有女子，亦陷虜中垂一紀。", "暮年不料逢阿瞞，厚幣贖之歸故里。", "惜哉此女不得如，終竟老死留穹廬。", "空餘詩話傳悽惻，不減胡笳十八拍。"]'),
('a1f6d616-70cd-45f1-94af-2c9c1d0abf99','雷公保國寺畫壁','曾季貍','宋','宋诗','song-poetry','','[]','我遊保國三十年，昔者童稚今華顛。',128,'全唐诗/poet.song.127000.json','["我遊保國三十年，昔者童稚今華顛。", "僧非昔人屋亦改，仰視喬木皆參天。", "惟餘畫壁屹相向，塵封蛛網猶依然。", "空王龍鍾曳杖立，彌勒遊戲挑囊眠。", "不知寺已幾興廢，獨此經久無變遷。", "我來摩挲三太息，欲去不忍空留連。", "丁寧老僧爲守護，慎勿破壁隨雲煙。", "作詩仍以示來者，此詩此畫當俱傳。"]'),
('945b7af2-e04a-4d62-90a3-74986c30a07f','憩雷公山','曾季貍','宋','宋诗','song-poetry','','[]','酒薄飲難醉，山寒夢不成。',48,'全唐诗/poet.song.127000.json','["酒薄飲難醉，山寒夢不成。", "窗間殘月影，枕上曉鐘聲。", "邱壑平生事，山林少日情。", "白頭翁老矣，數畝未經營。"]'),
('f7ad657b-55d1-4b13-a8bc-d3ab83567332','金沙寺','曾季貍','宋','宋诗','song-poetry','','[]','古寺同真率，君家更秩筵。',48,'全唐诗/poet.song.127000.json','["古寺同真率，君家更秩筵。", "酒杯無算飲，橘樹不論錢。", "勝日携佳客，曾來是去年。", "莫嫌頻至此，直爲主人賢。"]'),
('c21c3090-3378-4920-b943-34a407d7ccdd','宿正覺寺','曾季貍','宋','宋诗','song-poetry','','[]','古寺荒凉甚，秋風更颯然。',48,'全唐诗/poet.song.127000.json','["古寺荒凉甚，秋風更颯然。", "殿焚猶有礎，僧老不知年。", "但可扶藜至，無因假榻眠。", "鐘魚久寂寞，誰施一囊錢。"]'),
('771d42f7-a141-4c5a-833a-3c96ffd7a51d','寶應寺','曾季貍','宋','宋诗','song-poetry','','[]','檀心素面水沉香，一架清陰滿院凉。',32,'全唐诗/poet.song.127000.json','["檀心素面水沉香，一架清陰滿院凉。", "莫道春歸無覓處，春歸却在贊公房。"]'),
('e36a9873-2c96-4c5a-826c-af6df70d80f6','宿正覺寺','曾季貍','宋','宋诗','song-poetry','','[]','月落僧窗暗，衾單客夢驚。',48,'全唐诗/poet.song.127000.json','["月落僧窗暗，衾單客夢驚。", "雞鳴催客起，犬吠惡人行。", "蓐食事已畢，膏車天未明。", "畏塗饑餓歲，哪得事宵征。"]'),
('66f23150-6cac-45cf-ad32-ad8d67e92e0c','相峰寺','曾季貍','宋','宋诗','song-poetry','','[]','一燈投宿阿蘭若，雨過凉生夜氣清。',32,'全唐诗/poet.song.127000.json','["一燈投宿阿蘭若，雨過凉生夜氣清。", "何許秋聲驚客夢，簷間不斷一鈴鳴。"]'),
('525ab458-0208-4dad-821a-d12422c0a452','陪張舍人出郊','曾季貍','宋','宋诗','song-poetry','','[]','官椏千尋大，清溪五尺流。',48,'全唐诗/poet.song.127000.json','["官椏千尋大，清溪五尺流。", "眼看春事適，心與老農謀。", "節物年年好，田園事事幽。", "緩歸陪皂蓋，覓句待蘇州。"]'),
('a23fee8e-f49f-4501-9735-2760a38b13d5','句  其一','曾季貍','宋','宋诗','song-poetry','','[]','悠悠造物何所爲，賢愚共滯令人悲。',32,'全唐诗/poet.song.127000.json','["悠悠造物何所爲，賢愚共滯令人悲。", "男兒不恨功名晚，功名必在老大時。"]'),
('775fb57d-4b4b-42ce-bf6e-a1da60dd7fb7','句  其二','曾季貍','宋','宋诗','song-poetry','','[]','好事不知誰爾汝，還能郭索到樽前。',16,'全唐诗/poet.song.127000.json','["好事不知誰爾汝，還能郭索到樽前。"]'),
('143e5802-050e-4dc3-8cec-ea2c4c3312de','句  其三','曾季貍','宋','宋诗','song-poetry','','[]','甘餐不美鴆，毒終非可戒。',12,'全唐诗/poet.song.127000.json','["甘餐不美鴆，毒終非可戒。"]'),
('2a5d72d7-b4c7-45aa-8661-ba6d4f7bacba','句  其四','曾季貍','宋','宋诗','song-poetry','','[]','遠及水中蟹，直以投葅醢。',12,'全唐诗/poet.song.127000.json','["遠及水中蟹，直以投葅醢。"]'),
('1abdcee8-8ac6-4b14-8878-54a82a087d65','句  其五','曾季貍','宋','宋诗','song-poetry','','[]','故人憐我貧，走送不待買。',12,'全唐诗/poet.song.127000.json','["故人憐我貧，走送不待買。"]'),
('e8571db0-a14a-438e-8c6d-73de794691f7','句  其六','曾季貍','宋','宋诗','song-poetry','','[]','朝來蟹眼方新試，昨夜燈花早得知。',16,'全唐诗/poet.song.127000.json','["朝來蟹眼方新試，昨夜燈花早得知。"]'),
('fb9224b1-434c-44fc-88f5-1f59980d45de','句  其七','曾季貍','宋','宋诗','song-poetry','','[]','惟有山茶殊奈久，獨能探月占春風。',16,'全唐诗/poet.song.127000.json','["惟有山茶殊奈久，獨能探月占春風。"]'),
('3392d4da-4d2e-47ae-808a-304a70ed5bab','别曾學士','陸游','宋','宋诗','song-poetry','','[]','兒時聞公名，謂在千載前。',168,'全唐诗/poet.song.127000.json','["兒時聞公名，謂在千載前。", "稍長誦公文，雜之韓杜編。", "夜輒夢見公，皎若月在天。", "起坐三嘆息，欲見亡繇緣。", "忽聞高軒過，歡喜忘食眠。", "袖書拜轅下，此意私自憐。", "道若九達衢，小智妄鑿穿。", "所願瞻德容，頑固或少痊。", "公不謂狂疏，屈體與周旋。", "騎氣動原隰，霜日明山川。", "匏繫不得從，瞻望抱悁悁。", "畫石或十日，刻楮有三年。", "賤貧未即死，聞道期華顛。", "他時得公心，敢不知所傳。"]'),
('3b1701d8-65eb-47fb-90b3-bafa337befb0','送仲高兄宫學秩滿赴行在','陸游','宋','宋诗','song-poetry','','["\u9001\u522b", "\u89c4\u529d"]','兄去游東閤，才堪直北扉。',48,'全唐诗/poet.song.127000.json','["兄去游東閤，才堪直北扉。", "莫憂持槖晚，姑記乞身歸。", "道義無今古，功名有是非。", "臨分出苦語，不敢計從違。"]'),
('22cdc7b6-8593-4808-a08c-72506349395f','題閻郎中溧水東皋園亭','陸游','宋','宋诗','song-poetry','','[]','省中地禁清晝長，侍史深注熏籠香。',160,'全唐诗/poet.song.127000.json','["省中地禁清晝長，侍史深注熏籠香。", "榮名挽公公不住，東皋歸去栽花忙。", "毿毿華髮映朱紱，同舍半已排雲翔。", "正如少陵入嚴幕，本自不用尚書郎。", "向令封侯佩金印，不然草詔直玉堂。", "萬鍾會作夢幻過，三徑空嘆松菊荒。", "樂天十年履道宅，贊皇一夕平泉莊。", "公看富貴定何物，一笑乃復坐此妨。", "東皋樂哉日成趣，簪花起舞當自強。", "知公能容賤子狂，請賦式微之二章。"]'),
('f376c3a9-7d58-45cf-a2fe-2680979043b8','和陳魯山十詩以孟夏草木長遶屋樹扶疏爲韵  其一','陸游','宋','宋诗','song-poetry','','[]','言語日益工，風節顧弗競。',48,'全唐诗/poet.song.127000.json','["言語日益工，風節顧弗競。", "杞柳爲桮棬，此豈真物性。", "病夫背俗馳，梁甫時一詠。", "奈何七尺軀，貴賤視趙孟。"]'),
('cb0e6892-3c2a-4b78-bd05-a55e13bb61d0','和陳魯山十詩以孟夏草木長遶屋樹扶疏爲韵  其二','陸游','宋','宋诗','song-poetry','','[]','唐虞亦人耳，四海可高謝。',48,'全唐诗/poet.song.127000.json','["唐虞亦人耳，四海可高謝。", "哀哉斗升故，諂妄兩憑架。", "心明物自賓，能整故能暇。", "會當棄人事，面壁度九夏。"]'),
('8260c59c-f7de-49f4-a31c-48ea427c21b9','和陳魯山十詩以孟夏草木長遶屋樹扶疏爲韵  其三','陸游','宋','宋诗','song-poetry','','[]','大父昔在朝，騰上唯恐早。',48,'全唐诗/poet.song.127000.json','["大父昔在朝，騰上唯恐早。", "淡然清班中，灰寒而木槁。", "議論主中和，人才進耆老。", "至今下馬墳，不生刺人草。"]'),
('2691ac81-31af-4398-909f-92903bc869f5','和陳魯山十詩以孟夏草木長遶屋樹扶疏爲韵  其四','陸游','宋','宋诗','song-poetry','','[]','櫻酪事已過，角黍配夏熟。',48,'全唐诗/poet.song.127000.json','["櫻酪事已過，角黍配夏熟。", "尚憶少小時，綵縷繫腕玉。", "此生本幻戲，衰態轉眼足。", "三郎老無憀，始解嘆絲木。"]'),
('2abec948-97e3-4054-9d04-88259ccd7393','和陳魯山十詩以孟夏草木長遶屋樹扶疏爲韵  其五','陸游','宋','宋诗','song-poetry','','[]','門無容車高，庭止旋馬廣。',48,'全唐诗/poet.song.127000.json','["門無容車高，庭止旋馬廣。", "富貴固易耳，正恐卿慚長。", "時情競脂韋，家法獨骯髒。", "靜處看紛紛，桔槔勞頫仰。"]'),
('85771e41-4dbc-465b-af07-d2e1a227189b','和陳魯山十詩以孟夏草木長遶屋樹扶疏爲韵  其六','陸游','宋','宋诗','song-poetry','','[]','至人貴其身，不使事物遶。',48,'全唐诗/poet.song.127000.json','["至人貴其身，不使事物遶。", "捐身易富貴，明珠彈飛鳥。", "我願稱善人，題作墓上表。", "從來尺鷃樂，不羨飛鴻矯。"]'),
('69a8c9f1-9d15-49b2-ae1b-ad7cd093a2ee','和陳魯山十詩以孟夏草木長遶屋樹扶疏爲韵  其七','陸游','宋','宋诗','song-poetry','','[]','匆匆過三十，夢境日已蹙。',48,'全唐诗/poet.song.127000.json','["匆匆過三十，夢境日已蹙。", "誰知嘆亡羊，但有喜得鹿。", "本來作何面，認此逆旅屋。", "逢人吹布毛，出世不忍獨。"]'),
('a4cbc77d-e73a-4ef1-ac55-44be2317da96','和陳魯山十詩以孟夏草木長遶屋樹扶疏爲韵  其八','陸游','宋','宋诗','song-poetry','','[]','杜門殊省事，百巧輸一粗。',48,'全唐诗/poet.song.127000.json','["杜門殊省事，百巧輸一粗。", "燒香淨掃地，袖手了朝暮。", "君看瓦摳手，端自勝金注。", "塵機早見貸，不待雞竿樹。"]'),
('5812124c-3570-48a8-9e47-449834ffae15','和陳魯山十詩以孟夏草木長遶屋樹扶疏爲韵  其九','陸游','宋','宋诗','song-poetry','','[]','萬物備於我，本來無欠餘。',48,'全唐诗/poet.song.127000.json','["萬物備於我，本來無欠餘。", "寠儒可憐生，西抺復東塗。", "斯文如大厦，傾壞要力扶。", "犬子真鼠輩，辛苦賣子虚。"]'),
('9290f44a-ecbb-4008-b48e-ccfa14a7ffeb','和陳魯山十詩以孟夏草木長遶屋樹扶疏爲韵  其一○','陸游','宋','宋诗','song-poetry','','[]','風花憐寂寞，起舞爲我娛。',48,'全唐诗/poet.song.127000.json','["風花憐寂寞，起舞爲我娛。", "舉酒謝風花，吾道殊不疏。", "汝開何自有，汝落何自無。", "居然會此理，吾汝皆如如。"]'),
('3b0c2583-4795-45a7-8685-3c277f74167b','看梅絕句五首  其一','陸游','宋','宋诗','song-poetry','','[]','梅花宜寒更宜陰，摩挲拄杖過溪尋。',32,'全唐诗/poet.song.127000.json','["梅花宜寒更宜陰，摩挲拄杖過溪尋。", "幽香著人索管領，不信如今鐡石心。"]'),
('1e2cbd4e-6f46-4515-bcee-6d751fe5c04c','看梅絕句五首  其二','陸游','宋','宋诗','song-poetry','','[]','梅花樹下黄茆丘，古人尚能愛花不。',32,'全唐诗/poet.song.127000.json','["梅花樹下黄茆丘，古人尚能愛花不。", "月淡烟深聽牧笛，死生常事不須愁。"]'),
('fbc86160-8b33-4a5b-82b1-838c2dad410b','看梅絕句五首  其三','陸游','宋','宋诗','song-poetry','','[]','荒陂十畆浴鳬鴨，折葦枯蒲寒意深。',32,'全唐诗/poet.song.127000.json','["荒陂十畆浴鳬鴨，折葦枯蒲寒意深。", "何處得船滿載酒，醉時繫著古梅林。"]'),
('bcb7b76c-2b94-4ca8-8d8d-e5cc3b0f3bfa','看梅絕句五首  其四','陸游','宋','宋诗','song-poetry','','[]','一物不向胸次横，醉中談謔坐中傾。',32,'全唐诗/poet.song.127000.json','["一物不向胸次横，醉中談謔坐中傾。", "梅花有情應記得，可惜如今白髮生。"]'),
('b24a1fde-1fe6-4255-a4ef-567946d7e83b','看梅絕句五首  其五','陸游','宋','宋诗','song-poetry','','["\u7231\u56fd", "\u6292\u60c5", "\u6885\u82b1", "\u82b1", "\u5199\u82b1"]','老子舞時不須拍，梅花亂插烏巾香。',32,'全唐诗/poet.song.127000.json','["老子舞時不須拍，梅花亂插烏巾香。", "尊前作劇莫相笑，我死諸君思此狂。"]'),
('a7256eb6-42ec-491c-88aa-43135f93015a','春晚簡陳魯山','陸游','宋','宋诗','song-poetry','','[]','春工我輩人，可許不待面。',96,'全唐诗/poet.song.127000.json','["春工我輩人，可許不待面。", "欲老更增奇，原野紅緑遍。", "向來苦摧傷，零雨雜飛霰。", "豈知袖此手，天定乃徐見。", "吾齋萬花間，輕衫稱團扇。", "飛花點書冊，戲蝶遊几研。", "吾衰未忘情，小句亦倩絢。", "持問陳元龍，試乞語一轉。"]'),
('130b5d79-6c74-42b5-9d7f-4bb4aded419f','寄酬曾學士學宛陵先生體比得書云所寓廣教僧舍有陸子泉每對之輒奉懷','陸游','宋','宋诗','song-poetry','','[]','庭中下乾鵲，門外傳遠書。',240,'全唐诗/poet.song.127000.json','["庭中下乾鵲，門外傳遠書。", "小印紅屈蟠，兩端黄蠟塗。", "開緘展矮紙，滑細疑卵膚。", "首言勞良苦，後問逮妻孥。", "中間勉以仕，語意極勤渠。", "字如老瘠竹，墨淡行疏疏。", "詩如古鼎篆，可愛不可摹。", "快讀醒人意，垢癢逢爬梳。", "細讀味益長，炙轂出膏腴。", "行吟坐臥看，廢食至日晡。", "想見落筆時，萬象聽指呼。", "亦知題詩處，緑井石髮粗。", "公閑計有客，煎茶置風爐。", "倘公無客時，濯纓亦足娛。", "井名本季疵，思人理豈無。", "居然及賤子，愧謝恩意殊。", "幾時得從公，舊學鋤荒蕪。", "古文講聲形，誤字辨魯魚。", "時時酌井泉，露芽奉瓢盂。", "不知公許否，因風報何如。"]'),
('620a149e-403a-4014-909c-753efc6e23df','夜讀兵書','陸游','宋','宋诗','song-poetry','','[]','孤燈耿霜夕，窮山讀兵書。',72,'全唐诗/poet.song.127000.json','["孤燈耿霜夕，窮山讀兵書。", "平生萬里心，執戈王前驅。", "戰死士所有，恥復守妻孥。", "成功亦邂逅，逆料政自疏。", "陂澤號饑鴻，歲月欺貧儒。", "嘆息鏡中面，安得長膚腴。"]'),
('7e47674a-1432-4700-bb8b-a498c5287fbb','二月二十四日作','陸游','宋','宋诗','song-poetry','','["\u5fe7\u56fd\u5fe7\u6c11", "\u8bb0\u4e8b", "\u519c\u6751"]','棠梨花開社酒濃，南村北村鼓鼕鼕。',64,'全唐诗/poet.song.127000.json','["棠梨花開社酒濃，南村北村鼓鼕鼕。", "且祈麥熟得飽飰，敢說穀賤復傷農。", "崖州萬里竄酷吏，湖南幾時起臥龍。", "但願諸賢集廊廟，書生窮死勝侯封。"]'),
('fb21cdb5-8789-4af9-a57c-63d72e01f8ce','送曾學士赴行在','陸游','宋','宋诗','song-poetry','','[]','二月侍燕觴，紅杏寒未坼。',216,'全唐诗/poet.song.127000.json','["二月侍燕觴，紅杏寒未坼。", "四月送入都，杏子已可摘。", "流年不貸人，俯仰遂成昔。", "事賢要及時，感此我心惻。", "欲書加餐字，寄之西飛翮。", "念公爲民起，我得怨乖隔。", "揺揺跂前旌，去去望車軛。", "亭鄣鬱將暮，落日澹陂澤。", "敢忘國士風，涕泣效臧獲。", "敬輸千一慮，或取二三策。", "公歸對延英，清問方側席。", "民瘼公所知，願言寫肝膈。", "向來酷吏横，至今有遺螫。", "織羅士破膽，白著民碎魄。", "詔書已屢下，宿蠧或未革。", "期公作醫和，湯劑窮絡脈。", "士生恨不用，得位忍辭責。", "併乞謝諸賢，努力光竹帛。"]'),
('7f9c5832-45d8-4c48-9f8d-82169507d596','霽夜觀月','陸游','宋','宋诗','song-poetry','','[]','雲重真愁無散時，可憐不奈一風吹。',32,'全唐诗/poet.song.127000.json','["雲重真愁無散時，可憐不奈一風吹。", "清輝如此那休得，誰悞虚空作許癡。"]'),
('406f5390-f0af-4375-8340-a0f0725ac92d','新夏感事','陸游','宋','宋诗','song-poetry','','[]','百花過盡緑陰成，漠漠爐香睡晚晴。',64,'全唐诗/poet.song.127000.json','["百花過盡緑陰成，漠漠爐香睡晚晴。", "病起兼旬疏把酒，山深四月始聞鶯。", "近傳下詔通言路，已卜餘年見太平。", "聖主不忘初政美，小儒唯有涕縱横。"]'),
('8ad87123-d9d4-4b04-b9c0-aa2023d068c4','留題雲門草堂','陸游','宋','宋诗','song-poetry','','[]','小住初爲旬月期，二年留滯未應非。',64,'全唐诗/poet.song.127000.json','["小住初爲旬月期，二年留滯未應非。", "尋碑野寺雲生屨，送客溪橋雪滿衣。", "親滌硯池餘墨漬，臥看爐面散烟霏。", "他年遊宦應無此，早買漁蓑未老歸。"]'),
('94bdcb6d-5aae-4275-a724-979752953659','送韓梓秀才十八韵','陸游','宋','宋诗','song-poetry','','[]','束髮走塲屋，始得從君遊。',216,'全唐诗/poet.song.127000.json','["束髮走塲屋，始得從君遊。", "燈火都城夜，風雨湖上秋。", "追隨不隔日，巖壑窮探搜。", "摩挲石屋背，揺兀闇門舟。", "酒酣耳頰熱，意氣蓋九州。", "夜臥相蹋語，狂笑雜嘲謳。", "但恐富貴逼，肯懷貧賤憂。", "人事信難料，百戰竟不侯。", "我老農圃間，君落天南陬。", "相逢會稽市，感嘆歲月遒。", "君從上都來，倘逢舊朋儔。", "我窮本天命，於人寜有求。", "但念侯君房，不知尚癡不。", "君聞拊手笑，怪我狂未瘳。", "共談平生舊，只欲苦死留。", "如何忽決去，病瘧送無由。", "秋風墜桐葉，新霜犯貂裘。", "君聽馬蹄聲，中有千里愁。"]'),
('356d340c-e3f7-4e82-ab5f-960d19b28e6e','送陳德邵宫教赴行在二十韵','陸游','宋','宋诗','song-poetry','','[]','相從何必早，白頭或如新。',240,'全唐诗/poet.song.127000.json','["相從何必早，白頭或如新。", "登門雖尚疏，數面自成親。", "昨者始見公，凜然鬚如銀。", "敗席留煮茗，寒廳無雜賓。", "平生事賢意，寸心渴生塵。", "樂哉得所從，貧病忘吟呻。", "恭惟大雅姿，信是邦國珍。", "廣文舊官長，二紀轉鴻鈞。", "恩仇快報復，禍福出笑顰。", "同舍事容悦，腰佩玉麒麟。", "群諛更得志，後來如積薪。", "於時公淡如，位屈道則伸。", "法宫親決事，收召極海濱。", "人才方雜沓，公仕益逡巡。", "欲以貴祝公，公豈慕要津。", "欲以窮託公，公豈私賤貧。", "頗欲述古誼，勸公勿愛身。", "此又公所存，豈待賤子陳。", "高颿泊江渚，歲晚風雨頻。", "願言添衣裘，寒陰能薄人。"]'),
('33b4dd28-27c0-440d-b5c3-fc1d7c50ce4d','朱子雲園中觀花','陸游','宋','宋诗','song-poetry','','[]','我鬢忽已白，君顔非復朱。',96,'全唐诗/poet.song.127000.json','["我鬢忽已白，君顔非復朱。", "花前一杯酒，不樂復何如。", "暮看枝上花，已覺不如早。", "富貴當及時，吾輩奈何老。", "我歌君起舞，竟日爲君留。", "安知花無情，不解替人愁。", "長安二三月，花滿上林中。", "祝君早得意，歸轡聽璁瓏。"]'),
('2d778a8d-c9e5-4b6e-a799-b12eec32b04c','酬妙湛闍梨見贈妙湛能棋其師璘公蓋嘗與先君遊云','陸游','宋','宋诗','song-poetry','','[]','昔侍先君故里時，僧中最喜老璘師。',64,'全唐诗/poet.song.127000.json','["昔侍先君故里時，僧中最喜老璘師。", "高標無復鄉人識，妙寄惟應弟子知。", "山店煎茶留小語，寺橋看雨待幽期。", "可人不但詩超絕，玉子紋枰又一奇。"]'),
('c2701754-e7ef-445d-94b6-a9d4e17e9232','次韵魯山新居絕句二首  其一','陸游','宋','宋诗','song-poetry','','[]','求得軒車心愧天，不如窮死却陶然。',32,'全唐诗/poet.song.127000.json','["求得軒車心愧天，不如窮死却陶然。", "君曾布衣尚可活，那有日興須萬錢。"]'),
('c79baf58-c656-41b2-8ed3-cf9cf680aa80','次韵魯山新居絕句二首  其二','陸游','宋','宋诗','song-poetry','','[]','短牆缺處插疏籬，巷劣容車堂對陂。',32,'全唐诗/poet.song.127000.json','["短牆缺處插疏籬，巷劣容車堂對陂。", "天下有公殊可賀，坐中著我不妨奇。"]'),
('00df2b4c-ec56-4b16-bc6e-8fc6e7681f79','寄陳魯山二首  其一','陸游','宋','宋诗','song-poetry','','[]','諸公貴人識面稀，胸中璀璨漫珠璣。',64,'全唐诗/poet.song.127000.json','["諸公貴人識面稀，胸中璀璨漫珠璣。", "即今舉手遮西日，應有流塵化素衣。", "舊學極知難少貶，吾儕持此欲安歸。", "夜來風雨空堂靜，忽憶燈前語入微。"]'),
('5ddd5058-84bb-4691-b13d-e411b822ad79','寄陳魯山二首  其二','陸游','宋','宋诗','song-poetry','','[]','天下無虞國論深，書生端合老山林。',64,'全唐诗/poet.song.127000.json','["天下無虞國論深，書生端合老山林。", "平生力學所得處，政要如今不動心。", "舊友幾年猶短褐，謫官萬里少來音。", "願公思此寬羈旅，靜勝炎曦豈易侵。"]'),
('c76869b6-436c-4cfb-af8d-21ae81746c62','戲題江心寺僧房壁','陸游','宋','宋诗','song-poetry','','[]','史君千騎駐霜天，主簿孤舟冷不眠。',32,'全唐诗/poet.song.127000.json','["史君千騎駐霜天，主簿孤舟冷不眠。", "也與史君同快意，臥聽鼓角大江邊。"]'),
('c1322235-a93b-492f-be46-ba755aee7a71','泛瑞安江風濤貼然','陸游','宋','宋诗','song-poetry','','[]','俯仰兩青空，舟行明鏡中。',24,'全唐诗/poet.song.127000.json','["俯仰兩青空，舟行明鏡中。", "蓬萊定不遠，正要一颿風。"]'),
('05fb3962-16a7-42e2-8586-1c3b6921b623','平陽驛舍梅花','陸游','宋','宋诗','song-poetry','','[]','江路輕陰未成雨，梅花欲過半沾泥。',32,'全唐诗/poet.song.127000.json','["江路輕陰未成雨，梅花欲過半沾泥。", "遠來不負東皇意，一絕清詩手自題。"]'),
('3f49cf1a-b102-4c6c-ada1-69158b704069','度浮橋至南臺','陸游','宋','宋诗','song-poetry','','[]','客中多病廢登臨，聞說南臺試一尋。',64,'全唐诗/poet.song.127000.json','["客中多病廢登臨，聞說南臺試一尋。", "九軌徐行怒濤上，千艘横繫大江心。", "寺樓鐘鼓催昏曉，墟落雲烟自古今。", "白髮未除豪氣在，醉吹横笛坐榕陰。"]'),
('b81a156b-d134-4c40-906f-8b3a1410c9ae','出縣','陸游','宋','宋诗','song-poetry','','[]','匆匆簿領不堪論，出宿聊寬久客魂。',64,'全唐诗/poet.song.127000.json','["匆匆簿領不堪論，出宿聊寬久客魂。", "稻壟牛行泥活活，野塘橋壞雨昏昏。", "槿籬護藥纔通徑，竹筧分泉自遍村。", "歸計未成留亦好，愁腸不用遶吳門。"]'),
('2539e977-218e-4ddb-b924-4fd0ad424bd1','還縣','陸游','宋','宋诗','song-poetry','','[]','霽色清和日已長，綸巾蕭散意差強。',64,'全唐诗/poet.song.127000.json','["霽色清和日已長，綸巾蕭散意差強。", "飛飛鷗鷺陂塘緑，鬱鬱桑麻風露香。", "南陌東村初過社，輕裝小隊似還鄉。", "哦詩忘却登車去，枉是人言作吏忙。"]'),
('61f36fd0-90ac-42ba-81cd-b46c5f854b0d','雨晴遊洞宫山天慶觀坐間復雨','陸游','宋','宋诗','song-poetry','','[]','近水松篁鎖翠微，洞天宫殿對清暉。',64,'全唐诗/poet.song.127000.json','["近水松篁鎖翠微，洞天宫殿對清暉。", "快晴似爲酴醿計，急雨還妨燕子飛。", "道士晝閑丹竈冷，山童曉出藥苗肥。", "拂床不用勤留客，我困文書自怕歸。"]'),
('2e3223a1-72a1-48ab-9044-0126d6a10b63','寄陳魯山正字','陸游','宋','宋诗','song-poetry','','[]','平生交遊中，陳子我所敬。',120,'全唐诗/poet.song.127000.json','["平生交遊中，陳子我所敬。", "初猶似豪舉，晚乃抱淵靜。", "獨觀心地初，皎若虚室鏡。", "人知自渠事，道行君有命。", "青衫二十年，老色上鬚鬢。", "偶然預收召，瘦馬趁朝請。", "退食輒杜門，不省求捷徑。", "似聞石渠書，雌黄久未定。", "丁字猶恨曲，朋字竟須正。", "願君試思之，魚魯何足訂。"]'),
('3ec69f1f-0684-46b0-99e5-04905a48f198','航海','陸游','宋','宋诗','song-poetry','','[]','我不如列子，神遊御天風。',96,'全唐诗/poet.song.127000.json','["我不如列子，神遊御天風。", "尚應似安石，悠然雲海中。", "臥看十幅蒲，彎彎若張弓。", "潮來湧銀山，忽復磨青銅。", "饑鶻掠船舷，大魚舞虚空。", "流落何足道，豪氣蕩肺胸。", "歌罷海動色，詩成天改容。", "行矣跨鵬背，弭節蓬萊宫。"]'),
('42d829c9-8b8d-4236-b4aa-e08eec2707f5','海中醉題時雷雨初霽天水相接也','陸游','宋','宋诗','song-poetry','','[]','羈遊那復恨，奇觀有南溟。',48,'全唐诗/poet.song.127000.json','["羈遊那復恨，奇觀有南溟。", "浪蹴半空白，天浮無盡青。", "吐吞交日月，澒洞戰雷霆。", "醉後吹横笛，魚龍亦出聽。"]'),
('61df99f0-9ebe-41b8-aff0-c67f36015d2a','溪行二首  其一','陸游','宋','宋诗','song-poetry','','[]','蓬蒻鳴春雨，帆蒲挂暮烟。',48,'全唐诗/poet.song.127000.json','["蓬蒻鳴春雨，帆蒲挂暮烟。", "買魚尋近市，覓火就鄰船。", "愁臥醒還醉，灘行却復前。", "長年殊可念，力盡逆風牽。"]'),
('dba2169c-ee13-4efc-a0f0-96e27621a7fb','溪行二首  其二','陸游','宋','宋诗','song-poetry','','[]','冒雨牽何急，爭風力不餘。',48,'全唐诗/poet.song.127000.json','["冒雨牽何急，爭風力不餘。", "逢人問虛市，計日買薪蔬。", "烟寺高旛出，山畬一老鋤。", "枕書醒醉裏，短髮不曾梳。"]'),
('ffb80841-042f-4cf2-a4e5-5df5c708df05','自來福州詩酒殆廢北歸始稍稍復飲至永嘉括蒼無日不醉詩亦屢作此事不可不記也','陸游','宋','宋诗','song-poetry','','[]','尊酒如江緑，春愁抵草長。',48,'全唐诗/poet.song.127000.json','["尊酒如江緑，春愁抵草長。", "但令閑一日，便擬醉千場。", "柳弱風禁絮，花殘雨漬香。", "客遊還役役，心賞竟茫茫。"]'),
('ea1b3384-d89b-466e-827c-06aa78508c38','東陽道中','陸游','宋','宋诗','song-poetry','','[]','風欹烏帽送輕寒，雨點春衫作碎斑。',32,'全唐诗/poet.song.127000.json','["風欹烏帽送輕寒，雨點春衫作碎斑。", "小吏知人當著句，先安筆硯對溪山。"]'),
('b3f1015a-ee66-4df5-b5db-cf5e66ca5db9','東陽觀酴醿','陸游','宋','宋诗','song-poetry','','[]','福州正月把離杯，已見酴醿壓架開。',32,'全唐诗/poet.song.127000.json','["福州正月把離杯，已見酴醿壓架開。", "吳地春寒花漸晚，北歸一路摘香來。"]'),
('5eec2dad-dd1a-4d81-903f-c75e43e331a4','送李德遠寺丞奉祠歸臨川','陸游','宋','宋诗','song-poetry','','[]','送騎擁東城，烟帆如鳥輕。',48,'全唐诗/poet.song.127000.json','["送騎擁東城，烟帆如鳥輕。", "道行端有命，身隱更須名。", "旰食煩明主，塵沙暗舊京。", "臨分一襟泪，不獨爲交情。"]'),
('e4728e57-fb5e-4b00-a5f9-90b46147fbba','送王嘉叟編修出佐南昌','陸游','宋','宋诗','song-poetry','','[]','玉殿求衣早，鸞臺退食遲。',48,'全唐诗/poet.song.127000.json','["玉殿求衣早，鸞臺退食遲。", "君看多故日，寜是棄言時。", "小作南州計，方觀急詔追。", "歸來上霄漢，莫遣此心移。"]'),
('a73ade79-8300-4c2d-9ad0-3bbc31ba3b3e','送王龜齡著作赴會稽大宗丞二首  其一','陸游','宋','宋诗','song-poetry','','[]','有越逾千載，何人不宦遊。',48,'全唐诗/poet.song.127000.json','["有越逾千載，何人不宦遊。", "向來惟一范，真足壯吾州。", "高躅今誰繼，先生獨再留。", "登堂吊興廢，想像氣横秋。"]'),
('574786ed-7931-4a09-a7de-8a6be821e774','送王龜齡著作赴會稽大宗丞二首  其二','陸游','宋','宋诗','song-poetry','','[]','大將上兵符，軍容備掃除。',48,'全唐诗/poet.song.127000.json','["大將上兵符，軍容備掃除。", "恭惟陛下聖，方采直臣書。", "忽報分司去，還尋入幕初。", "宗藩雖舊識，莫遣得親疏。"]'),
('8cfa53bb-ccd5-4496-a781-1dbc9b28ebe8','送杜起莘殿院出守遂寜','陸游','宋','宋诗','song-poetry','','[]','羽檄聨翩晝夜馳，臣憂顧不在邊陲。',64,'全唐诗/poet.song.127000.json','["羽檄聨翩晝夜馳，臣憂顧不在邊陲。", "軍容地密寜當議，陛下恩深不忍欺。", "白簡萬言幾慟哭，青編一傳可前知。", "平生所學今無負，未嘆還鄉兩鬢絲。"]'),
('5409192f-dfd4-4032-be3f-ada9411b20d3','和曾待制遊兩山三首 題育王山明月堂','陸游','宋','宋诗','song-poetry','','[]','翰林碑立崔嵬上，待制詩題杳靄間。',32,'全唐诗/poet.song.127000.json','["翰林碑立崔嵬上，待制詩題杳靄間。", "人天八萬四千塔，便合推爲第一山。"]'),
('b3bb81ca-cbed-4507-9213-940b8ccb577f','和曾待制遊兩山三首 題天章山宿鷺亭','陸游','宋','宋诗','song-poetry','','[]','疏鐘迎客到溪亭，碧瓦朱欄相照明。',32,'全唐诗/poet.song.127000.json','["疏鐘迎客到溪亭，碧瓦朱欄相照明。", "想得松陰排萬衲，籃輿放處恰詩成。"]'),
('6fb7189f-3754-44e8-8aa7-5b03e6161b2e','和曾待制遊兩山三首 題天章山更幽亭且以未到玲瓏爲恨','陸游','宋','宋诗','song-poetry','','[]','攀石捫蘿到更幽，玲瓏咫尺懶窮搜。',32,'全唐诗/poet.song.127000.json','["攀石捫蘿到更幽，玲瓏咫尺懶窮搜。", "旁人不會當時意，爲欠門生作伴遊。"]'),
('b1476223-d12b-4fb3-882e-df6f55444569','雨中出遊夜歸','陸游','宋','宋诗','song-poetry','','[]','小雨南山路，今朝思出遊。',48,'全唐诗/poet.song.127000.json','["小雨南山路，今朝思出遊。", "難從子規請，寜遣竹雞憂。", "野店寒饒柿，烟津晚喚舟。", "歸來對燈火，未恨濕衣裘。"]'),
('e3976fad-d3e4-4c13-9eee-00da1ed43b3a','謝李平叔郎中問疾','陸游','宋','宋诗','song-poetry','','[]','吏部朝回早，幽人病始蘇。',48,'全唐诗/poet.song.127000.json','["吏部朝回早，幽人病始蘇。", "過門迂問訊，欹枕聽傳呼。", "緣瘦重裁帽，因衰學染鬚。", "投詩發公笑，試想此形模。"]'),
('e6d5c538-a103-4a19-ad44-76285f72e0fc','聞武均州報已復西京','陸游','宋','宋诗','song-poetry','','["\u559c\u60a6", "\u6218\u4e89", "\u6292\u6000"]','白髮將軍亦壯哉，西京昨夜捷書來。',64,'全唐诗/poet.song.127000.json','["白髮將軍亦壯哉，西京昨夜捷書來。", "胡兒敢作千年計，天意寜知一日回。", "列聖仁恩深雨露，中興赦令疾風雷。", "懸知寒食朝陵使，驛路梨花處處開。"]'),
('0ca69435-77ea-46dc-a245-9d38d429dad8','喜小兒輩到行在','陸游','宋','宋诗','song-poetry','','[]','阿綱學書蚓滿幅，阿繪學語鶯囀木。',96,'全唐诗/poet.song.127000.json','["阿綱學書蚓滿幅，阿繪學語鶯囀木。", "截竹作馬走不休，小車駕羊聲陸續。", "書窗涴壁誰忍嗔，啼呼也復可憐人。", "却思胡馬飲江水，敢道春風無戰塵。", "傳聞賊棄兩京走，列城爭爲朝廷守。", "從今父子見太平，花前飲水勿飲酒。"]'),
('b6b4d219-7fed-4b53-a445-cf3878090cde','病起寄曾原伯兄弟','陸游','宋','宋诗','song-poetry','','[]','意象殊非昨，筋骸劣自持。',48,'全唐诗/poet.song.127000.json','["意象殊非昨，筋骸劣自持。", "衰如霜後木，愁抵盎中絲。", "風雪書來少，江山夢到遲。", "出門還惘惘，倚杖獨移時。"]'),
('fe62d8ce-c77d-46f3-a5e6-c65823d803a2','送湯岐公鎮會稽','陸游','宋','宋诗','song-poetry','','[]','吳越東西州，浙江限其中。',192,'全唐诗/poet.song.127000.json','["吳越東西州，浙江限其中。", "黄旗高十丈，大舟凌虚空。", "都人送留守，郡吏迎相公。", "江心波濤壯，帳下鼓角雄。", "樂哉公何憾，廷論則未同。", "永懷前年秋，群胡方嘯凶。", "閭左發薊北，戈船滿山東。", "舊盟顧未解，誰敢嬰其鋒。", "公時立殿上，措置極雍容。", "南荒竄驕將，京口起元戎。", "舊勲與宿貴，屏氣聽指蹤。", "規模一朝定，強虜終歸窮。", "當時謂易耳，未見回天功。", "及今始大服，咨嗟到兒童。", "天心佑社稷，主聖肖祖宗。", "旌節早來朝，笑談折遐衝。"]'),
('27109a1d-f417-44cb-9467-e50b5183c5b5','周洪道學士許折贈館中海棠以詩督之','陸游','宋','宋诗','song-poetry','','[]','嫋嫋柔絲不自持，更禁日炙與風吹。',32,'全唐诗/poet.song.127000.json','["嫋嫋柔絲不自持，更禁日炙與風吹。", "仙家見慣渾閑事，乞與人間看一枝。"]'),
('b3a8a881-f41c-4aab-a750-d26e1258b7e3','送七兄赴楊州帥幕','陸游','宋','宋诗','song-poetry','','["\u9001\u522b", "\u5fe7\u56fd", "\u5199\u666f"]','初報邊烽照石頭，旋聞胡馬集瓜州。',64,'全唐诗/poet.song.127000.json','["初報邊烽照石頭，旋聞胡馬集瓜州。", "諸公誰聽芻蕘策，吾輩空懷畎畆憂。", "急雪打窗心共碎，危樓望遠涕俱流。", "豈知今日淮南路，亂絮飛花送客舟。"]'),
('b07752f3-981e-4ea5-b94d-27d1d9a43fdb','閏二月二十日遊西湖','陸游','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖二月遊人稠，鮮車快馬巷無留。',112,'全唐诗/poet.song.127000.json','["西湖二月遊人稠，鮮車快馬巷無留。", "梨園樂工教坊優，絲竹悲激雜清謳。", "追逐下上暮始休，外雖狂酲樂則不。", "豈知吾曹淡相求，酒肴取具非預謀。", "青梅苦筍助獻酬，意象簡樸足鎮浮。", "尚慚一官自拘囚，未免疋馬從兩騶。", "南山老翁亦出遊，百錢自挂竹杖頭。"]'),
('6c9504d9-edab-49e3-bba4-80315bbca06e','劉太尉挽歌辭二首  其一','陸游','宋','宋诗','song-poetry','','[]','羌胡忘覆育，師旅備非常。',48,'全唐诗/poet.song.127000.json','["羌胡忘覆育，師旅備非常。", "南服更旄節，中軍鑄印章。", "馳書諭燕趙，開府冠侯王。", "赫赫今何在，門庭冷似霜。"]'),
('6081be50-c164-4b74-a741-f7e25510ee02','劉太尉挽歌辭二首  其二','陸游','宋','宋诗','song-poetry','','[]','堅壁臨江日，人疑制敵疏。',48,'全唐诗/poet.song.127000.json','["堅壁臨江日，人疑制敵疏。", "安知百萬虜，鋭盡浹旬餘。", "智出常情表，功如定計初。", "云何媢公者，不置篋中書。"]'),
('bedce2e1-2f17-4b1c-9b35-551b4ecb67e3','過林黄中食柑子有感學宛陵先生體','陸游','宋','宋诗','song-poetry','','[]','博士得黄柑，甚愛不忍擘。',168,'全唐诗/poet.song.127000.json','["博士得黄柑，甚愛不忍擘。", "持獻太夫人，遠附海上舶。", "故山饒氛霧，可使酒杯窄。", "豈無荔枝好，饜飫恐不摘。", "相去三千里，無異娛旁側。", "乃知母子意，更遠未嘗隔。", "我昨往見君，從容弄書冊。", "藥分臘劑香，茶泛春芽白。", "主意顧未厭，筐筥自搜索。", "敢謂甘旨餘，亦及此下客。", "霜包纔三四，氣可壓千百。", "重是慈孝物，不敢吐其核。", "甘寒雖遶齒，悲感已横臆。", "半生無歡娛，初不爲湮阨。"]'),
('0b1d532b-d2e6-4f33-8276-70116da4bdc9','玉牒所迎駕望見周洪道舍人','陸游','宋','宋诗','song-poetry','','[]','自卜河橋宅，清談喜屢陪。',48,'全唐诗/poet.song.127000.json','["自卜河橋宅，清談喜屢陪。", "今年見騰踔，不恨老氛埃。", "曉放宫門鑰，霜彫輦路槐。", "班回獨小立，爲待繡鞍來。"]'),
('bafb9a88-3cd8-4727-b1e5-dea68882ffff','送梁諫議','陸游','宋','宋诗','song-poetry','','[]','湖海還朝白髮生，懶隨年少事聲名。',64,'全唐诗/poet.song.127000.json','["湖海還朝白髮生，懶隨年少事聲名。", "極知憂國人誰及，細看無心語自平。", "歸訪鄉人忘位重，乍辭言責覺身輕。", "籃輿避暑雲門寺，應過幽居聽水聲。"]'),
('0d7eddfb-0944-4de6-aa64-842c9387530a','以石芥送劉韶美禮部劉比釀酒勁甚因以爲戲二首  其一','陸游','宋','宋诗','song-poetry','','[]','古人重改陽城驛，吾輩欣聞石芥名。',32,'全唐诗/poet.song.127000.json','["古人重改陽城驛，吾輩欣聞石芥名。", "風味可人終骨骾，尊前真見魯諸生。"]'),
('e98c1b18-0659-423b-a92b-5dec6cae715b','以石芥送劉韶美禮部劉比釀酒勁甚因以爲戲二首  其二','陸游','宋','宋诗','song-poetry','','[]','長安官酒甜如蜜，風月雖佳懶舉觴。',32,'全唐诗/poet.song.127000.json','["長安官酒甜如蜜，風月雖佳懶舉觴。", "持送盤蔬還會否，與公新釀鬭端方。"]'),
('f5b7ba53-910b-4ff0-8579-08b3a1859b6e','出都','陸游','宋','宋诗','song-poetry','','[]','重入修門甫歲餘，又攜琴劍返江湖。',64,'全唐诗/poet.song.127000.json','["重入修門甫歲餘，又攜琴劍返江湖。", "乾坤浩浩何由報，犬馬區區正自愚。", "緣熟且爲蓮社客，伻來喜對草堂圖。", "西廂屋了吾真足，高枕看雲一事無。"]'),
('bd058d98-3b7d-410e-b1a2-939fc8052010','曾原伯屢勸居城中而僕方欲自梅山入雲門今日病酒偶得長句奉寄','陸游','宋','宋诗','song-poetry','','[]','借得僧房似釣船，兼旬散髮醉江天。',64,'全唐诗/poet.song.127000.json','["借得僧房似釣船，兼旬散髮醉江天。", "酒能作病真如此，窮乃工詩却未然。", "閑似白鷗雖自許，健如黄犢已無緣。", "秋高更欲移家去，先葺雲門屋數椽。"]'),
('d7453fe0-0fbc-4e0c-9608-647078ee5655','村居','陸游','宋','宋诗','song-poetry','','[]','富貴功名不擬論，且浮舴艋寄烟村。',64,'全唐诗/poet.song.127000.json','["富貴功名不擬論，且浮舴艋寄烟村。", "生憎快馬隨鞭影，寜作癡人記劍痕。", "樵牧相諳欲爭席，比鄰漸熟約論婚。", "晨舂夜績吾家舊，正要遺風付子孫。"]'),
('c1a3c29b-4ba6-431b-bc0f-455227fdfb68','看山','陸游','宋','宋诗','song-poetry','','[]','小葺茆茨紫翠間，今年偷得半年閑。',32,'全唐诗/poet.song.127000.json','["小葺茆茨紫翠間，今年偷得半年閑。", "門前木落須霜曉，且看西南一角山。"]'),
('5ad9352a-e4b3-439a-b922-4329f59ae927','夏夜泛舟書所見','陸游','宋','宋诗','song-poetry','','[]','山房猶復畏炎蒸，長掩柴門愧老僧。',64,'全唐诗/poet.song.127000.json','["山房猶復畏炎蒸，長掩柴門愧老僧。", "兩槳去揺東浦月，一龕回望上方燈。", "驚飛宿鳥時呼侣，騰起長魚有脱罾。", "夜半歸來步松影，真成赤脚踏層冰。"]'),
('b490f5fe-6bfb-46f4-bfc0-8183e3825a2c','秋陰','陸游','宋','宋诗','song-poetry','','[]','陂澤秋容淡，郊原曉氣清。',48,'全唐诗/poet.song.127000.json','["陂澤秋容淡，郊原曉氣清。", "雨來鳩有語，社近燕無情。", "拄杖扶腰痛，漁舟照眼明。", "苦吟緣病輟，隨意或詩成。"]'),
('8a9f44af-fb0b-4ac1-8b18-730c9d8c423b','盆池','陸游','宋','宋诗','song-poetry','','[]','門外江濤湧雪堆，埋盆作沼亦何哉。',32,'全唐诗/poet.song.127000.json','["門外江濤湧雪堆，埋盆作沼亦何哉。", "兒曹不解渠翁意，新脱風波嶮處來。"]'),
('2510937c-ce95-4128-8b63-6b3f7347f38f','比從人覓酒皆酸薄戲作此詩','陸游','宋','宋诗','song-poetry','','[]','酒盡聊憑折簡求，不知人要博涼州。',32,'全唐诗/poet.song.127000.json','["酒盡聊憑折簡求，不知人要博涼州。", "牆隅棄置空三嘆，露下螢飛奈此秋。"]'),
('072103ca-45ad-401d-8918-837d28903b8c','買魚二首  其一','陸游','宋','宋诗','song-poetry','','[]','臥沙細肋何由得，出水纖鱗却易求。',32,'全唐诗/poet.song.127000.json','["臥沙細肋何由得，出水纖鱗却易求。", "一夏與僧同粥飯，朝來破戒醉新秋。"]'),
('3cde0a32-0024-472e-b354-fc7b5d26370b','買魚二首  其二','陸游','宋','宋诗','song-poetry','','[]','兩京春薺論斤賣，江上鱸魚不直錢。',32,'全唐诗/poet.song.127000.json','["兩京春薺論斤賣，江上鱸魚不直錢。", "斫膾搗齏香滿屋，雨窗喚起醉中眠。"]'),
('11c896c9-d6d0-44eb-b495-7837a6cb2f1a','秋雨','陸游','宋','宋诗','song-poetry','','[]','漫道秋來雨，那無一日晴。',48,'全唐诗/poet.song.127000.json','["漫道秋來雨，那無一日晴。", "只供高枕臥，不放小窗明。", "書冊頻開闔，山瓢任濁清。", "長年諳世味，不是故逃名。"]'),
('498355ca-7b62-4743-ab0e-b21130c134ea','晨起偶題','陸游','宋','宋诗','song-poetry','','[]','城遠不聞長短更，上方鐘鼓自分明。',64,'全唐诗/poet.song.127000.json','["城遠不聞長短更，上方鐘鼓自分明。", "幽居不負秋來睡，末路偏諳世上情。", "大事豈堪重破壞，窮人難與共功名。", "風爐歙鉢生涯在，且試新寒芋糝羮。"]'),
('fa60d331-af50-4695-89c6-321c55ed1803','悲秋','陸游','宋','宋诗','song-poetry','','[]','烟草凄迷八月秋，荒村絡緯戒衣裘。',32,'全唐诗/poet.song.127000.json','["烟草凄迷八月秋，荒村絡緯戒衣裘。", "道人大欠修行力，平地閑生爾許愁。"]'),
('a8647c2a-c2ac-4e65-b109-ae8a261752c5','寄張真父舍人二首  其一','陸游','宋','宋诗','song-poetry','','[]','諸公方衮衮，無地著斯人。',48,'全唐诗/poet.song.127000.json','["諸公方衮衮，無地著斯人。", "萬里夔州守，中朝禁省臣。", "孤帆秋上峽，五馬曉班春。", "想見懷明主，登臨白髮新。"]'),
('b1a31631-fcdf-4bcd-b242-2280a91ef0ff','寄張真父舍人二首  其二','陸游','宋','宋诗','song-poetry','','[]','天上紫微省，鶯花繞直廬。',48,'全唐诗/poet.song.127000.json','["天上紫微省，鶯花繞直廬。", "逢時身鼎貴，憂國鬢先疏。", "憔悴元當棄，牽聨也得書。", "猶能下榻否，擬卜瀼西居。"]'),
('1b5f7354-e44b-4fd4-b23f-5bd4e16d0e5c','幽居','陸游','宋','宋诗','song-poetry','','[]','翳翳桑麻巷，幽幽水竹居。',48,'全唐诗/poet.song.127000.json','["翳翳桑麻巷，幽幽水竹居。", "紉縫一獠婢，樵汲兩蠻奴。", "雨挾清砧急，籬懸野蔓枯。", "鄰村有鬻子，吾敢嘆空無。"]'),
('893c33ef-099b-48d9-8d65-7e57326d058b','法寶璉師求竹軒詩','陸游','宋','宋诗','song-poetry','','[]','南軒竹色映谿光，不减吾州五月涼。',32,'全唐诗/poet.song.127000.json','["南軒竹色映谿光，不减吾州五月涼。", "猶恨秋來鷗鷺少，須君更爲築横塘。"]'),
('f9bb49fe-f1bd-4f44-ba73-719b8ce82d31','欲遊五峰不果往小詩寄瑩老','陸游','宋','宋诗','song-poetry','','[]','東來恨不見湯休，千首清詩儻許求。',32,'全唐诗/poet.song.127000.json','["東來恨不見湯休，千首清詩儻許求。", "要與茶山燈下讀，莫令侍者作蠅頭。"]'),
('a26443d2-38c3-4023-aca4-5aed81a85f9a','謝王彦光提刑見訪并送茶','陸游','宋','宋诗','song-poetry','','[]','邇英帷幄舊儒臣，肯顧荒山野水濱。',64,'全唐诗/poet.song.127000.json','["邇英帷幄舊儒臣，肯顧荒山野水濱。", "不怕客嘲輕薄尹，要令我識老成人。", "颿回鼓轉東城暮，酒冽橙香一笑新。", "遥想解酲須底物，隆興第一壑源春。"]'),
('07077994-b91f-45c3-aa75-5718e433505e','送查元章赴夔漕','陸游','宋','宋诗','song-poetry','','[]','柳色西門路，看公上馬時。',48,'全唐诗/poet.song.127000.json','["柳色西門路，看公上馬時。", "亦知非久别，不奈自成悲。", "白髮劉賓客，青衫杜拾遺。", "分留端有待，剩賦竹枝詞。"]'),
('79a35d05-292b-4a52-b8a4-555d8e5cbab8','逍遥','陸游','宋','宋诗','song-poetry','','[]','臺省諸公日造朝，放慵别駕愧逍遥。',64,'全唐诗/poet.song.127000.json','["臺省諸公日造朝，放慵别駕愧逍遥。", "州如斗大真無事，日抵年長未易消。", "午坐焚香常寂寂，晨興署字亦寥寥。", "時平更喜戈船靜，閑看城邊帯雨潮。"]'),
('690e92ce-5482-48dc-a4ba-491770751ce7','病中簡仲彌性唐克明蘇訓直','陸游','宋','宋诗','song-poetry','','[]','移疾還家暫曲肱，依然耐久北窗燈。',64,'全唐诗/poet.song.127000.json','["移疾還家暫曲肱，依然耐久北窗燈。", "心如澤國春歸雁，身是雲堂旦過僧。", "細雨佩壺尋廢寺，夕陽下馬吊荒陵。", "小留莫厭時追逐，勝社年來冷欲冰。"]'),
('5e695b14-2161-457b-b398-419c252b926c','送王景文','陸游','宋','宋诗','song-poetry','','[]','張公遂如此，海內共悲辛。',48,'全唐诗/poet.song.127000.json','["張公遂如此，海內共悲辛。", "逆胡猶遺種，皇天奪老臣。", "深知萬言策，不愧九原人。", "風雨津亭暮，辭君泪滿君。"]'),
('92a4de8e-e56d-4ed0-9a65-4c22adc3207f','送吕彦升參謀','陸游','宋','宋诗','song-poetry','','[]','楚塞蕭條久宿師，參謀承詔上丹墀。',64,'全唐诗/poet.song.127000.json','["楚塞蕭條久宿師，參謀承詔上丹墀。", "苦言到口真當發，聖度如天莫自疑。", "萬里寄聲長不達，一尊相屬豈前期。", "遥憐霜曉朝衣冷，深愧江城睡足時。"]'),
('1dde87e5-f7c3-4604-8aee-7712aaff9c0c','无咎兄郡齋燕集有詩末章見及敬次元韵','陸游','宋','宋诗','song-poetry','','[]','城樓畫角吹晚晴，梅花墮地草欲生。',224,'全唐诗/poet.song.127000.json','["城樓畫角吹晚晴，梅花墮地草欲生。", "綺盤翠杓春滿眼，我胡不樂君將行。", "君歸吾黨共增氣，往往怪我衰涕横。", "我來江干舊交少，見君不啻河之清。", "北風共愛地爐暖，西日同賞油窗明。", "微吟劇醉不知倦，坐閲漢臘逾周正。", "君文雄麗擅一世，凜凜武庫藏五兵。", "酸寒如我每自笑，顧辱刻畫爲虛聲。", "乃知好士如好色，遇合不必皆傾城。", "君方與世作水鏡，如此過許人將驚。", "千金敝帚有定價，周玉鄭鼠難強名。", "失言議罰不可緩，敬白府主浮金觥。", "君看失脚落塵土，豈復毫髮餘詩情。", "自傷但似路旁堠，雨剝風摧供送迎。"]'),
('e6f83931-d4a8-4011-a610-d6ac85041810','次韵无咎别後見寄','陸游','宋','宋诗','song-poetry','','[]','平日杯行不解辭，長亭況是送君時。',64,'全唐诗/poet.song.127000.json','["平日杯行不解辭，長亭況是送君時。", "幾行零落僧窗字，何限流傳樂府詩。", "歸思恰如重醖酒，歡情略似欲殘棋。", "龍蛇飛動無由見，坐愧文園屬思遲。"]'),
('9639351e-0f1d-4192-adc0-6233d4b0f57a','晚泊慈姥磯下二首  其一','陸游','宋','宋诗','song-poetry','','[]','山斷峭崖立，江空翠靄生。',48,'全唐诗/poet.song.127000.json','["山斷峭崖立，江空翠靄生。", "漫多來往客，不盡古今情。", "月碎知流急，風高覺笛清。", "兒曹笑老子，不睡待潮平。"]'),
('87310eab-a5e5-444e-9304-82da59539ad9','晚泊慈姥磯下二首  其二','陸游','宋','宋诗','song-poetry','','[]','慈姥磯頭月，纖纖照酒杯。',48,'全唐诗/poet.song.127000.json','["慈姥磯頭月，纖纖照酒杯。", "素秋風露重，久客鬢毛催。", "宿鳥驚還定，飛螢闔復開。", "平生四方志，老去轉悠哉。"]'),
('021737d0-567e-44ac-8907-5b0b91e3c345','七月十四夜觀月','陸游','宋','宋诗','song-poetry','','[]','不復微雲滓太清，浩然風露欲三更。',32,'全唐诗/poet.song.127000.json','["不復微雲滓太清，浩然風露欲三更。", "開簾一寄平生快，萬頃空江著月明。"]'),
('e8f8f100-f019-41ad-b368-7502eaeff44e','夜宿陽山磯將曉大雨北風甚勁俄頃行三百餘里遂抵雁翅浦','陸游','宋','宋诗','song-poetry','','[]','五更顛風吹急雨，倒海翻江洗殘暑。',160,'全唐诗/poet.song.127000.json','["五更顛風吹急雨，倒海翻江洗殘暑。", "白浪如山潑入船，家人驚怖篙師舞。", "此行十日苦滯留，我亦蘆樷厭鳴艣。", "書生快意輕性命，十丈蒲帆百夫舉。", "星馳電騖三百里，坡隴聮翩雜平楚。", "船頭風浪聲愈厲，助以長笛撾鼉鼓。", "豈惟澎湃震山嶽，直恐澒洞連后土。", "起看草木盡南靡，水鳥號鳴集洲渚。", "稽首龍公謝風伯，區區未禱煩神許。", "應知老去負壯心，戲遣窮途出豪語。"]'),
('b77982af-e449-443a-a9a4-6a9d8708639c','望江道中','陸游','宋','宋诗','song-poetry','','[]','吾道非邪來曠野，江濤如此去何之。',64,'全唐诗/poet.song.127000.json','["吾道非邪來曠野，江濤如此去何之。", "起隨烏鵲初翻後，宿及牛羊欲下時。", "風力漸添帆力健，艣聲常雜雁聲悲。", "晚來又入淮南路，紅樹青山合有詩。"]'),
('bd48ae2c-a19d-4d2b-b338-498bcbbdfa9b','秋夜讀書每以二鼓盡爲節','陸游','宋','宋诗','song-poetry','','["\u5bd2\u591c", "\u7406\u60f3", "\u8bfb\u4e66"]','腐儒碌碌嘆無奇，獨喜遺編不我欺。',64,'全唐诗/poet.song.127000.json','["腐儒碌碌嘆無奇，獨喜遺編不我欺。", "白髮無情侵老境，青燈有味似兒時。", "高梧策策傳寒意，疊鼓鼕鼕迫睡期。", "秋夜漸長饑作祟，一杯山藥進瓊糜。"]'),
('3510eda3-98c1-4232-9dc7-a0ccc6379aa8','往在都下時與鄒德章兵部同居百官宅無日不相從僕來佐豫章而德章亦謫高安感事述懷作歌奉寄','陸游','宋','宋诗','song-poetry','','[]','巷南巷北秋月明，東家西家讀書聲。',192,'全唐诗/poet.song.127000.json','["巷南巷北秋月明，東家西家讀書聲。", "官閑出局各無事，冷落往往思同盟。", "出門相尋索一笑，亦或邂逅因俱行。", "黄中掀髯語激烈，韶美堅坐書縱横。", "子充清言喜置酒，赤梨緑柿相扶檠。", "寒燈耿耿地爐暖，宫門風順聞疏更。", "故交一作霜葉散，外物已付秋毫輕。", "兩窮相遭世果有，我與鄒子俱南征。", "豫章高安本一郡，挂帆起柂無三程。", "簿書衮衮不少借，懷抱鬱鬱何由傾。", "明年君歸我亦去，早卜三畆開柴荆。", "軟紅舊路莫重蹋，二升脱粟同煨鐺。"]'),
('5c6e3a01-6fb9-462f-9955-14daf4173dac','寄答綿州楊齊伯左司','陸游','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','磊落人爲磊落州，滕王閣望越王樓。',64,'全唐诗/poet.song.127000.json','["磊落人爲磊落州，滕王閣望越王樓。", "欲憑夢去直虚語，賴有詩來寬旅愁。", "我老一官書紙尾，君行千騎試遨頭。", "遥知小寄平生快，春酒如川炙萬牛。"]'),
('a8d1b3e0-3a9f-4e64-ac08-2ff28c413a02','送全州趙都曹','陸游','宋','宋诗','song-poetry','','[]','霜葉無停聲，脂車有行色。',48,'全唐诗/poet.song.127000.json','["霜葉無停聲，脂車有行色。", "正悲南浦秋，又送清湘客。", "啼饑兒頰紅，待養親髮白。", "努力事上官，世路日已迫。"]'),
('8089f91d-f6bd-430e-85b7-91bb49d5ef88','病中作','陸游','宋','宋诗','song-poetry','','[]','豫章瀕大江，氣候頗不令。',96,'全唐诗/poet.song.127000.json','["豫章瀕大江，氣候頗不令。", "孟冬風薄人，十室八九病。", "外寒客肺胃，下濕攻脚脛。", "俗巫醫不藝，嗚呼安託命。", "我始屏藥囊，治病以清靜。", "幻妄消六塵，虚白全一性。", "三日體遂輕，成此不戰勝。", "長年更事多，苦語君試聽。"]'),
('51b11a01-e0a9-48c4-a219-dbb1192e39b3','夜夢從數客雨中載酒出遊山川城闕極雄麗云長安也因與客馬上分韵作詩得遊字','陸游','宋','宋诗','song-poetry','','[]','有酒不謀州，能詩自勝侯。',48,'全唐诗/poet.song.127000.json','["有酒不謀州，能詩自勝侯。", "但須繩繫日，安用地埋憂。", "射雉侵星出，看花秉燭遊。", "殘春杜陵雨，不恨濕貂裘。"]'),
('5dfe3e3c-b181-493f-bdbf-d9b9cecbba88','去年余佐京口遇王嘉叟從張魏公督師過焉魏公道免相嘉叟亦出守莆陽近辱書報魏公已葬衡山感嘆不已因用所遺拄頰亭詩韵奉寄','陸游','宋','宋诗','song-poetry','','["\u8861\u5c71"]','河亭挈手共徘徊，萬事寜非有數哉。',64,'全唐诗/poet.song.127000.json','["河亭挈手共徘徊，萬事寜非有數哉。", "黄閣相君三黜去，青雲學士一麾來。", "中原故老知誰在，南嶽新丘共此哀。", "火冷夜窗聽急雪，相思時取近書開。"]'),
('23a86e43-1079-49b9-b601-196edbddbd26','自詠示客','陸游','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','衰髮蕭蕭老郡丞，洪州又看上元燈。',64,'全唐诗/poet.song.127000.json','["衰髮蕭蕭老郡丞，洪州又看上元燈。", "羞將枉直分尋尺，寜走東西就斗升。", "吏進飽諳箝紙尾，客來苦勸摸床稜。", "歸裝漸理君知否，笑指廬山古澗藤。"]'),
('c8efdbe4-52c2-4746-be90-7cee6551b8c4','醉中歌','陸游','宋','宋诗','song-poetry','','[]','吾少貧賤真臞儒，貪食嗜味老不除。',144,'全唐诗/poet.song.127000.json','["吾少貧賤真臞儒，貪食嗜味老不除。", "折腰斂版日走趨，歸來聊以醉自娛。", "長缾巨榼羅杯盂，不須漁翁勸三閭。", "牛尾膏美如凝酥，猫頭輪囷欲專車。", "黄雀萬里行頭顱，白鵝作鮓天下無。", "潯陽糖蟹徑尺餘，吾州之蔊尤嘉蔬。", "珍盤餖飣百味俱，不但項臠與腹腴。", "悠然一飽自笑愚，顧爲口腹勞形軀。", "投劾行矣歸園廬，莫厭糲飯嘗黄葅。"]'),
('435ad59a-f072-43d0-a075-dbdbca53b597','寄陶茂安監丞','陸游','宋','宋诗','song-poetry','','[]','永州太守鬢毛殘，矍鑠猶能起據鞍。',64,'全唐诗/poet.song.127000.json','["永州太守鬢毛殘，矍鑠猶能起據鞍。", "徴士雖思賦松菊，隱居未可挂衣冠。", "功名夢境元非實，歌舞山城且自寬。", "也勝鍾陵窮别駕，閉門無客遣憂端。"]'),
('0496071c-26ad-48f4-8a7c-333b780b96b8','燒香','陸游','宋','宋诗','song-poetry','','[]','茹芝却粒世無方，隨食江湖每自傷。',64,'全唐诗/poet.song.127000.json','["茹芝却粒世無方，隨食江湖每自傷。", "千里一身鳬泛泛，十年萬事海茫茫。", "春來鄉夢憑誰說，歸去君恩未敢忘。", "一寸丹心幸無愧，庭空月白夜燒香。"]'),
('6f4af192-4023-4894-bb15-b1de6f7483f2','寒食臨川道中','陸游','宋','宋诗','song-poetry','','[]','百卉千花了不存，墮溪飛絮看無痕。',64,'全唐诗/poet.song.127000.json','["百卉千花了不存，墮溪飛絮看無痕。", "家人自作清明節，老子來穿緑暗村。", "日落啼鴉隨野祭，雨餘荒蔓上頽垣。", "道邊醉飽休相避，作吏堪羞甚乞墦。"]'),
('05a5e8dc-7bab-4774-8f49-bee0c25ab5e3','上巳臨川道中','陸游','宋','宋诗','song-poetry','','[]','二月六夜春水生，陸子初有臨川行。',160,'全唐诗/poet.song.127000.json','["二月六夜春水生，陸子初有臨川行。", "溪深橋斷不得渡，城近臥聞吹角聲。", "三月三日天氣新，臨川道中愁殺人。", "纖纖女手桑葉緑，漠漠客舍桐花春。", "平生怕路如怕虎，幽居不省遊城府。", "鶴軀苦瘦坐長饑，龜息無聲惟黙數。", "如今自憐還自笑，斂版低心事年少。", "儒冠未恨終自誤，刀筆最驚非素料。", "五更欹枕一凄然，夢裏扁舟水接天。", "紅蕖緑芰梅山下，白塔朱樓禹廟邊。"]'),
('27ab42d5-4222-41b3-beb8-e7ff04e44eb3','寄别李德遠二首  其一','陸游','宋','宋诗','song-poetry','','[]','蕭蕭風雨臨川驛，邂逅連床若有期。',64,'全唐诗/poet.song.127000.json','["蕭蕭風雨臨川驛，邂逅連床若有期。", "自起挑燈貪夜話，疾呼索飯療朝饑。", "即今明月共千里，已占深林巢一枝。", "惜别自嫌兒女態，夢騎羸馬度芳陂。"]'),
('6186c03d-2328-4113-8dc0-11f9b586a2d5','寄别李德遠二首  其二','陸游','宋','宋诗','song-poetry','','[]','李侯不恨世賣友，陸子那須錢買山。',64,'全唐诗/poet.song.127000.json','["李侯不恨世賣友，陸子那須錢買山。", "出牧君當千里去，歸耕我判一生閑。", "中原亂後儒風替，黨禁興來士氣孱。", "復古主盟須老手，勉追慶曆數公間。"]'),
('6c7a3eb2-9862-476f-8f16-a3d611fad442','初夏道中','陸游','宋','宋诗','song-poetry','','[]','桑間葚熟麥齊腰，鶯語惺惺野雉驕。',64,'全唐诗/poet.song.127000.json','["桑間葚熟麥齊腰，鶯語惺惺野雉驕。", "日薄人家晒蠶子，雨餘山客買魚苗。", "豐年隨處俱堪樂，行路終然不自聊。", "獨喜此身強健在，又揺團扇著絺蕉。"]'),
('55ec0449-5ab5-4524-8e73-1a1dcfadc0ac','示兒子','陸游','宋','宋诗','song-poetry','','[]','父子扶攜返故鄉，欣然擊壤詠陶唐。',64,'全唐诗/poet.song.127000.json','["父子扶攜返故鄉，欣然擊壤詠陶唐。", "墓前自誓寜非隘，澤畔行吟未免狂。", "雨潤北窗看洗竹，霜清南陌課剶桑。", "秋毫何者非君賜，回首修門敢遽忘。"]'),
('834ca44d-a17a-43cd-bc26-0243a70089da','重五同尹少稷觀江中競渡','陸游','宋','宋诗','song-poetry','','[]','楚人遺俗閲千年，簫鼓喧呼鬭畫船。',32,'全唐诗/poet.song.127000.json','["楚人遺俗閲千年，簫鼓喧呼鬭畫船。", "風浪如山鮫鰐横，何心此地更爭先。"]'),
('dcffa2fc-ecee-4a32-85c9-83a7a6f72e7d','過玉山辱芮國器檢詳留語甚勤因寄此詩兼呈韓无咎右司','陸游','宋','宋诗','song-poetry','','[]','遼東歸老白襦裙，名字何堪遣世聞。',64,'全唐诗/poet.song.127000.json','["遼東歸老白襦裙，名字何堪遣世聞。", "便謂與公長契濶，不知留語故慇懃。", "詩章有便猶應寄，禄米無多切莫分。", "倘見右司煩說似，每因風月愴離群。"]'),
('05b285de-2939-4ea4-9d67-2496d66abbc2','隨意','陸游','宋','宋诗','song-poetry','','[]','隨意上漁舟，幽尋不預謀。',48,'全唐诗/poet.song.127000.json','["隨意上漁舟，幽尋不預謀。", "清溪欣始泛，野寺憶前遊。", "豐歲雞豚賤，霜天柿栗稠。", "餘生知有幾，且置萬端憂。"]'),
('7efb21be-56f4-4ca0-8f26-5ac672a9e746','寄龔實之正言','陸游','宋','宋诗','song-poetry','','[]','臺省諸公歲歲新，平生敬慕獨斯人。',64,'全唐诗/poet.song.127000.json','["臺省諸公歲歲新，平生敬慕獨斯人。", "山林不恨音塵遠，夢寐時容笑語親。", "學道皮膚雖脫落，憂時肝膽尚輪囷。", "至和嘉祐須公了，乞向升平作幸民。"]'),
('53f7d126-b9ad-443b-b054-1e2ae8e0e05c','遊山西村','陸游','宋','宋诗','song-poetry','','["\u751f\u6d3b", "\u5c71\u6c34", "\u5199\u666f", "\u521d\u4e2d\u53e4\u8bd7", "\u4e61\u6751", "\u54f2\u7406"]','莫笑農家臘酒渾，豐年留客足雞豚。',64,'全唐诗/poet.song.127000.json','["莫笑農家臘酒渾，豐年留客足雞豚。", "山重水複疑無路，柳暗花明又一村。", "簫鼓追隨春社近，衣冠簡朴古風存。", "從今若許閑乘月，拄杖無時夜叩門。"]'),
('521a0816-94b4-4a1d-978e-a51e248c5e21','觀村童戲溪上','陸游','宋','宋诗','song-poetry','','["\u513f\u7ae5", "\u751f\u6d3b", "\u519c\u6c11"]','雨餘溪水掠堤平，閑看村童戲晚晴。',64,'全唐诗/poet.song.127000.json','["雨餘溪水掠堤平，閑看村童戲晚晴。", "竹馬踉蹡沖淖去，紙鳶跋扈挾風鳴。", "三冬暫就儒生學，千耦還從父老耕。", "識字粗堪供賦役，不須辛苦慕公卿。"]'),
('ea14a57b-b55f-43a9-be4e-c70e9a8b2e88','雨霽出遊書事','陸游','宋','宋诗','song-poetry','','[]','十日苦雨一日晴，拂拭拄杖西村行。',128,'全唐诗/poet.song.127000.json','["十日苦雨一日晴，拂拭拄杖西村行。", "清溝泠泠流水細，好風習習吹衣輕。", "四鄰蛙聲已閤閤，兩岸柳色爭青青。", "辛夷先開半委地，海棠獨立方傾城。", "春工遇物初不擇，亦秀燕麥開蕪菁。", "薺花如雪又爛漫，百草紅紫那知名。", "小魚誰取置道側，細柳穿頰危將烹。", "欣然買放寄吾意，草萊無地蘇疲氓。"]'),
('20a630d3-47fe-437a-9bdb-960d6c10f7e8','殘春','陸游','宋','宋诗','song-poetry','','[]','殘春醉著釣魚庵，花雨娛人落半巖。',64,'全唐诗/poet.song.127000.json','["殘春醉著釣魚庵，花雨娛人落半巖。", "豈是天公無皂白，獨悲世俗異酸鹹。", "妄身似夢行當覺，談口如狂未易緘。", "已作沉舟君勿嘆，年來何止閲千帆。"]'),
('875f4891-2078-445e-9237-3f14b99c0113','家園小酌二首  其一','陸游','宋','宋诗','song-poetry','','[]','旋作園廬指顧成，柳陰已復著啼鶯。',64,'全唐诗/poet.song.127000.json','["旋作園廬指顧成，柳陰已復著啼鶯。", "百年更把幾杯酒，一月元無三日晴。", "鷗鷺向人殊耐久，山林與世本無營。", "小詩漫付兒曹誦，不用韓公說有聲。"]'),
('ae92cc4a-bcc3-4be2-bc6e-63210549b702','家園小酌二首  其二','陸游','宋','宋诗','song-poetry','','[]','滿林春筍生無數，竟日鸕鷀來百回。',64,'全唐诗/poet.song.127000.json','["滿林春筍生無數，竟日鸕鷀來百回。", "衣上塵埃真一洗，酒邊懷抱得頻開。", "池魚往者憂奇禍，社櫟終然幸散材。", "世事紛紛心本懶，閉門豈獨畏嫌猜。"]'),
('17bc8c71-6678-43a6-adc4-280023ab0957','寄王嘉叟吏部','陸游','宋','宋诗','song-poetry','','[]','宿負煩公議，隆寬荷聖時。',48,'全唐诗/poet.song.127000.json','["宿負煩公議，隆寬荷聖時。", "江湖真送老，藥餌且扶衰。", "撫事驚年往，懷人有夢知。", "敢嗟貧到骨，飲水誦君詩。"]'),
('738f6c06-4a79-4555-bcae-b0504c09d540','夜讀隱書有感','陸游','宋','宋诗','song-poetry','','[]','平生志慕白雲鄉，俯仰人間每自傷。',64,'全唐诗/poet.song.127000.json','["平生志慕白雲鄉，俯仰人間每自傷。", "倦鶴摧頹寜望料，寒龜蹙縮且支床。", "力探鴻寶尋奇訣，剩采青精試秘方。", "常鄙臞仙老山澤，要令仰首看飛翔。"]'),
('c6103e6f-4e94-4dd2-971e-aeff82bef9e4','上虞逆旅見舊題歲月感懷','陸游','宋','宋诗','song-poetry','','[]','舴艋爲家東復西，今朝破曉下前溪。',64,'全唐诗/poet.song.127000.json','["舴艋爲家東復西，今朝破曉下前溪。", "青山缺處日初上，孤店開時鶯亂啼。", "倦枕不成千里夢，壞牆閑覓十年題。", "漆園傲吏猶非達，物我區區豈足齊。"]'),
('a232464d-d63a-47a8-a804-77b2e6d44d29','舜廟懷古','陸游','宋','宋诗','song-poetry','','[]','雲斷蒼梧竟不歸，江邊古廟鎖朱扉。',64,'全唐诗/poet.song.127000.json','["雲斷蒼梧竟不歸，江邊古廟鎖朱扉。", "山川不爲興亡改，風月應憐感慨非。", "孤枕有時鶯喚夢，斜風無賴客添衣。", "千年回首消磨盡，輸與漁舟送落暉。"]'),
('135d2199-1418-4873-9e8a-652a0f8c0118','題十八學士圖','陸游','宋','宋诗','song-poetry','','[]','隋日昏曀東南傾，雷塘風吹草木腥。',160,'全唐诗/poet.song.127000.json','["隋日昏曀東南傾，雷塘風吹草木腥。", "平時但忌黑色兒，不知乃有虬髯生。", "晉陽龍飛雲滃滃，關洛萬里即日平。", "東征歸來脫金甲，天策開府延豪英。", "琴書閑暇永清晝，簪履光彩明華星。", "高參伊吕列佐命，下者才氣猶崢嶸。", "但餘一恨到千載，高陽繆公來竄名。", "老奸得志國幾喪，李氏誅徙連孤嬰。", "向令亟念履霜戒，危亂安得存勾萌。", "衆賢一佞禍尚爾，掩卷涕泪臨風横。"]'),
('22928e97-311b-45b0-a686-03198556a3e5','統分稻晚歸二首  其一','陸游','宋','宋诗','song-poetry','','[]','出裹一簞飯，歸收百把禾。',48,'全唐诗/poet.song.127000.json','["出裹一簞飯，歸收百把禾。", "勤勞解堪忍，餘暇更吟哦。", "歲惡增吾困，家貧賴汝多。", "村醪莫辭醉，羮芋學岷峨。"]'),
('54c9201a-e6bd-47a2-88b5-ed546e7fd1ed','統分稻晚歸二首  其二','陸游','宋','宋诗','song-poetry','','[]','薄酒不自酌，夕陽須汝歸。',48,'全唐诗/poet.song.127000.json','["薄酒不自酌，夕陽須汝歸。", "橘包霜後美，豆莢雨中肥。", "路遠應加飯，天寒莫減衣。", "老懷憂自切，道眼看皆非。"]'),
('f422d9bd-e24b-4ab4-8bcd-3613c389e7ca','衰病二首  其一','陸游','宋','宋诗','song-poetry','','[]','衰病不浪出，閉門烟雨中。',48,'全唐诗/poet.song.127000.json','["衰病不浪出，閉門烟雨中。", "葦花添絮暖，葑火試爐紅。", "仕宦螘窠夢，功名馬耳風。", "山翁但更事，人看作神通。"]'),
('f8d585ce-44a7-4910-9cf9-1f817d953839','衰病二首  其二','陸游','宋','宋诗','song-poetry','','[]','病除猶老健，雨止得冬晴。',48,'全唐诗/poet.song.127000.json','["病除猶老健，雨止得冬晴。", "覓句嗟心在，鈔書試眼明。", "朝寒添布褐，晚步出柴荆。", "外慕終無益，兒曹且力耕。"]'),
('49eb06b8-96f2-4c39-ad99-4b0b9fd74202','霜風','陸游','宋','宋诗','song-poetry','','[]','十月霜風吼屋邊，布裘未辦一銖綿。',64,'全唐诗/poet.song.127000.json','["十月霜風吼屋邊，布裘未辦一銖綿。", "豈惟饑索鄰僧米，真是寒無坐客氊。", "身老嘯歌悲永夜，家貧撐拄過凶年。", "丈夫經此寜非福，破涕燈前一粲然。"]'),
('709cb47c-a27d-48cd-8fea-16277a5a02a7','小酌','陸游','宋','宋诗','song-poetry','','[]','盤箸貧猶設，杯盂老更耽。',48,'全唐诗/poet.song.127000.json','["盤箸貧猶設，杯盂老更耽。", "宗文樹雞柵，靈照挈蔬籃。", "徑醉眼花亂，高眠鼻息酣。", "覺來寒日晚，落葉擁茆庵。"]'),
('8e037350-0130-455a-b201-02aacd784824','十月苦蠅二首  其一','陸游','宋','宋诗','song-poetry','','[]','村北村南打稻忙，浮雲吹盡見朝陽。',32,'全唐诗/poet.song.127000.json','["村北村南打稻忙，浮雲吹盡見朝陽。", "不宜便作晴明看，撲面飛蠅未退藏。"]'),
('1ed769ad-e155-467e-a0ff-fa74a9da2ca2','十月苦蠅二首  其二','陸游','宋','宋诗','song-poetry','','[]','十月江南未擁爐，癡蠅擾擾莫嫌渠。',32,'全唐诗/poet.song.127000.json','["十月江南未擁爐，癡蠅擾擾莫嫌渠。", "細看豈是堅牢物，付與清霜爲掃除。"]'),
('39524a3f-b5b4-4c65-8411-cca1055de753','丫頭巖見周洪道以進士入都日題字','陸游','宋','宋诗','song-poetry','','[]','烏巾白紵蹋京塵，瑶樹瓊林照路人。',32,'全唐诗/poet.song.127000.json','["烏巾白紵蹋京塵，瑶樹瓊林照路人。", "西省歸來名蓋代，兩行墨色尚如新。"]'),
('172b0072-edf6-499d-af57-bd58c0a3d71d','獨學','陸游','宋','宋诗','song-poetry','','[]','師友雕零身白首，杜門獨學就誰評。',64,'全唐诗/poet.song.127000.json','["師友雕零身白首，杜門獨學就誰評。", "秋風棄扇知安命，小炷留燈悟養生。", "踵息無聲酣午枕，舌根忘味美晨烹。", "少年妄起功名念，豈信身閑心太平。"]'),
('d8ec70ba-5387-4392-a1cc-f195fcf076d0','霜月','陸游','宋','宋诗','song-poetry','','[]','枯草霜花白，寒窗月影新。',48,'全唐诗/poet.song.127000.json','["枯草霜花白，寒窗月影新。", "驚鴉時繞樹，吠犬遠隨人。", "出仕讒銷骨，歸耕病滿身。", "世間輸壞衲，切莫勸冠巾。"]'),
('73f47791-e034-4775-ad44-5419e54669be','寄黄龍升老','陸游','宋','宋诗','song-poetry','','[]','讀書萬卷裂儒衣，黄金可成棄不爲。',144,'全唐诗/poet.song.127000.json','["讀書萬卷裂儒衣，黄金可成棄不爲。", "快哉天馬不可羈，開口便呼臨濟兒。", "諸方蹴蹋莫支持，吾州一老偶得之。", "閉門夜付僧伽黎，明日聲價羽檄馳。", "弟子不必不如師，黄龍所立尤瑰奇。", "空山鬼火號狐狸，築屋千礎食萬緇。", "癡人不解公遊嬉，嫉怒欲碎門前碑。", "世衰道喪士自欺，山林亦復踐駭機。", "長謡寄公公試思，吾輩救此當何施。"]'),
('5bc16ba5-2adc-4ea1-9e6f-3c46a44af936','贈進賢劉令','陸游','宋','宋诗','song-poetry','','[]','簿領塵埃裏，超然見鳯麟。',48,'全唐诗/poet.song.127000.json','["簿領塵埃裏，超然見鳯麟。", "性疏忘顧忌，學大有經綸。", "正論雖頻接，高標豈易親。", "向來相識晚，吾黨欠斯人。"]'),
('4593c7ed-27e4-4277-8c2f-621f3ed80c1b','書室名可齋或問其義作此告之','陸游','宋','宋诗','song-poetry','','[]','得福常廉禍自輕，坦然無愧亦無驚。',32,'全唐诗/poet.song.127000.json','["得福常廉禍自輕，坦然無愧亦無驚。", "平生秘訣今相付，只向君心可處行。"]'),
('4ba38856-cfa9-4c35-9bcc-764326159188','寄酬楊齊伯少卿','陸游','宋','宋诗','song-poetry','','[]','楊卿人材金百鍊，岐公座上初識面。',96,'全唐诗/poet.song.127000.json','["楊卿人材金百鍊，岐公座上初識面。", "十年萬事不須說，猶喜歸來且強健。", "題詩想見初削瓜，寄到茆堂已歸燕。", "辭嚴意密敢輕讀，呼兒炷燈重把卷。", "即今相望幾千里，何日蟬聨語忘倦。", "就令有使即寄書，豈如無事長相見。"]'),
('a0b35d7f-d529-4481-9923-f906e02419e1','自笑','陸游','宋','宋诗','song-poetry','','[]','自笑平生醉後狂，千鍾使氣少年塲。',64,'全唐诗/poet.song.127000.json','["自笑平生醉後狂，千鍾使氣少年塲。", "那知病葉先摧落，却羡寒龜巧縮藏。", "藥物及時希老健，山家隨日了窮忙。", "凶年坐待新春麥，莫厭清吟雪夜長。"]'),
('5090d818-798b-4f09-917c-679b8740be3d','夜聞松聲有感','陸游','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','清晨放船落星石，大風吹颿如箭激。',128,'全唐诗/poet.song.127000.json','["清晨放船落星石，大風吹颿如箭激。", "回頭已失廬山雲，却上吳城觀落日。", "夜深龍歸擘祠門，入木數寸留爪痕。", "明朝就視心尚慄，腥風卷地雷霆奔。", "歸船買酒持自慰，性命平生驚屢戲。", "固知神怒有定時，波紋蹙作魚鱗細。", "如今衰病臥林坰，霜覆茆簷月滿庭。", "松聲驚破三更夢，猶作當時風浪聽。"]'),
('d85acabe-d585-435b-8f31-feb1d956a384','十二月一日二首  其一','陸游','宋','宋诗','song-poetry','','[]','病愈都忘老，晴和已似春。',48,'全唐诗/poet.song.127000.json','["病愈都忘老，晴和已似春。", "畦蔬青長甲，塘水緑生鱗。", "酒盌論交密，丹爐作夢新。", "窮居那敢恨，幸遠庾公塵。"]'),
('4beff453-c253-48dd-a658-123a17150a63','十二月一日二首  其二','陸游','宋','宋诗','song-poetry','','[]','東風吹斗柄，暖律變嚴凝。',48,'全唐诗/poet.song.127000.json','["東風吹斗柄，暖律變嚴凝。", "草色迷殘燒，溪流帯斷冰。", "兒書春日牓，女剪上元燈。", "莫笑蒲龕睡，山翁怯歲增。"]'),
('efa224dd-2c7c-4421-8ff8-364d6a6d8806','春日二首  其一','陸游','宋','宋诗','song-poetry','','[]','老夫一臥三山下，兩見城門送土牛。',64,'全唐诗/poet.song.127000.json','["老夫一臥三山下，兩見城門送土牛。", "貧舍春盤還草草，暮年心事轉悠悠。", "湖光漲緑分烟浦，柳色揺金映市樓。", "藥餌及時身尚健，無風無雨且閑遊。"]'),
('b2832845-0213-4b0c-b07f-b42dff9783c0','春日二首  其二','陸游','宋','宋诗','song-poetry','','[]','久抛朝幘懶重彈，華髮蕭然二寸冠。',64,'全唐诗/poet.song.127000.json','["久抛朝幘懶重彈，華髮蕭然二寸冠。", "不恨凄涼侵晚境，猶能語笑向春盤。", "銀杯酒色家家緑，篛笠烟波處處寬。", "一片梅花無復在，却嫌新暖換餘寒。"]'),
('3b0b438d-13d9-4e49-99b2-36a3fc468d11','僧房假榻','陸游','宋','宋诗','song-poetry','','[]','過盡青山喚渡船，晚窗洗脚臥僧氊。',64,'全唐诗/poet.song.127000.json','["過盡青山喚渡船，晚窗洗脚臥僧氊。", "剩償平日清遊願，更結來生熟睡緣。", "吞啄漸稀如老鶴，鳴聲已斷似寒蟬。", "旁觀莫苦嘲癡鈍，此妙吾宗秘不傳。"]'),
('ba3859f0-d231-4c9c-b8e9-e7bb343ef542','聞雨','陸游','宋','宋诗','song-poetry','','[]','慷慨心猶壯，蹉跎鬢已秋。',48,'全唐诗/poet.song.127000.json','["慷慨心猶壯，蹉跎鬢已秋。", "百年殊鼎鼎，萬事秪悠悠。", "不悟魚千里，終歸貉一丘。", "夜闌聞急雨，起坐涕交流。"]'),
('c91fe76d-54f0-41b6-94af-75a3b31927fd','休日有感','陸游','宋','宋诗','song-poetry','','[]','少年從宦地，休日喜無涯。',48,'全唐诗/poet.song.127000.json','["少年從宦地，休日喜無涯。", "坐上強留客，街頭旋買花。", "開軒催汛掃，脱帽共諠譁。", "村巷朋遊絕，逢春祇自嗟。"]'),
('8a355f71-3361-44ed-bf05-cea9db884d70','題徐子禮宗丞自覺齋','陸游','宋','宋诗','song-poetry','','[]','末俗紛紛只自謾，惟公肯向靜中觀。',64,'全唐诗/poet.song.127000.json','["末俗紛紛只自謾，惟公肯向靜中觀。", "閑看此事從何得，正自它人著力難。", "茶熟松風生石鼎，香殘雲縷遶蒲團。", "江湖多少癡禪衲，蹋破青鞵覓話端。"]'),
('4e03a399-4162-4f13-afaa-bbb830f90223','送張叔潛編修造朝四首  其一','陸游','宋','宋诗','song-poetry','','[]','此士名高北斗南，眼中獨許我同參。',32,'全唐诗/poet.song.127000.json','["此士名高北斗南，眼中獨許我同參。", "匆匆却作臨分恨，一月何曾笑二三。"]'),
('6ac5cc72-4d10-4191-91b2-8435202709d0','送張叔潛編修造朝四首  其二','陸游','宋','宋诗','song-poetry','','[]','簡牘清閑勝校讐，題詩應肯寄夔州。',32,'全唐诗/poet.song.127000.json','["簡牘清閑勝校讐，題詩應肯寄夔州。", "東厨羊美聊堪飽，北面鈴稀莫強愁。"]'),
('36377fd8-8e01-489a-8407-864efd7e24c3','送張叔潛編修造朝四首  其三','陸游','宋','宋诗','song-poetry','','[]','北窗銅碾破雲腴，捫腹翛然一事無。',32,'全唐诗/poet.song.127000.json','["北窗銅碾破雲腴，捫腹翛然一事無。", "安用雁行排院吏，正須魚貫看胡俘。"]'),
('00288a8a-4967-4170-8cfd-d24ba0dc3e6c','送張叔潛編修造朝四首  其四','陸游','宋','宋诗','song-poetry','','[]','芒屩年來漸懶穿，閉門日日只高眠。',32,'全唐诗/poet.song.127000.json','["芒屩年來漸懶穿，閉門日日只高眠。", "今朝出送張夫子，借得南鄰放鴨船。"]'),
('fb3f1602-c3f3-4379-ad6a-a9e2355697c7','有感','陸游','宋','宋诗','song-poetry','','[]','雲崦重重不易尋，庖厨性命走山林。',64,'全唐诗/poet.song.127000.json','["雲崦重重不易尋，庖厨性命走山林。", "但令有月同幽夢，更用何人識苦心。", "流輩漸稀知死近，鬢毛無色覺愁侵。", "平生自許忘情者，頗怪燈前感慨深。"]'),
('f4f72b28-ff34-4812-9daa-5318975da5ed','澗松','陸游','宋','宋诗','song-poetry','','[]','藥出山來爲小草，楸成樹後困長藤。',32,'全唐诗/poet.song.127000.json','["藥出山來爲小草，楸成樹後困長藤。", "澗松鬱鬱何勞嘆，却是人間奈廢興。"]'),
('7a635612-b9c1-4dfb-9f35-55ca9224f433','將赴官夔府書懷','陸游','宋','宋诗','song-poetry','','[]','病夫喜山澤，抗志自年少。',156,'全唐诗/poet.song.127000.json','["病夫喜山澤，抗志自年少。", "有時緣龜饑，妄出丏鶴料。", "亦嘗厠朝紳，退懦每自笑。", "正如怯酒人，雖愛不敢釂。", "一從南昌免，五歲嗟不調。", "朝廷每哀矜，幙府誤辟召。", "終然斂孤迹，萬里遊絕徼。", "民風雜莫徭，封域近無詔。", "凄涼黄魔宫，峭絕白帝廟。", "又嘗聞此邦，野陋可嘲誚。", "通衢舞竹枝，譙門對山燒。", "浮生一夢耳，何者可慶吊。", "但愁癭纍纍，把鏡羞自照。"]'),
('376bc09c-3434-4b82-bb43-d18cd3f9a871','送芮國器司業二首  其一','陸游','宋','宋诗','song-poetry','','[]','此心知我豈非天，雙鬢皤然氣浩然。',64,'全唐诗/poet.song.127000.json','["此心知我豈非天，雙鬢皤然氣浩然。", "曾見灰寒百僚底，真能山立萬夫前。", "洛城霜重聽宫漏，霅水雲深著釣船。", "拈起吾宗安樂法，人生何處不隨緣。"]'),
('33a5d52e-4656-4d48-a481-88522c08f957','送芮國器司業二首  其二','陸游','宋','宋诗','song-poetry','','[]','往歲淮邊虜未歸，諸生合疏論危機。',64,'全唐诗/poet.song.127000.json','["往歲淮邊虜未歸，諸生合疏論危機。", "人材衰靡方當慮，士氣崢嶸未可非。", "萬事不如公論久，諸賢莫與衆心違。", "還朝此段宜先及，豈獨遺經賴發揮。"]'),
('8d15f455-37fc-4de2-962a-aa1011aafe0d','春陰','陸游','宋','宋诗','song-poetry','','[]','春風浩蕩作春陰，弱燕歸來不自禁。',64,'全唐诗/poet.song.127000.json','["春風浩蕩作春陰，弱燕歸來不自禁。", "白塔昏昏纔半露，青山淡淡欲平沉。", "裘茸細雨初驚濕，屐齒新泥忽已深。", "直怕樓高生客恨，不因病起倦登臨。"]'),
('fcedabac-b89e-4f79-a748-f826c0e73686','投梁參政','陸游','宋','宋诗','song-poetry','','[]','浮生無根株，志士惜浪死。',168,'全唐诗/poet.song.127000.json','["浮生無根株，志士惜浪死。", "雞鳴何預人，推枕中夕起。", "游也本無奇，腰折百僚底。", "流離鬢成絲，悲咤涙如洗。", "殘年走巴峽，辛苦爲斗米。", "遠衝三伏熱，前指九月水。", "回首長安城，未忍便萬里。", "袖詩叩東府，再拜求望履。", "平生實易足，名幸污黄紙。", "但憂死無聞，功不挂青史。", "頗聞匈奴亂，天意殄蛇豕。", "何時嫖姚師，大刷渭橋恥。", "士各奮所長，儒生未宜鄙。", "覆氊草軍書，不畏寒墮指。"]'),
('ee620b8b-9d17-4e8b-81ce-8522d0ebb70e','宿楓橋','陸游','宋','宋诗','song-poetry','','[]','七年不到楓橋寺，客枕依然半夜鐘。',32,'全唐诗/poet.song.127000.json','["七年不到楓橋寺，客枕依然半夜鐘。", "風月未須輕感慨，巴山此去尚千重。"]'),
('3d96d633-75c0-40ba-aa80-6a61f2618245','晚泊','陸游','宋','宋诗','song-poetry','','["\u6292\u60c5", "\u4e58\u8239", "\u665a\u4e0a", "\u5199\u666f"]','半世無歸似轉蓬，今年作夢到巴東。',64,'全唐诗/poet.song.127000.json','["半世無歸似轉蓬，今年作夢到巴東。", "身遊萬死一生地，路入千峰百嶂中。", "鄰舫有時來乞火，樷祠無處不祈風。", "晚潮又泊淮南岸，落日啼鴉戍堞空。"]'),
('d4e2be64-5e01-4b87-9bcd-4d9cf840d850','金山觀日出','陸游','宋','宋诗','song-poetry','','[]','繫船浮玉山，清晨得奇觀。',72,'全唐诗/poet.song.127000.json','["繫船浮玉山，清晨得奇觀。", "日輪擘水出，始覺江面寬。", "遥波蹙紅鱗，翠靄開金盤。", "光彩射樓塔，丹碧浮雲端。", "詩人窘筆力，但詠秋月寒。", "何當羅浮望，湧海夜未闌。"]'),
('46c67652-ca17-407a-a2dc-7944cc65789e','吊李翰林墓','陸游','宋','宋诗','song-poetry','','[]','飲似長鯨快吸川，思如渴驥勇奔泉。',64,'全唐诗/poet.song.127000.json','["飲似長鯨快吸川，思如渴驥勇奔泉。", "客從縣令初何有，醉忤將軍亦偶然。", "駿馬名姬如昨日，斷碑喬木不知年。", "浮生今古同歸此，回首桓公亦故阡。"]'),
('08b1dc40-fe06-4249-8a23-0de8756a01a0','雨中泊趙屯有感','陸游','宋','宋诗','song-poetry','','[]','歸燕羈鴻共斷魂，荻花楓葉泊孤村。',64,'全唐诗/poet.song.127000.json','["歸燕羈鴻共斷魂，荻花楓葉泊孤村。", "風吹暗浪重添纜，雨送新寒半掩門。", "魚市人烟横慘淡，龍祠簫鼓閙黄昏。", "此身且健無餘恨，行路雖難莫更論。"]'),
('726e75c1-289e-4aa7-9a85-d52fd78c9e13','黄州','陸游','宋','宋诗','song-poetry','','[]','局促常悲類楚囚，遷流還嘆學齊優。',64,'全唐诗/poet.song.127000.json','["局促常悲類楚囚，遷流還嘆學齊優。", "江聲不盡英雄恨，天意無私草木秋。", "萬里羈愁添白髮，一帆寒日過黄州。", "君看赤壁終陳迹，生子何須似仲謀。"]'),
('be3bf9a2-5b5f-4e5d-abc3-a3084e18505d','武昌感事','陸游','宋','宋诗','song-poetry','','[]','百萬呼盧事已空，新寒擁褐一衰翁。',64,'全唐诗/poet.song.127000.json','["百萬呼盧事已空，新寒擁褐一衰翁。", "但悲鬢色成枯草，不恨生涯似斷蓬。", "烟雨凄迷雲夢澤，山川蕭瑟武昌宫。", "西遊處處堪流涕，撫枕悲歌興未窮。"]'),
('d5ceb1ed-5d04-4cfc-a4fb-f15a4c0d0616','夜思','陸游','宋','宋诗','song-poetry','','[]','露泣啼螿草，潮生宿雁汀。',48,'全唐诗/poet.song.127000.json','["露泣啼螿草，潮生宿雁汀。", "經年寄孤舫，終夜託丘亭。", "楚澤無窮白，巴山何處青。", "四方男子事，不敢恨飄零。"]'),
('f4cfa25b-a9f9-423b-8728-1cdc18e0a86e','哀郢二首  其一','陸游','宋','宋诗','song-poetry','','[]','遠接商周祚最長，北盟齊晉勢爭強。',64,'全唐诗/poet.song.127000.json','["遠接商周祚最長，北盟齊晉勢爭強。", "章華歌舞終蕭瑟，雲夢風烟舊莽蒼。", "草合故宫惟雁起，盜穿荒冢有狐藏。", "離騷未盡靈均恨，志士千秋泪滿裳。"]'),
('3af9be82-18d1-4ed6-9686-ef65583815f8','哀郢二首  其二','陸游','宋','宋诗','song-poetry','','[]','荆州十月早梅春，徂歲真同下阪輪。',64,'全唐诗/poet.song.127000.json','["荆州十月早梅春，徂歲真同下阪輪。", "天地何心窮壯士，江湖從古著羈臣。", "淋漓痛飲長亭暮，慷慨悲歌白髮新。", "欲吊章華無處問，廢城霜露濕荆榛。"]'),
('133422d0-5338-481d-96c9-6e6e8e4b4ff2','江陵道中作','陸游','宋','宋诗','song-poetry','','[]','山川雜吳楚，氣候接秋冬。',48,'全唐诗/poet.song.127000.json','["山川雜吳楚，氣候接秋冬。", "水落魚可拾，霜清裘欲重。", "鄉遥歸夢短，酒薄客愁濃。", "白帝何時到，高吟酹臥龍。"]'),
('07ee3c3b-e5cd-442d-9e74-a7cc62cbac6c','石首縣雨中繫舟戲作短歌','陸游','宋','宋诗','song-poetry','','[]','庚寅去吳西適楚，秋晚孤舟泊江渚。',128,'全唐诗/poet.song.127000.json','["庚寅去吳西適楚，秋晚孤舟泊江渚。", "荒林月黑虎欲行，古道人稀鬼相語。", "鬼語亦如人語悲，楚國繁華非昔時。", "章華臺前小家住，茆屋雨漏秋風吹。", "悲哉秦人真虎狼，欺侮六國囚侯王。", "亦知興廢古來有，但恨不見秦先亡。", "開窗酹汝一杯酒，等爲亡國秦更醜。", "驪山冢破已千年，至今過者無傷憐。"]'),
('52a0917c-9e23-4178-9ba2-9da92d7928c8','初寒','陸游','宋','宋诗','song-poetry','','[]','船尾寒風不滿旗，江邊樷祠常掩扉。',64,'全唐诗/poet.song.127000.json','["船尾寒風不滿旗，江邊樷祠常掩扉。", "行人畏虎少晨起，舟子捕魚多夜歸。", "茆葉翻翻带宿雨，葦花漠漠弄斜暉。", "傷心到處聞碪杵，九月今年未授衣。"]'),
('1d4769db-5421-43eb-a782-fc2abc57bf05','醉歌','陸游','宋','宋诗','song-poetry','','[]','老夫檣竿插蒼石，水落岸沙痕數尺。',128,'全唐诗/poet.song.127000.json','["老夫檣竿插蒼石，水落岸沙痕數尺。", "江南秋盡未揺落，槲葉離離楓葉赤。", "楚人自古多悲傷，道傍行歌猶感激。", "野花碧紫亦滿把，澗果青紅正堪摘。", "客中得酒薄亦好，江頭爛醉真不惜。", "千古興亡在目前，鬱鬱關河含暝色。", "饑鴻垂翅掠舟過，此意與我同凄惻。", "三撫闌干恨未平，月明正照頹烏幘。"]'),
('5067fa3d-64aa-427c-8c21-d219c8092f38','秋風','陸游','宋','宋诗','song-poetry','','[]','秋風吹客檣，節物嘆遐方。',48,'全唐诗/poet.song.127000.json','["秋風吹客檣，節物嘆遐方。", "歲事忽云暮，吾行殊未央。", "霜清漢水緑，日落楚山蒼。", "此去三巴路，無猿亦斷腸。"]'),
('3c794407-c4ff-431b-8437-5296eb7317c7','塔子磯','陸游','宋','宋诗','song-poetry','','[]','塔子磯前艇子横，一窗秋月爲誰明。',64,'全唐诗/poet.song.127000.json','["塔子磯前艇子横，一窗秋月爲誰明。", "青山不減年年恨，白髮無端日日生。", "七澤蒼茫非故國，九歌哀怨有遺聲。", "古來撥亂非無策，夜半潮平意未平。"]'),
('b347443d-e0d5-440a-8040-54acf0016724','重陽','陸游','宋','宋诗','song-poetry','','[]','照江丹葉一林霜，折得黄花更斷腸。',32,'全唐诗/poet.song.127000.json','["照江丹葉一林霜，折得黄花更斷腸。", "商略此時須痛飲，細腰宫畔過重陽。"]'),
('3f2f7c53-2622-4420-a23f-887c17d45220','早寒','陸游','宋','宋诗','song-poetry','','[]','沔鄂猶殘暑，荆巫已早寒。',48,'全唐诗/poet.song.127000.json','["沔鄂猶殘暑，荆巫已早寒。", "潦收灘正白，霜重葉初丹。", "節物元非惡，情懷自鮮歡。", "暮年更世事，唯有醉江干。"]'),
('96dadd1b-de52-41ed-b796-d3fb365151bd','公安','陸游','宋','宋诗','song-poetry','','[]','地曠江天接，沙隤市井移。',48,'全唐诗/poet.song.127000.json','["地曠江天接，沙隤市井移。", "避風留半日，買米待多時。", "蝶冷停菰葉，鷗馴傍艣枝。", "昔人勲業地，搔首嘆吾衰。"]'),
('0716e141-0389-43cf-aca0-f862c493a1b0','沙頭','陸游','宋','宋诗','song-poetry','','[]','游子行愈遠，沙頭逢暮秋。',48,'全唐诗/poet.song.127000.json','["游子行愈遠，沙頭逢暮秋。", "孫劉鼎足地，荆益犬牙州。", "鼓角風雲慘，江湖日夜浮。", "此生應衮衮，高枕看東流。"]'),
('e0bc7030-d5ad-49d4-9fc7-b4ac5e0855fb','大寒出江陵西門','陸游','宋','宋诗','song-poetry','','[]','平明羸馬出西門，淡日寒雲久吐吞。',64,'全唐诗/poet.song.127000.json','["平明羸馬出西門，淡日寒雲久吐吞。", "醉面衝風驚易醒，重裘藏手取微温。", "紛紛狐兔投深莽，點點牛羊散遠村。", "不爲山川多感慨，歲窮遊子自消魂。"]'),
('4df4a2be-a73b-47ef-a31a-0402501e2245','江夏與章冠之遇别後寄贈','陸游','宋','宋诗','song-poetry','','[]','騎鶴仙人不可呼，一樽猶得與君俱。',64,'全唐诗/poet.song.127000.json','["騎鶴仙人不可呼，一樽猶得與君俱。", "未應湖海無豪士，長恨乾坤有腐儒。", "壯歲光陰隨手過，晚途衰病要人扶。", "凄涼江夏秋風裏，況見新豐舊酒徒。"]'),
('9b04f21e-ad85-462c-8431-31347c74d694','題江陵村店壁','陸游','宋','宋诗','song-poetry','','[]','青旆三家市，黄茆十里岡。',48,'全唐诗/poet.song.127000.json','["青旆三家市，黄茆十里岡。", "蓬飛風浩浩，塵起日茫茫。", "馳騁多從獸，鉏耰少破荒。", "行人相指似，此路走襄陽。"]'),
('5e9773dc-57e5-4f38-b7be-fa52f45d884e','馬上','陸游','宋','宋诗','song-poetry','','[]','燈前薄飰陳鹽虀，带睡強出行江隄。',64,'全唐诗/poet.song.127000.json','["燈前薄飰陳鹽虀，带睡強出行江隄。", "五更落月移樹影，十月清霜侵馬蹄。", "荒陂嗈嗈已度雁，小市喔喔初鳴雞。", "可憐萬里覓歸夢，未到故山先自迷。"]'),
('7704b630-4379-491c-9018-82912abfa9bd','水亭有懷','陸游','宋','宋诗','song-poetry','','[]','漁村把酒對丹楓，水驛憑軒送去鴻。',64,'全唐诗/poet.song.127000.json','["漁村把酒對丹楓，水驛憑軒送去鴻。", "道路半年行不到，江山萬里看無窮。", "故人草詔九天上，老子題詩三峽中。", "笑謂毛錐可無恨，書生處處與卿同。"]'),
('51416749-322b-4e9b-8c04-6bf3a234862c','移船','陸游','宋','宋诗','song-poetry','','[]','沙際舟衘尾，相依作四鄰。',48,'全唐诗/poet.song.127000.json','["沙際舟衘尾，相依作四鄰。", "暮年多感慨，分路亦酸辛。", "折竹占行日，吹簫賽水神。", "無勞問亭驛，久客自知津。"]'),
('dbf40d22-daba-4a97-aff2-ebdc78377a97','將離江陵','陸游','宋','宋诗','song-poetry','','[]','暮暮過渡頭，旦旦走隄上。',168,'全唐诗/poet.song.127000.json','["暮暮過渡頭，旦旦走隄上。", "舟人與關吏，見熟識顔狀。", "癡頑久不去，常恐遭誚讓。", "昨日倒檣竿，今日聮百丈。", "買薪備雨雪，儲米滿瓶盎。", "明當遂去此，障袂先側望。", "即今孟冬月，波濤幸非壯。", "潦收出奇石，霧卷見疊嶂。", "地嶮多崎嶇，峽束少平曠。", "從來樂山水，臨老愈跌宕。", "皇天憐其狂，擇地令自放。", "山花白似雪，江水緑於釀。", "竹枝本楚些，妙句寄悽愴。", "何當出清詩，千古續遺唱。"]'),
('392b91a2-b944-4675-b9c7-21439a88b8c1','六言','陸游','宋','宋诗','song-poetry','','[]','三巴亦有何好，萬里翩然獨尋。',28,'全唐诗/poet.song.127000.json','["三巴亦有何好，萬里翩然獨尋。", "本意爲君說破，消磨夢境光陰。"]'),
('02655e51-aa4e-463f-8eca-2a18d5b24309','江上','陸游','宋','宋诗','song-poetry','','[]','江上霜寒透客衣，閉窗羸臥不支持。',64,'全唐诗/poet.song.127000.json','["江上霜寒透客衣，閉窗羸臥不支持。", "羈孤形影真相吊，衰颯頭顱已可知。", "潦縮穩經行雨峽，竹疏賸見挂猿枝。", "清樽可置須勤醉，莫望功名老大時。"]'),
('b7aa136f-0597-4296-9de1-822cf39d0886','旅食','陸游','宋','宋诗','song-poetry','','[]','霜餘漢水淺，野逈朔風寒。',48,'全唐诗/poet.song.127000.json','["霜餘漢水淺，野逈朔風寒。", "炊黍香浮甑，烹蔬緑映盤。", "心安失粗糲，味美出艱難。", "惟恨虚捐日，無書得縱觀。"]'),
('57447d93-fdc8-49cf-9aa5-c93837aecf48','滄灘','陸游','宋','宋诗','song-poetry','','[]','百夫正讙助鳴艣，舟中對面不得語。',96,'全唐诗/poet.song.127000.json','["百夫正讙助鳴艣，舟中對面不得語。", "須臾人散寂無譁，惟聞百丈轉兩車。", "嘔嘔啞啞車轉急，舟人已在沙際立。", "霧斂蘆村落照紅，雨餘漁舍炊烟濕。", "故鄉回首已千山，上峽初經第一灘。", "少年亦慕宦遊樂，投老方知行路難。"]'),
('0b5c87c7-2794-4d66-84cc-a03c9ebae31c','松滋小酌','陸游','宋','宋诗','song-poetry','','[]','西遊六千里，此地最凄涼。',48,'全唐诗/poet.song.127000.json','["西遊六千里，此地最凄涼。", "騷客久埋骨，巴歌猶斷腸。", "風聲撼雲夢，雪意接瀟湘。", "萬古茫茫恨，悠然付一觴。"]'),
('fe4093de-5ba7-4ea2-ac4c-74a81c8b1a47','晚泊松滋渡口二首  其一','陸游','宋','宋诗','song-poetry','','[]','此行何處不艱難，寸寸強弓且旋彎。',64,'全唐诗/poet.song.127000.json','["此行何處不艱難，寸寸強弓且旋彎。", "縣近歡欣初得菜，江回徙倚忽逢山。", "繫船日落松滋渡，跋馬雲埋灩澦關。", "未滿百年均是客，不須數日待東還。"]'),
('7e46087a-384a-4cd5-91b5-091ebe4c91e7','晚泊松滋渡口二首  其二','陸游','宋','宋诗','song-poetry','','[]','小灘拍拍鸕鷀飛，深竹蕭蕭杜宇悲。',64,'全唐诗/poet.song.127000.json','["小灘拍拍鸕鷀飛，深竹蕭蕭杜宇悲。", "看鏡不堪衰病後，繫船最好夕陽時。", "生涯落魄惟躭酒，客路蒼茫自詠詩。", "莫問長安在何許，亂山孤店是松滋。"]'),
('f5b56738-9b55-4113-9c9b-e1ccf1f5548c','荆門冬夜','陸游','宋','宋诗','song-poetry','','[]','常饑龜老欲無腸，臥聽寒更自短長。',64,'全唐诗/poet.song.127000.json','["常饑龜老欲無腸，臥聽寒更自短長。", "香椀得閑聊作伴，酒杯因病頗相忘。", "有情窗罅恰通月，耐冷櫓枝多得霜。", "歴盡風波知險阻，平生錯羨捕魚郎。"]'),
('0fd8b6dc-337e-435c-b035-ca045f62ca3e','繫舟下牢溪游三游洞二十八韵','陸游','宋','宋诗','song-poetry','','[]','舊觀三峽圖，常謂非人情。',288,'全唐诗/poet.song.127000.json','["舊觀三峽圖，常謂非人情。", "意疑天壤間，豈有此崢嶸。", "畫師定戲耳，聊欲窮丹青。", "西游過沔鄂，莽莽千里平。", "昨日到峽州，所見始可驚。", "乃知畫非妄，却恨筆未精。", "及兹下牢戍，峰嶂畢自呈。", "下入裂坤軸，高鶱插青冥。", "角勝多列峙，擅美有孤撐。", "或如釡上甑，或如坐後屏。", "或如倨而立，或如喜而迎。", "或深如螺房，或疏如窗櫺。", "峨巍冠冕古，婀娜髻鬟傾。", "其間絕出者，虎搏蛟龍獰。", "崩崖凜欲墮，修梁架空横。", "懸瀑瀉無底，終古何時盈。", "幽泉莫知處，但聞珩珮鳴。", "怪怪與奇奇，萬狀不可名。", "久聞三游洞，疾走忘病嬰。", "竇穴初漆黑，傴僂捫壁行。", "方虞觸蟄蛇，頫見一點明。", "扶接困僮奴，恍然出瓶罌。", "穹穹厦屋寬，滴乳成微泓。", "題名歐與黄，雲蒸蒼蘚平。"]'),
('2a8aae59-5911-4e3e-b124-7fcd10e66316','三游洞前巖下小潭水甚奇取以煎茶','陸游','宋','宋诗','song-poetry','','[]','苔徑芒鞵滑不妨，潭邊聊得據胡床。',64,'全唐诗/poet.song.127000.json','["苔徑芒鞵滑不妨，潭邊聊得據胡床。", "巖空倒看峰巒影，澗遠中含藥草香。", "汲取滿瓶牛乳白，分流觸石珮聲長。", "囊中日鑄傳天下，不是名泉不合嘗。"]'),
('3710cd89-4134-4181-b19a-7a9a22b9c630','扇子峽山腹有草閣小亭極幽邃意其非俗人居也','陸游','宋','宋诗','song-poetry','','[]','絕境慰人心，誰家住玉岑。',48,'全唐诗/poet.song.127000.json','["絕境慰人心，誰家住玉岑。", "亂雲生翠竇，密雪灑青林。", "高閣臨空豁，孤亭隠邃深。", "定知非俗士，櫓急不容尋。"]'),
('caf2c8ff-0554-41c2-8636-af3548b209b7','蝦蟆碚','陸游','宋','宋诗','song-poetry','','[]','不肯爬沙桂樹邊，朵頤千古向巖前。',64,'全唐诗/poet.song.127000.json','["不肯爬沙桂樹邊，朵頤千古向巖前。", "巴東峽裏最初峽，天下泉中第四泉。", "齧雪飲冰疑換骨，掬珠弄玉可忘年。", "清游自笑何曾足，疊鼓鼕鼕又解船。"]'),
('7ab1f9a9-c5af-49d2-9149-5b2ca2487667','黄牛峽廟','陸游','宋','宋诗','song-poetry','','[]','三峽束江流，崖谷互吐納。',149,'全唐诗/poet.song.127000.json','["三峽束江流，崖谷互吐納。", "黄牛不負重，雲表恣蹴蹋。", "吳船與蜀舸，有請神必答。", "誰憐馬遭刖，百歲創未合。", "柂師浪奔走，烹彘陳酒榼。", "紛然餕神餘，羮{炙火=肉}爭嘬嚃。", "空庭多落葉，日莫聲颯颯。", "奇文粲可辨，高古篆籕雜。", "村女賣秋茶，簪花髻鬟匝。", "襁兒著背上，帖妥若在榻。", "山寒雪欲下，虎出門早闔。", "我行忽至此，臨風久嗚唈。"]'),
('14c010eb-ff72-42f1-bacf-bfd01fae94a7','過夷陵適值祈雪與葉使君清飲談括蒼舊游既行舟中雪作戲成長句奉寄','陸游','宋','宋诗','song-poetry','','[]','巴楚夷陵酒最醇，使君風味更清真。',64,'全唐诗/poet.song.127000.json','["巴楚夷陵酒最醇，使君風味更清真。", "少年恨不從豪飲，薄宦那知託近鄰。", "本擬笙歌娛病客，却催雨雪惱行人。", "朝來凍手題詩寄，莫笑欹斜字不勻。"]'),
('9d41ab96-105e-4e12-b43c-b797b4ad58c9','泊虎頭灘下','陸游','宋','宋诗','song-poetry','','[]','大舟已泊燈火明，小舟猶行聞櫓聲。',32,'全唐诗/poet.song.127000.json','["大舟已泊燈火明，小舟猶行聞櫓聲。", "虎頭崔嵬鹿角横，人生實難君勿輕。"]'),
('bc5edeba-bb44-4d3c-91af-0f484b0644b4','過東𤃩灘入馬肝峽','陸游','宋','宋诗','song-poetry','','[]','書生就食等奔逃，道路崎嶇信所遭。',64,'全唐诗/poet.song.127000.json','["書生就食等奔逃，道路崎嶇信所遭。", "船上急灘如退鷁，人緣絕壁似飛猱。", "口誇遠嶺青千疊，心憶平波緑一篙。", "猶勝溪丁絕輕死，無時來往駕𦨴艚。"]'),
('98a86ee2-a2e2-420f-943c-4ceb57e5bf70','新安驛','陸游','宋','宋诗','song-poetry','','[]','孤驛荒山與虎鄰，更堪風雪暗南津。',64,'全唐诗/poet.song.127000.json','["孤驛荒山與虎鄰，更堪風雪暗南津。", "羈遊如此真無策，獨立悽然黙愴神。", "木盎汲江人起早，銀釵簇髻女粧新。", "蠻風弊惡蛟龍横，未敢全誇見在身。"]'),
('9988b4f4-0a1d-4dab-b685-5cfb5d317c39','秭歸醉中懷都下諸公示坐客','陸游','宋','宋诗','song-poetry','','[]','長謡爲子說天涯，四坐聽歌且勿譁。',64,'全唐诗/poet.song.127000.json','["長謡爲子說天涯，四坐聽歌且勿譁。", "蠻俗殺人供鬼祭，敗舟觸石委江沙。", "此身長是滄浪客，何日能爲飽暖家。", "坐憶故人空有夢，尺書不敢到京華。"]'),
('82ebe438-1875-487a-8f5b-c8e39aa4c162','憩歸州光孝寺寺後有楚冢近歲或發之得寶玉劍佩之類','陸游','宋','宋诗','song-poetry','','[]','秭歸城畔蹋斜陽，古寺無僧晝閉房。',64,'全唐诗/poet.song.127000.json','["秭歸城畔蹋斜陽，古寺無僧晝閉房。", "殘珮斷釵陵谷變，苦茆架竹井閭荒。", "虎行欲與人爭路，猿嘯能令客斷腸。", "寂寞倚樓搔短髮，剩題新恨付巴娘。"]'),
('0e2f8ef7-0d64-4ae6-8893-34fdf0e9442b','飲罷寺門獨立有感','陸游','宋','宋诗','song-poetry','','[]','一邑無平土，邦人例得窮。',48,'全唐诗/poet.song.127000.json','["一邑無平土，邦人例得窮。", "凄涼遠嫁婦，憔悴獨醒翁。", "今古闌干外，悲歡酒醆中。", "三巴不揺落，搔首對丹楓。"]'),
('2459253a-cfab-4b2d-8418-0163ae1b1800','泛溪船至巴東','陸游','宋','宋诗','song-poetry','','[]','溪船莫嫌迮，船迮始相宜。',48,'全唐诗/poet.song.127000.json','["溪船莫嫌迮，船迮始相宜。", "兩槳行何駛，重灘過不知。", "荒村寇相縣，破屋屈平祠。", "不奈新愁得，啼猿挂冷枝。"]'),
('673f587b-fa27-4b4f-ba60-2254e23a8c4d','巴東遇小雨二首  其一','陸游','宋','宋诗','song-poetry','','[]','暫借清溪伴釣翁，沙邊微雨濕孤蓬。',32,'全唐诗/poet.song.127000.json','["暫借清溪伴釣翁，沙邊微雨濕孤蓬。", "從今詩在巴東縣，不屬灞橋風雪中。"]'),
('309ea326-9a79-4029-bd91-d1079cc78348','巴東遇小雨二首  其二','陸游','宋','宋诗','song-poetry','','[]','西遊萬里亦何爲，欲就騷人乞棄遺。',32,'全唐诗/poet.song.127000.json','["西遊萬里亦何爲，欲就騷人乞棄遺。", "到此宛然詩不進，始知才分有窮時。"]'),
('ab474f16-12da-4980-a22b-1baa252f8529','秋風亭拜宼萊公遺像二首  其一','陸游','宋','宋诗','song-poetry','','[]','江上秋風宋玉悲，長官手自葺茅茨。',32,'全唐诗/poet.song.127000.json','["江上秋風宋玉悲，長官手自葺茅茨。", "人生窮達誰能料，蠟泪成堆又一時。"]'),
('5531ec5e-af0f-4df4-8d20-62f44818a986','秋風亭拜宼萊公遺像二首  其二','陸游','宋','宋诗','song-poetry','','[]','豪傑何心後世名，材高遇事即崢嶸。',32,'全唐诗/poet.song.127000.json','["豪傑何心後世名，材高遇事即崢嶸。", "巴東詩句澶州策，信手拈來盡可驚。"]'),
('60e5d629-cd36-4609-b883-39a29825f92d','巴東令廨白雲亭','陸游','宋','宋诗','song-poetry','','[]','寇公壯歲落巴蠻，得意孤亭縹緲間。',64,'全唐诗/poet.song.127000.json','["寇公壯歲落巴蠻，得意孤亭縹緲間。", "常倚曲闌貪看水，不安四壁怕遮山。", "遺民雖盡猶能說，老令初來亦愛閑。", "正使官清貧至骨，未妨留客聽潺潺。"]');
